{
  "name": "FlashMind - Word Association Master",
  "description": "A sophisticated flash-card application designed for memorizing word pairs through a 4-stage psychological learning cycle. Effortlessly manage word lists and track your progress from Unknown to Learned."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum AssociationStatus {
  DESCONOCIDA = 'DESCONOCIDA',
  DESCUBIERTA = 'DESCUBIERTA',
  RECONOCIDA = 'RECONOCIDA',
  CONOCIDA = 'CONOCIDA',
  APRENDIDA = 'APRENDIDA'
}

export interface Association {
  id: string;
  term: string;
  definition: string;
  status: AssociationStatus;
  history?: boolean; // If moved to history, won't show up in standard games
}

export interface AssociationList {
  id: string;
  name: string;
  concept: string; // e.g., "English/Spanish"
  associations: Association[];
  createdAt: number;
}

export type GameCycle = 1 | 2 | 3 | 4;

export interface GameState {
  listId: string;
  currentCycle: GameCycle;
  currentIndex: number;
  queue: string[]; // IDs of associations in the current cycle
  history: string[]; // For "Back" functionality
  isFinished: boolean;
  revealed: boolean;
}

import React, { useState, useEffect } from 'react';
import { Dashboard } from './components/Dashboard';
import { GameView } from './components/GameView';
import { ListEditor } from './components/ListEditor';
import { AssociationList } from './types';

const App: React.FC = () => {
  const [view, setView] = useState<'dashboard' | 'game' | 'editor'>('dashboard');
  const [lists, setLists] = useState<AssociationList[]>([]);
  const [selectedListId, setSelectedListId] = useState<string | null>(null);

  // Load from localStorage
  useEffect(() => {
    const saved = localStorage.getItem('flashmind_lists');
    if (saved) {
      setLists(JSON.parse(saved));
    }
  }, []);

  // Save to localStorage
  useEffect(() => {
    localStorage.setItem('flashmind_lists', JSON.stringify(lists));
  }, [lists]);

  const handleCreateList = (name: string, concept: string) => {
    const newList: AssociationList = {
      id: crypto.randomUUID(),
      name,
      concept,
      associations: [],
      createdAt: Date.now()
    };
    setLists([...lists, newList]);
    setSelectedListId(newList.id);
    setView('editor');
  };

  const handleDeleteList = (id: string) => {
    setLists(lists.filter(l => l.id !== id));
  };

  const handleUpdateList = (updatedList: AssociationList) => {
    setLists(lists.map(l => l.id === updatedList.id ? updatedList : l));
  };

  const currentList = lists.find(l => l.id === selectedListId);

  return (
    <div className="min-h-screen flex flex-col">
      <header className="bg-white border-b px-6 py-4 flex justify-between items-center sticky top-0 z-50">
        <div 
          className="flex items-center gap-2 cursor-pointer" 
          onClick={() => setView('dashboard')}
        >
          <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center text-white font-bold">F</div>
          <h1 className="text-xl font-bold text-gray-800">FlashMind</h1>
        </div>
        <nav className="flex gap-4">
          <button 
            onClick={() => setView('dashboard')}
            className={`px-4 py-2 rounded-md text-sm font-medium transition ${view === 'dashboard' ? 'bg-indigo-50 text-indigo-700' : 'text-gray-600 hover:bg-gray-100'}`}
          >
            Dashboard
          </button>
        </nav>
      </header>

      <main className="flex-1 overflow-y-auto">
        {view === 'dashboard' && (
          <Dashboard 
            lists={lists} 
            onCreate={handleCreateList} 
            onDelete={handleDeleteList}
            onEdit={(id) => { setSelectedListId(id); setView('editor'); }}
            onPlay={(id) => { setSelectedListId(id); setView('game'); }}
          />
        )}

        {view === 'editor' && currentList && (
          <ListEditor 
            list={currentList} 
            onSave={handleUpdateList} 
            onBack={() => setView('dashboard')}
          />
        )}

        {view === 'game' && currentList && (
          <GameView 
            list={currentList} 
            onUpdateList={handleUpdateList}
            onBack={() => setView('dashboard')}
          />
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { AssociationList } from '../types';

interface DashboardProps {
  lists: AssociationList[];
  onCreate: (name: string, concept: string) => void;
  onDelete: (id: string) => void;
  onEdit: (id: string) => void;
  onPlay: (id: string) => void;
}

export const Dashboard: React.FC<DashboardProps> = ({ lists, onCreate, onDelete, onEdit, onPlay }) => {
  const [isCreating, setIsCreating] = useState(false);
  const [newName, setNewName] = useState('');
  const [newConcept, setNewConcept] = useState('');

  const handleCreate = (e: React.FormEvent) => {
    e.preventDefault();
    if (newName && newConcept) {
      onCreate(newName, newConcept);
      setNewName('');
      setNewConcept('');
      setIsCreating(false);
    }
  };

  return (
    <div className="max-w-5xl mx-auto p-6">
      <div className="flex justify-between items-center mb-8">
        <div>
          <h2 className="text-3xl font-bold text-gray-900">Your Study Sets</h2>
          <p className="text-gray-500 mt-1">Manage your word associations and start learning.</p>
        </div>
        <button 
          onClick={() => setIsCreating(true)}
          className="bg-indigo-600 text-white px-6 py-2.5 rounded-lg font-semibold hover:bg-indigo-700 transition shadow-sm flex items-center gap-2"
        >
          <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
          </svg>
          Create New List
        </button>
      </div>

      {isCreating && (
        <div className="mb-8 bg-white p-6 rounded-xl border border-indigo-100 shadow-sm">
          <form onSubmit={handleCreate} className="grid grid-cols-1 md:grid-cols-3 gap-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">List Name</label>
              <input 
                type="text" 
                value={newName}
                onChange={(e) => setNewName(e.target.value)}
                placeholder="e.g., Common English Verbs"
                className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none"
                required
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Concept</label>
              <input 
                type="text" 
                value={newConcept}
                onChange={(e) => setNewConcept(e.target.value)}
                placeholder="e.g., English / Spanish"
                className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none"
                required
              />
            </div>
            <div className="flex items-end gap-2">
              <button 
                type="submit"
                className="bg-indigo-600 text-white px-4 py-2 rounded-lg font-medium hover:bg-indigo-700 flex-1"
              >
                Create
              </button>
              <button 
                type="button"
                onClick={() => setIsCreating(false)}
                className="bg-gray-100 text-gray-600 px-4 py-2 rounded-lg font-medium hover:bg-gray-200"
              >
                Cancel
              </button>
            </div>
          </form>
        </div>
      )}

      {lists.length === 0 ? (
        <div className="text-center py-20 bg-white rounded-2xl border-2 border-dashed border-gray-200">
          <div className="w-20 h-20 bg-gray-50 rounded-full flex items-center justify-center mx-auto mb-4 text-gray-400">
            <svg className="w-10 h-10" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M12 6.253v13m0-13C10.832 5.477 9.246 5 7.5 5S4.168 5.477 3 6.253v13C4.168 18.477 5.754 18 7.5 18s3.332.477 4.5 1.253m0-13C13.168 5.477 14.754 5 16.5 5c1.747 0 3.332.477 4.5 1.253v13C19.832 18.477 18.247 18 16.5 18c-1.746 0-3.332.477-4.5 1.253" />
            </svg>
          </div>
          <h3 className="text-xl font-semibold text-gray-900">No study lists yet</h3>
          <p className="text-gray-500 mt-2">Start by creating your first list of word associations.</p>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {lists.map(list => (
            <div key={list.id} className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 hover:shadow-md transition group">
              <div className="flex justify-between items-start mb-4">
                <span className="bg-indigo-50 text-indigo-600 text-xs font-bold px-2 py-1 rounded uppercase tracking-wider">
                  {list.concept}
                </span>
                <button 
                  onClick={() => onDelete(list.id)}
                  className="text-gray-400 hover:text-red-500 transition opacity-0 group-hover:opacity-100"
                >
                  <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                  </svg>
                </button>
              </div>
              <h3 className="text-xl font-bold text-gray-900 mb-1">{list.name}</h3>
              <p className="text-gray-500 text-sm mb-6">
                {list.associations.length} associations • {list.associations.filter(a => a.status === 'APRENDIDA').length} learned
              </p>
              <div className="flex gap-3">
                <button 
                  onClick={() => onPlay(list.id)}
                  disabled={list.associations.length === 0}
                  className="flex-1 bg-indigo-600 text-white px-4 py-2 rounded-lg font-medium hover:bg-indigo-700 disabled:bg-gray-300 disabled:cursor-not-allowed transition"
                >
                  Study Now
                </button>
                <button 
                  onClick={() => onEdit(list.id)}
                  className="px-4 py-2 border border-gray-200 rounded-lg text-gray-700 font-medium hover:bg-gray-50 transition"
                >
                  Edit
                </button>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { AssociationList, Association, AssociationStatus } from '../types';

interface ListEditorProps {
  list: AssociationList;
  onSave: (list: AssociationList) => void;
  onBack: () => void;
}

export const ListEditor: React.FC<ListEditorProps> = ({ list, onSave, onBack }) => {
  const [bulkText, setBulkText] = useState('');
  const [showBulk, setShowBulk] = useState(false);
  const [editList, setEditList] = useState<AssociationList>(list);

  const handleBulkAdd = () => {
    const lines = bulkText.split('\n').filter(l => l.trim().includes(','));
    const newAssocs: Association[] = lines.map(line => {
      const [term, def] = line.split(',').map(s => s.trim());
      return {
        id: crypto.randomUUID(),
        term: term || '',
        definition: def || '',
        status: AssociationStatus.DESCONOCIDA
      };
    });

    const updated = {
      ...editList,
      associations: [...editList.associations, ...newAssocs]
    };
    setEditList(updated);
    onSave(updated);
    setBulkText('');
    setShowBulk(false);
  };

  const handleAddRow = () => {
    const updated = {
      ...editList,
      associations: [
        ...editList.associations,
        { id: crypto.randomUUID(), term: '', definition: '', status: AssociationStatus.DESCONOCIDA }
      ]
    };
    setEditList(updated);
    onSave(updated);
  };

  const handleUpdateRow = (id: string, field: keyof Association, value: string) => {
    const updated = {
      ...editList,
      associations: editList.associations.map(a => a.id === id ? { ...a, [field]: value } : a)
    };
    setEditList(updated);
    onSave(updated);
  };

  const handleRemoveRow = (id: string) => {
    const updated = {
      ...editList,
      associations: editList.associations.filter(a => a.id !== id)
    };
    setEditList(updated);
    onSave(updated);
  };

  return (
    <div className="max-w-4xl mx-auto p-6">
      <div className="flex items-center gap-4 mb-8">
        <button onClick={onBack} className="text-gray-400 hover:text-indigo-600 transition">
          <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 19l-7-7m0 0l7-7m-7 7h18" />
          </svg>
        </button>
        <div>
          <h2 className="text-2xl font-bold text-gray-900">{editList.name}</h2>
          <p className="text-sm text-gray-500">Editing associations for {editList.concept}</p>
        </div>
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
        <div className="p-4 border-b bg-gray-50 flex justify-between items-center">
          <h3 className="font-semibold text-gray-700">Word Pairs ({editList.associations.length})</h3>
          <div className="flex gap-2">
             <button 
              onClick={() => setShowBulk(!showBulk)}
              className="text-indigo-600 text-sm font-medium hover:underline"
            >
              {showBulk ? 'Hide Bulk Import' : 'Bulk Import'}
            </button>
            <button 
              onClick={handleAddRow}
              className="bg-indigo-600 text-white px-3 py-1 rounded text-sm font-medium hover:bg-indigo-700 transition"
            >
              Add Row
            </button>
          </div>
        </div>

        {showBulk && (
          <div className="p-4 bg-indigo-50 border-b">
            <label className="block text-sm font-medium text-indigo-900 mb-2">Paste comma-separated pairs (one per line)</label>
            <textarea 
              value={bulkText}
              onChange={(e) => setBulkText(e.target.value)}
              placeholder="hello, hola&#10;world, mundo"
              className="w-full h-32 px-3 py-2 border border-indigo-200 rounded-lg text-sm mb-3 outline-none focus:ring-2 focus:ring-indigo-500"
            />
            <button 
              onClick={handleBulkAdd}
              className="bg-indigo-600 text-white px-4 py-2 rounded-lg text-sm font-medium hover:bg-indigo-700"
            >
              Add All
            </button>
          </div>
        )}

        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="text-xs uppercase text-gray-400 font-bold border-b">
                <th className="px-6 py-3">Term</th>
                <th className="px-6 py-3">Definition</th>
                <th className="px-6 py-3 w-20"></th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-50">
              {editList.associations.map((assoc) => (
                <tr key={assoc.id} className="group hover:bg-gray-50 transition">
                  <td className="px-6 py-3">
                    <input 
                      type="text" 
                      value={assoc.term}
                      onChange={(e) => handleUpdateRow(assoc.id, 'term', e.target.value)}
                      className="w-full bg-transparent border-none focus:ring-0 text-gray-900"
                      placeholder="Term"
                    />
                  </td>
                  <td className="px-6 py-3">
                    <input 
                      type="text" 
                      value={assoc.definition}
                      onChange={(e) => handleUpdateRow(assoc.id, 'definition', e.target.value)}
                      className="w-full bg-transparent border-none focus:ring-0 text-gray-900"
                      placeholder="Definition"
                    />
                  </td>
                  <td className="px-6 py-3 text-right">
                    <button 
                      onClick={() => handleRemoveRow(assoc.id)}
                      className="text-gray-300 hover:text-red-500 transition opacity-0 group-hover:opacity-100"
                    >
                      <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                      </svg>
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
          {editList.associations.length === 0 && (
            <div className="py-12 text-center text-gray-400 italic">
              No associations yet. Add a row or use bulk import.
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { AssociationList, Association, AssociationStatus, GameCycle, GameState } from '../types';

interface GameViewProps {
  list: AssociationList;
  onUpdateList: (list: AssociationList) => void;
  onBack: () => void;
}

export const GameView: React.FC<GameViewProps> = ({ list, onUpdateList, onBack }) => {
  const [gameState, setGameState] = useState<GameState>({
    listId: list.id,
    currentCycle: 1,
    currentIndex: 0,
    queue: [],
    history: [],
    isFinished: false,
    revealed: false
  });

  const [associations, setAssociations] = useState<Association[]>(list.associations);

  // Initialize first cycle
  useEffect(() => {
    startCycle(1);
  }, []);

  const startCycle = (cycle: GameCycle) => {
    let targetStatus: AssociationStatus;
    switch (cycle) {
      case 1: targetStatus = AssociationStatus.DESCONOCIDA; break;
      case 2: targetStatus = AssociationStatus.DESCUBIERTA; break;
      case 3: targetStatus = AssociationStatus.RECONOCIDA; break;
      case 4: targetStatus = AssociationStatus.CONOCIDA; break;
    }

    const availableIds = associations
      .filter(a => a.status === targetStatus && !a.history)
      .map(a => a.id);

    const shuffled = [...availableIds].sort(() => Math.random() - 0.5);

    if (shuffled.length === 0 && cycle < 4) {
      startCycle((cycle + 1) as GameCycle);
      return;
    }

    setGameState(prev => ({
      ...prev,
      currentCycle: cycle,
      currentIndex: 0,
      queue: shuffled,
      isFinished: shuffled.length === 0,
      revealed: false,
      history: []
    }));
  };

  const currentAssocId = gameState.queue[gameState.currentIndex];
  const currentAssoc = associations.find(a => a.id === currentAssocId);

  const handleNext = () => {
    if (!currentAssoc) return;

    // Transition logic
    let nextStatus = currentAssoc.status;
    if (gameState.currentCycle === 1) nextStatus = AssociationStatus.DESCUBIERTA;
    else if (gameState.currentCycle === 2) nextStatus = AssociationStatus.RECONOCIDA;
    else if (gameState.currentCycle === 3) nextStatus = AssociationStatus.CONOCIDA;
    // Cycle 4 doesn't change state

    const updatedAssociations = associations.map(a => 
      a.id === currentAssocId ? { ...a, status: nextStatus } : a
    );
    setAssociations(updatedAssociations);

    if (gameState.currentIndex < gameState.queue.length - 1) {
      setGameState(prev => ({
        ...prev,
        currentIndex: prev.currentIndex + 1,
        revealed: false,
        history: [...prev.history, currentAssocId]
      }));
    } else {
      // Cycle ended
      if (gameState.currentCycle < 4) {
        // Prepare next cycle but we need to commit status changes first
        onUpdateList({ ...list, associations: updatedAssociations });
        startCycle((gameState.currentCycle + 1) as GameCycle);
      } else {
        setGameState(prev => ({ ...prev, isFinished: true }));
        onUpdateList({ ...list, associations: updatedAssociations });
      }
    }
  };

  const handleCorrect = () => {
    if (!currentAssoc) return;

    // Special logic for first cycle: immediate "Learned"
    let nextStatus = currentAssoc.status;
    if (gameState.currentCycle === 1) {
      nextStatus = AssociationStatus.APRENDIDA;
    } 
    // Other cycles: Correct keeps current state as per request

    const updatedAssociations = associations.map(a => 
      a.id === currentAssocId ? { ...a, status: nextStatus } : a
    );
    setAssociations(updatedAssociations);

    if (gameState.currentIndex < gameState.queue.length - 1) {
      setGameState(prev => ({
        ...prev,
        currentIndex: prev.currentIndex + 1,
        revealed: false,
        history: [...prev.history, currentAssocId]
      }));
    } else {
      if (gameState.currentCycle < 4) {
        onUpdateList({ ...list, associations: updatedAssociations });
        startCycle((gameState.currentCycle + 1) as GameCycle);
      } else {
        setGameState(prev => ({ ...prev, isFinished: true }));
        onUpdateList({ ...list, associations: updatedAssociations });
      }
    }
  };

  const handleBack = () => {
    if (gameState.currentIndex > 0) {
      setGameState(prev => ({
        ...prev,
        currentIndex: prev.currentIndex - 1,
        revealed: false,
        history: prev.history.slice(0, -1)
      }));
    }
  };

  const resetAll = () => {
    const updated = associations.map(a => ({ ...a, status: AssociationStatus.DESCONOCIDA }));
    setAssociations(updated);
    onUpdateList({ ...list, associations: updated });
    startCycle(1);
  };

  const moveLearnedToHistory = () => {
    const updated = associations.map(a => 
      a.status === AssociationStatus.APRENDIDA ? { ...a, history: true } : a
    );
    setAssociations(updated);
    onUpdateList({ ...list, associations: updated });
    startCycle(1);
  };

  const continuePlaying = () => {
    const updated = associations.map(a => ({ ...a, status: AssociationStatus.DESCONOCIDA }));
    setAssociations(updated);
    onUpdateList({ ...list, associations: updated });
    startCycle(1);
  };

  const stats = useMemo(() => {
    return {
      total: associations.filter(a => !a.history).length,
      learned: associations.filter(a => a.status === 'APRENDIDA').length,
      discovered: associations.filter(a => a.status === 'DESCUBIERTA').length,
      recognized: associations.filter(a => a.status === 'RECONOCIDA').length,
      known: associations.filter(a => a.status === 'CONOCIDA').length,
      unknown: associations.filter(a => a.status === 'DESCONOCIDA').length,
      missing: gameState.queue.length - gameState.currentIndex
    };
  }, [associations, gameState]);

  if (gameState.isFinished) {
    return (
      <div className="max-w-2xl mx-auto p-6">
        <div className="bg-white rounded-3xl shadow-xl p-8 border border-indigo-50 text-center">
          <div className="w-20 h-20 bg-green-100 text-green-600 rounded-full flex items-center justify-center mx-auto mb-6">
            <svg className="w-10 h-10" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
            </svg>
          </div>
          <h2 className="text-3xl font-bold text-gray-900 mb-2">Game Complete!</h2>
          <p className="text-gray-500 mb-8">You've cycled through all available word associations.</p>

          <div className="grid grid-cols-2 gap-4 mb-8">
            <div className="bg-indigo-50 p-4 rounded-xl">
              <div className="text-2xl font-bold text-indigo-700">{stats.learned}</div>
              <div className="text-sm text-indigo-600 font-medium">Learned</div>
            </div>
            <div className="bg-blue-50 p-4 rounded-xl">
              <div className="text-2xl font-bold text-blue-700">{stats.known}</div>
              <div className="text-sm text-blue-600 font-medium">Known</div>
            </div>
            <div className="bg-purple-50 p-4 rounded-xl">
              <div className="text-2xl font-bold text-purple-700">{stats.recognized}</div>
              <div className="text-sm text-purple-600 font-medium">Recognized</div>
            </div>
             <div className="bg-orange-50 p-4 rounded-xl">
              <div className="text-2xl font-bold text-orange-700">{stats.discovered}</div>
              <div className="text-sm text-orange-600 font-medium">Discovered</div>
            </div>
          </div>

          <div className="space-y-3">
            <button 
              onClick={continuePlaying}
              className="w-full bg-indigo-600 text-white py-3 rounded-xl font-bold hover:bg-indigo-700 transition"
            >
              Restart (All to Unknown)
            </button>
            <button 
              onClick={moveLearnedToHistory}
              className="w-full bg-indigo-100 text-indigo-700 py-3 rounded-xl font-bold hover:bg-indigo-200 transition"
            >
              Archive Learned & Continue
            </button>
            <button 
              onClick={resetAll}
              className="w-full bg-white border border-gray-200 text-gray-600 py-3 rounded-xl font-bold hover:bg-gray-50 transition"
            >
              Reset All Progress
            </button>
            <button 
              onClick={onBack}
              className="w-full text-gray-500 font-medium py-2 hover:text-gray-700"
            >
              Return to Dashboard
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
