};

import React, { useState, useEffect } from 'react';
import { Dashboard } from './components/Dashboard';
import { GameView } from './components/GameView';
import { ListEditor } from './components/ListEditor';
import { AssociationList, Association } from './types';

const App: React.FC = () => {
  const [view, setView] = useState<'dashboard' | 'game' | 'editor'>('dashboard');
  const [lists, setLists] = useState<AssociationList[]>([]);
  const [selectedListId, setSelectedListId] = useState<string | null>(null);

  useEffect(() => {
    const saved = localStorage.getItem('flashmind_lists');
    if (saved) {
      setLists(JSON.parse(saved));
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('flashmind_lists', JSON.stringify(lists));
  }, [lists]);

  const handleCreateList = (name: string, concept: string, initialAssociations: Association[] = []) => {
    const newList: AssociationList = {
      id: crypto.randomUUID(),
      name,
      concept,
      associations: initialAssociations,
      createdAt: Date.now()
    };
    setLists([...lists, newList]);
    setSelectedListId(newList.id);
    setView('editor');
  };

  const handleDeleteList = (id: string) => {
    setLists(lists.filter(l => l.id !== id));
  };

  const handleUpdateList = (updatedList: AssociationList) => {
    setLists(lists.map(l => l.id === updatedList.id ? updatedList : l));
  };

  const currentList = lists.find(l => l.id === selectedListId);

  return (
    <div className="min-h-screen flex flex-col">
      <header className="bg-white border-b px-6 py-4 flex justify-between items-center sticky top-0 z-50">
        <div 
          className="flex items-center gap-2 cursor-pointer" 
          onClick={() => setView('dashboard')}
        >
          <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center text-white font-bold">F</div>
          <h1 className="text-xl font-bold text-gray-800">FlashMind</h1>
        </div>
        <nav className="flex gap-4">
          <button 
            onClick={() => setView('dashboard')}
            className={`px-4 py-2 rounded-md text-sm font-medium transition ${view === 'dashboard' ? 'bg-indigo-50 text-indigo-700' : 'text-gray-600 hover:bg-gray-100'}`}
          >
            Dashboard
          </button>
        </nav>
      </header>

      <main className="flex-1 overflow-y-auto">
        {view === 'dashboard' && (
          <Dashboard 
            lists={lists} 
            onCreate={handleCreateList} 
            onDelete={handleDeleteList}
            onEdit={(id) => { setSelectedListId(id); setView('editor'); }}
            onPlay={(id) => { setSelectedListId(id); setView('game'); }}
          />
        )}

        {view === 'editor' && currentList && (
          <ListEditor 
            list={currentList} 
            onSave={handleUpdateList} 
            onBack={() => setView('dashboard')}
          />
        )}

        {view === 'game' && currentList && (
          <GameView 
            list={currentList} 
            onUpdateList={handleUpdateList}
            onBack={() => setView('dashboard')}
          />
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { AssociationList, Association, AssociationStatus } from '../types';

interface DashboardProps {
  lists: AssociationList[];
  onCreate: (name: string, concept: string, initialAssociations: Association[]) => void;
  onDelete: (id: string) => void;
  onEdit: (id: string) => void;
  onPlay: (id: string) => void;
}

export const Dashboard: React.FC<DashboardProps> = ({ lists, onCreate, onDelete, onEdit, onPlay }) => {
  const [isCreating, setIsCreating] = useState(false);
  const [newName, setNewName] = useState('');
  const [newConcept, setNewConcept] = useState('');
  const [bulkData, setBulkData] = useState('');
  const [showBulk, setShowBulk] = useState(false);

  const parseBulkData = (text: string): Association[] => {
    if (!text.trim()) return [];

    return text.split('\n')
      .map(line => line.trim())
      .filter(line => line.length > 0)
      .map(line => {
        // Soporta tab, punto y coma o coma
        const parts = line.split(/[\t;]|,(?=(?:(?:[^"]*"){2})*[^"]*$)/);
        const term = parts[0]?.replace(/^"|"$/g, '').trim() || '';
        const definition = parts[1]?.replace(/^"|"$/g, '').trim() || '';

        return {
          id: crypto.randomUUID(),
          term,
          definition,
          status: AssociationStatus.DESCONOCIDA
        };
      })
      .filter(a => a.term || a.definition);
  };

  const handleCreate = (e: React.FormEvent) => {
    e.preventDefault();
    if (newName && newConcept) {
      const initialAssocs = parseBulkData(bulkData);
      onCreate(newName, newConcept, initialAssocs);
      setNewName('');
      setNewConcept('');
      setBulkData('');
      setIsCreating(false);
      setShowBulk(false);
    }
  };

  return (
    <div className="max-w-5xl mx-auto p-6">
      <div className="flex justify-between items-center mb-8">
        <div>
          <h2 className="text-3xl font-bold text-gray-900">Tus Listas de Estudio</h2>
          <p className="text-gray-500 mt-1">Memoriza asociaciones de palabras rápidamente.</p>
        </div>
        <button 
          onClick={() => setIsCreating(true)}
          className="bg-indigo-600 text-white px-6 py-2.5 rounded-lg font-semibold hover:bg-indigo-700 transition shadow-sm flex items-center gap-2"
        >
          <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
          </svg>
          Nueva Lista
        </button>
      </div>

      {isCreating && (
        <div className="mb-8 bg-white p-6 rounded-xl border border-indigo-100 shadow-lg animate-in fade-in slide-in-from-top-4 duration-300">
          <form onSubmit={handleCreate}>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Nombre de la Lista</label>
                <input 
                  type="text" 
                  value={newName}
                  onChange={(e) => setNewName(e.target.value)}
                  placeholder="ej: Verbos Irregulares"
                  className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none transition"
                  required
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Concepto (Par)</label>
                <input 
                  type="text" 
                  value={newConcept}
                  onChange={(e) => setNewConcept(e.target.value)}
                  placeholder="ej: Inglés / Español"
                  className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none transition"
                  required
                />
              </div>
            </div>

            <div className="mb-4">
              <button 
                type="button"
                onClick={() => setShowBulk(!showBulk)}
                className="text-indigo-600 text-sm font-semibold flex items-center gap-1 hover:underline mb-2"
              >
                {showBulk ? '− Quitar datos masivos' : '+ Pegar lista CSV / Excel ahora'}
              </button>

              {showBulk && (
                <div className="animate-in fade-in zoom-in-95 duration-200">
                  <p className="text-xs text-gray-400 mb-2">Pega tus datos aquí (Formato: Término, Definición). Puedes usar Tab, "," o ";".</p>
                  <textarea 
                    value={bulkData}
                    onChange={(e) => setBulkData(e.target.value)}
                    placeholder="correr, run&#10;saltar, jump&#10;hablar, talk"
                    className="w-full h-32 px-4 py-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none font-mono text-sm"
                  />
                </div>
              )}
            </div>

            <div className="flex justify-end gap-3 pt-4 border-t">
              <button 
                type="button"
                onClick={() => { setIsCreating(false); setBulkData(''); setShowBulk(false); }}
                className="px-6 py-2 text-gray-600 font-medium hover:bg-gray-100 rounded-lg transition"
              >
                Cancelar
              </button>
              <button 
                type="submit"
                className="bg-indigo-600 text-white px-8 py-2 rounded-lg font-bold hover:bg-indigo-700 transition shadow-md"
              >
                Crear y Empezar
              </button>
            </div>
          </form>
        </div>
      )}

      {lists.length === 0 ? (
        <div className="text-center py-20 bg-white rounded-2xl border-2 border-dashed border-gray-200">
          <div className="w-20 h-20 bg-gray-50 rounded-full flex items-center justify-center mx-auto mb-4 text-gray-400">
            <svg className="w-10 h-10" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M12 6.253v13m0-13C10.832 5.477 9.246 5 7.5 5S4.168 5.477 3 6.253v13C4.168 18.477 5.754 18 7.5 18s3.332.477 4.5 1.253m0-13C13.168 5.477 14.754 5 16.5 5c1.747 0 3.332.477 4.5 1.253v13C19.832 18.477 18.247 18 16.5 18c-1.746 0-3.332.477-4.5 1.253" />
            </svg>
          </div>
          <h3 className="text-xl font-semibold text-gray-900">No hay listas aún</h3>
          <p className="text-gray-500 mt-2">Crea tu primera lista para empezar a estudiar.</p>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {lists.map(list => (
            <div key={list.id} className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 hover:shadow-md transition group">
              <div className="flex justify-between items-start mb-4">
                <span className="bg-indigo-50 text-indigo-600 text-xs font-bold px-2 py-1 rounded uppercase tracking-wider">
                  {list.concept}
                </span>
                <button 
                  onClick={() => onDelete(list.id)}
                  className="text-gray-400 hover:text-red-500 transition opacity-0 group-hover:opacity-100"
                >
                  <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                  </svg>
                </button>
              </div>
              <h3 className="text-xl font-bold text-gray-900 mb-1">{list.name}</h3>
              <p className="text-gray-500 text-sm mb-6">
                {list.associations.length} pares • {list.associations.filter(a => a.status === 'APRENDIDA').length} aprendidas
              </p>
              <div className="flex gap-3">
                <button 
                  onClick={() => onPlay(list.id)}
                  disabled={list.associations.length === 0}
                  className="flex-1 bg-indigo-600 text-white px-4 py-2 rounded-lg font-medium hover:bg-indigo-700 disabled:bg-gray-300 disabled:cursor-not-allowed transition"
                >
                  Estudiar
                </button>
                <button 
                  onClick={() => onEdit(list.id)}
                  className="px-4 py-2 border border-gray-200 rounded-lg text-gray-700 font-medium hover:bg-gray-50 transition"
                >
                  Editar
                </button>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { AssociationList, Association, AssociationStatus } from '../types';

interface ListEditorProps {
  list: AssociationList;
  onSave: (list: AssociationList) => void;
  onBack: () => void;
}

export const ListEditor: React.FC<ListEditorProps> = ({ list, onSave, onBack }) => {
  const [bulkText, setBulkText] = useState('');
  const [showBulk, setShowBulk] = useState(false);
  const [editList, setEditList] = useState<AssociationList>(list);

  const handleBulkAdd = () => {
    if (!bulkText.trim()) return;

    const newAssocs: Association[] = bulkText.split('\n')
      .map(line => line.trim())
      .filter(line => line.length > 0)
      .map(line => {
        // Soporta tab, punto y coma o coma
        const parts = line.split(/[\t;]|,(?=(?:(?:[^"]*"){2})*[^"]*$)/);
        const term = parts[0]?.replace(/^"|"$/g, '').trim() || '';
        const definition = parts[1]?.replace(/^"|"$/g, '').trim() || '';

        return {
          id: crypto.randomUUID(),
          term,
          definition,
          status: AssociationStatus.DESCONOCIDA
        };
      })
      .filter(a => a.term || a.definition);

    const updated = {
      ...editList,
      associations: [...editList.associations, ...newAssocs]
    };
    setEditList(updated);
    onSave(updated);
    setBulkText('');
    setShowBulk(false);
  };

  const handleAddRow = () => {
    const updated = {
      ...editList,
      associations: [
        ...editList.associations,
        { id: crypto.randomUUID(), term: '', definition: '', status: AssociationStatus.DESCONOCIDA }
      ]
    };
    setEditList(updated);
    onSave(updated);
  };

  const handleUpdateRow = (id: string, field: keyof Association, value: string) => {
    const updated = {
      ...editList,
      associations: editList.associations.map(a => a.id === id ? { ...a, [field]: value } : a)
    };
    setEditList(updated);
    onSave(updated);
  };

  const handleRemoveRow = (id: string) => {
    const updated = {
      ...editList,
      associations: editList.associations.filter(a => a.id !== id)
    };
    setEditList(updated);
    onSave(updated);
  };

  return (
    <div className="max-w-4xl mx-auto p-6">
      <div className="flex items-center gap-4 mb-8">
        <button onClick={onBack} className="text-gray-400 hover:text-indigo-600 transition p-2 hover:bg-white rounded-full">
          <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 19l-7-7m0 0l7-7m-7 7h18" />
          </svg>
        </button>
        <div>
          <h2 className="text-2xl font-bold text-gray-900">{editList.name}</h2>
          <p className="text-sm text-gray-500">Editando {editList.associations.length} asociaciones de {editList.concept}</p>
        </div>
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
        <div className="p-4 border-b bg-gray-50 flex justify-between items-center">
          <h3 className="font-semibold text-gray-700">Pares de Palabras</h3>
          <div className="flex gap-2">
             <button 
              onClick={() => setShowBulk(!showBulk)}
              className="text-indigo-600 text-sm font-medium hover:underline px-3"
            >
              {showBulk ? 'Ocultar Importación' : 'Importación CSV'}
            </button>
            <button 
              onClick={handleAddRow}
              className="bg-indigo-600 text-white px-4 py-1 rounded-lg text-sm font-medium hover:bg-indigo-700 transition"
            >
              Añadir Fila
            </button>
          </div>
        </div>

        {showBulk && (
          <div className="p-4 bg-indigo-50 border-b animate-in slide-in-from-top-2 duration-200">
            <label className="block text-sm font-medium text-indigo-900 mb-2">Pega tus datos (CSV, Excel o Tabulado)</label>
            <textarea 
              value={bulkText}
              onChange={(e) => setBulkText(e.target.value)}
              placeholder="Ejemplo:&#10;palabra 1, definición 1&#10;palabra 2, definición 2"
              className="w-full h-32 px-3 py-2 border border-indigo-200 rounded-lg text-sm mb-3 outline-none focus:ring-2 focus:ring-indigo-500 font-mono"
            />
            <div className="flex justify-between items-center">
              <span className="text-xs text-indigo-400">Soporta: Coma (,), Punto y coma (;) o Tabulación</span>
              <button 
                onClick={handleBulkAdd}
                className="bg-indigo-600 text-white px-6 py-2 rounded-lg text-sm font-bold hover:bg-indigo-700 shadow-sm"
              >
                Añadir Registros
              </button>
            </div>
          </div>
        )}

        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="text-xs uppercase text-gray-400 font-bold border-b">
                <th className="px-6 py-3">Término ({editList.concept.split('/')[0]})</th>
                <th className="px-6 py-3">Definición ({editList.concept.split('/')[1] || 'Par'})</th>
                <th className="px-6 py-3 w-20"></th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-50">
              {editList.associations.map((assoc) => (
                <tr key={assoc.id} className="group hover:bg-gray-50 transition">
                  <td className="px-6 py-3">
                    <input 
                      type="text" 
                      value={assoc.term}
                      onChange={(e) => handleUpdateRow(assoc.id, 'term', e.target.value)}
                      className="w-full bg-transparent border-none focus:ring-0 text-gray-900 placeholder-gray-300"
                      placeholder="Escribe el término..."
                    />
                  </td>
                  <td className="px-6 py-3">
                    <input 
                      type="text" 
                      value={assoc.definition}
                      onChange={(e) => handleUpdateRow(assoc.id, 'definition', e.target.value)}
                      className="w-full bg-transparent border-none focus:ring-0 text-gray-900 placeholder-gray-300"
                      placeholder="Escribe la definición..."
                    />
                  </td>
                  <td className="px-6 py-3 text-right">
                    <button 
                      onClick={() => handleRemoveRow(assoc.id)}
                      className="text-gray-300 hover:text-red-500 transition opacity-0 group-hover:opacity-100"
                    >
                      <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                      </svg>
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
          {editList.associations.length === 0 && (
            <div className="py-12 text-center text-gray-400 italic">
              No hay asociaciones aún. Usa la importación CSV o añade una fila manualmente.
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

