  };

  if (loading) return <div className="min-h-screen flex items-center justify-center font-bold text-indigo-600">Cargando FlashMind...</div>;
  if (!user) return <Auth />;

  const currentList = lists.find(l => l.id === selectedListId);

  return (
    <div className="min-h-screen flex flex-col">
      <header className="bg-white border-b px-6 py-4 flex justify-between items-center sticky top-0 z-50">
