import React, { useState, useEffect } from 'react';
import { Dashboard } from './components/Dashboard';
import { GameView } from './components/GameView';
import { ListEditor } from './components/ListEditor';
import { Auth } from './components/Auth';
import { AssociationList, Association, AssociationStatus } from './types';
import { auth, db, onAuthStateChanged, collection, query, where, onSnapshot, doc, setDoc, deleteDoc, isConfigured } from './firebase';

const MOCK_USER = {
  uid: 'guest-user-123',
  displayName: 'Invitado (Dev Mode)',
  photoURL: 'https://ui-avatars.com/api/?name=Guest+User&background=6366f1&color=fff'
};

const SAMPLE_LIST: AssociationList = {
  id: 'sample-list-1',
  userId: 'guest-user-123',
  name: 'Verbos Comunes',
  concept: 'Inglés / Español',
  associations: [
    { id: '1', term: 'Run', definition: 'Correr', status: AssociationStatus.DESCONOCIDA },
    { id: '2', term: 'Jump', definition: 'Saltar', status: AssociationStatus.DESCONOCIDA },
    { id: '3', term: 'Speak', definition: 'Hablar', status: AssociationStatus.DESCONOCIDA },
    { id: '4', term: 'Eat', definition: 'Comer', status: AssociationStatus.DESCONOCIDA },
    { id: '5', term: 'Sleep', definition: 'Dormir', status: AssociationStatus.DESCONOCIDA },
    { id: '6', term: 'Write', definition: 'Escribir', status: AssociationStatus.DESCONOCIDA },
    { id: '7', term: 'Read', definition: 'Leer', status: AssociationStatus.DESCONOCIDA },
    { id: '8', term: 'Think', definition: 'Pensar', status: AssociationStatus.DESCONOCIDA },
    { id: '9', term: 'Go', definition: 'Ir', status: AssociationStatus.DESCONOCIDA },
    { id: '10', term: 'Come', definition: 'Venir', status: AssociationStatus.DESCONOCIDA },
  ],
  settings: {
    mode: 'training',
    flipOrder: 'normal',
    threshold: 0.90
  },
  createdAt: Date.now()
};

const App: React.FC = () => {
  const [user, setUser] = useState<any>(null);
  const [loading, setLoading] = useState(true);
  const [view, setView] = useState<'dashboard' | 'game' | 'editor'>('dashboard');
  const [lists, setLists] = useState<AssociationList[]>([]);
  const [selectedListId, setSelectedListId] = useState<string | null>(null);

  // Auth Effect
  useEffect(() => {
    const guestUser = localStorage.getItem('flashmind_guest_user');
    if (guestUser) {
      setUser(JSON.parse(guestUser));
      setLoading(false);
      return;
    }

    if (isConfigured && auth) {
      return onAuthStateChanged(auth, (u) => {
        setUser(u);
        setLoading(false);
      });
    } else {
      setLoading(false);
    }
  }, []);

  // Data Fetching Effect
  useEffect(() => {
    if (!user) {
      setLists([]);
      return;
    }

    if (user.uid.startsWith('guest-')) {
      const savedLists = localStorage.getItem(`flashmind_lists_${user.uid}`);
      if (savedLists) {
        setLists(JSON.parse(savedLists));
      } else {
        setLists([SAMPLE_LIST]);
        localStorage.setItem(`flashmind_lists_${user.uid}`, JSON.stringify([SAMPLE_LIST]));
      }
      return;
    }

    if (isConfigured && db) {
      const q = query(collection(db, "lists"), where("userId", "==", user.uid));
      const unsubscribe = onSnapshot(q, (snapshot) => {
        const fetchedLists = snapshot.docs.map(doc => doc.data() as AssociationList);
        setLists(fetchedLists);
      });
      return () => unsubscribe();
    }
  }, [user]);

  const handleCreateList = async (name: string, concept: string, initialAssociations: Association[] = []) => {
    if (!user) return;
    const newList: AssociationList = {
      id: crypto.randomUUID(),
      userId: user.uid,
      name,
      concept,
      associations: initialAssociations,
      settings: {
        mode: 'training',
        flipOrder: 'normal',
        threshold: 0.95
      },
      createdAt: Date.now()
    };

    if (user.uid.startsWith('guest-')) {
      const updatedLists = [...lists, newList];
      setLists(updatedLists);
      localStorage.setItem(`flashmind_lists_${user.uid}`, JSON.stringify(updatedLists));
    } else if (isConfigured && db) {
      await setDoc(doc(db, "lists", newList.id), newList);
    }

    setSelectedListId(newList.id);
    setView('editor');
  };

  const handleUpdateList = async (updatedList: AssociationList) => {
    if (user.uid.startsWith('guest-')) {
      const updatedLists = lists.map(l => l.id === updatedList.id ? updatedList : l);
      setLists(updatedLists);
      localStorage.setItem(`flashmind_lists_${user.uid}`, JSON.stringify(updatedLists));
    } else if (isConfigured && db) {
      await setDoc(doc(db, "lists", updatedList.id), updatedList);
    }
  };

  const handleDeleteList = async (id: string) => {
    if (!confirm('¿Seguro que quieres borrar esta lista?')) return;

    if (user.uid.startsWith('guest-')) {
      const updatedLists = lists.filter(l => l.id !== id);
      setLists(updatedLists);
      localStorage.setItem(`flashmind_lists_${user.uid}`, JSON.stringify(updatedLists));
    } else if (isConfigured && db) {
      await deleteDoc(doc(db, "lists", id));
    }
  };

  const handleLoginDev = () => {
    localStorage.setItem('flashmind_guest_user', JSON.stringify(MOCK_USER));
    setUser(MOCK_USER);
  };

  const handleLogout = async () => {
    if (user.uid.startsWith('guest-')) {
      localStorage.removeItem('flashmind_guest_user');
      setUser(null);
    } else if (isConfigured && auth) {
      await auth.signOut();
    }
    setView('dashboard');
  };

  if (loading) return (
    <div className="min-h-screen flex flex-col items-center justify-center bg-gray-50">
      <div className="w-16 h-16 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin mb-4"></div>
      <div className="font-bold text-indigo-600 animate-pulse">Cargando FlashMind...</div>
    </div>
  );

  if (!user) return <Auth onLoginDev={handleLoginDev} />;

  const currentList = lists.find(l => l.id === selectedListId);

  return (
    <div className="min-h-screen flex flex-col bg-slate-50">
      <header className="bg-white border-b px-6 py-4 flex justify-between items-center sticky top-0 z-50 shadow-sm">
        <div className="flex items-center gap-2 cursor-pointer" onClick={() => setView('dashboard')}>
          <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center text-white font-bold shadow-indigo-200 shadow-lg">F</div>
          <h1 className="text-xl font-black text-gray-800 tracking-tight">FlashMind</h1>
        </div>
        <div className="flex items-center gap-4">
          <div className="hidden md:block text-right">
            <div className="text-xs font-bold text-gray-900">{user.displayName}</div>
            <div className="text-[10px] text-gray-400 font-medium uppercase tracking-tighter">
              {user.uid.startsWith('guest-') ? 'Modo Invitado' : 'Sincronizado'}
            </div>
          </div>
          <img src={user.photoURL} className="w-8 h-8 rounded-full border shadow-sm" alt="Avatar" />
          <button onClick={handleLogout} className="text-gray-400 hover:text-red-500 text-sm font-medium transition p-2 rounded-lg hover:bg-red-50">
            <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1" /></svg>
          </button>
        </div>
      </header>

      <main className="flex-1 overflow-y-auto">
        {view === 'dashboard' && (
          <Dashboard 
            lists={lists} 
            onCreate={handleCreateList} 
            onDelete={handleDeleteList}
            onEdit={(id) => { setSelectedListId(id); setView('editor'); }}
            onPlay={(id) => { setSelectedListId(id); setView('game'); }}
          />
        )}
        {view === 'editor' && currentList && (
          <ListEditor list={currentList} onSave={handleUpdateList} onBack={() => setView('dashboard')} />
        )}
        {view === 'game' && currentList && (
          <GameView list={currentList} onUpdateList={handleUpdateList} onBack={() => setView('dashboard')} />
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { AssociationList, Association, AssociationStatus, GameCycle, GameState, FlipOrder, GameMode } from '../types';
import { calculateSimilarity } from '../utils/similarity';

interface GameViewProps {
  list: AssociationList;
  onUpdateList: (list: AssociationList) => void;
  onBack: () => void;
}

export const GameView: React.FC<GameViewProps> = ({ list, onUpdateList, onBack }) => {
  const [gameState, setGameState] = useState<GameState>({
    listId: list.id,
    currentCycle: 1,
    currentIndex: 0,
    queue: [],
    history: [],
    isFinished: false,
    revealed: false,
    userInput: '',
    lastMatchScore: null,
    wasRevealed: false
  });

  const [associations, setAssociations] = useState<Association[]>(list.associations);
  const [showSettings, setShowSettings] = useState(false);

  useEffect(() => { startCycle(1); }, []);

  const startCycle = (cycle: GameCycle) => {
    let targetStatus: AssociationStatus;
    switch (cycle) {
      case 1: targetStatus = AssociationStatus.DESCONOCIDA; break;
      case 2: targetStatus = AssociationStatus.DESCUBIERTA; break;
      case 3: targetStatus = AssociationStatus.RECONOCIDA; break;
      case 4: targetStatus = AssociationStatus.CONOCIDA; break;
    }

    const availableIds = associations
      .filter(a => a.status === targetStatus && !a.history)
      .map(a => a.id);

    const shuffled = [...availableIds].sort(() => Math.random() - 0.5);

    if (shuffled.length === 0 && cycle < 4) {
      startCycle((cycle + 1) as GameCycle);
      return;
    }

    setGameState(prev => ({
      ...prev,
      currentCycle: cycle,
      currentIndex: 0,
      queue: shuffled,
      isFinished: shuffled.length === 0,
      revealed: false,
      userInput: '',
      wasRevealed: false,
      lastMatchScore: null
    }));
  };

  const handleResetAll = () => {
    const reset = associations.map(a => ({ ...a, status: AssociationStatus.DESCONOCIDA, history: false }));
    setAssociations(reset);
    onUpdateList({ ...list, associations: reset });
    setTimeout(() => startCycle(1), 10);
  };

  const handleArchiveLearned = () => {
    const archived = associations.map(a => a.status === AssociationStatus.APRENDIDA ? { ...a, history: true } : a);
    setAssociations(archived);
    onUpdateList({ ...list, associations: archived });
    // Después de archivar, reseteamos las que quedan a desconocidas para poder seguir
    handleContinue();
  };

  const handleContinue = () => {
    const reset = associations.map(a => !a.history ? { ...a, status: AssociationStatus.DESCONOCIDA } : a);
    setAssociations(reset);
    onUpdateList({ ...list, associations: reset });
    setTimeout(() => startCycle(1), 10);
  };

  const currentAssocId = gameState.queue[gameState.currentIndex];
  const currentAssoc = associations.find(a => a.id === currentAssocId);

  const displayTerm = useMemo(() => {
    if (!currentAssoc) return '';
    return list.settings.flipOrder === 'reversed' ? currentAssoc.definition : currentAssoc.term;
  }, [currentAssoc, list.settings.flipOrder]);

  const targetDefinition = useMemo(() => {
    if (!currentAssoc) return '';
    return list.settings.flipOrder === 'reversed' ? currentAssoc.term : currentAssoc.definition;
  }, [currentAssoc, list.settings.flipOrder]);

  const handleNext = () => {
    if (!currentAssoc) return;
    let nextStatus = currentAssoc.status;
    if (gameState.currentCycle === 1) nextStatus = AssociationStatus.DESCUBIERTA;
    else if (gameState.currentCycle === 2) nextStatus = AssociationStatus.RECONOCIDA;
    else if (gameState.currentCycle === 3) nextStatus = AssociationStatus.CONOCIDA;

    advance(nextStatus);
  };

  const handleCorrect = () => {
    if (!currentAssoc) return;
    let nextStatus = currentAssoc.status;
    if (gameState.currentCycle === 1) {
      nextStatus = gameState.wasRevealed ? AssociationStatus.DESCUBIERTA : AssociationStatus.APRENDIDA;
    }
    advance(nextStatus);
  };

  const advance = (nextStatus: AssociationStatus) => {
    const updatedAssociations = associations.map(a => a.id === currentAssocId ? { ...a, status: nextStatus } : a);
    setAssociations(updatedAssociations);

    if (gameState.currentIndex < gameState.queue.length - 1) {
      setGameState(prev => ({
        ...prev,
        currentIndex: prev.currentIndex + 1,
        revealed: false,
        userInput: '',
        wasRevealed: false,
        lastMatchScore: null
      }));
    } else {
      if (gameState.currentCycle < 4) {
        onUpdateList({ ...list, associations: updatedAssociations });
        startCycle((gameState.currentCycle + 1) as GameCycle);
      } else {
        setGameState(prev => ({ ...prev, isFinished: true }));
        onUpdateList({ ...list, associations: updatedAssociations });
      }
    }
  };

  const checkInput = () => {
    const score = calculateSimilarity(gameState.userInput, targetDefinition);
    setGameState(prev => ({ ...prev, lastMatchScore: score }));
    if (score >= list.settings.threshold) {
      handleCorrect();
    }
  };

  const stats = useMemo(() => ({
    learned: associations.filter(a => a.status === 'APRENDIDA' && !a.history).length,
    known: associations.filter(a => a.status === 'CONOCIDA' && !a.history).length,
    recognized: associations.filter(a => a.status === 'RECONOCIDA' && !a.history).length,
    discovered: associations.filter(a => a.status === 'DESCUBIERTA' && !a.history).length,
    archived: associations.filter(a => a.history).length,
    missing: gameState.queue.length - gameState.currentIndex
  }), [associations, gameState]);

  if (gameState.isFinished) {
    return (
      <FinishedPanel 
        stats={stats} 
        onBack={onBack} 
        onResetAll={handleResetAll}
        onArchive={handleArchiveLearned}
        onContinue={handleContinue}
      />
    );
  }

  return (
    <div className="max-w-4xl mx-auto p-4 md:p-6 pb-32">
      <button 
        onClick={() => setShowSettings(true)}
        className="fixed top-20 right-6 z-50 p-3 bg-white rounded-full shadow-lg border text-gray-400 hover:text-indigo-600 transition"
      >
        <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" /></svg>
      </button>

      <div className="grid grid-cols-2 md:grid-cols-6 gap-2 mb-8 animate-in fade-in duration-500">
        {Object.entries(stats).map(([k, v]) => (
          <div key={k} className="bg-white p-3 rounded-xl border border-gray-100 shadow-sm">
            <div className="text-xl font-black text-gray-900">{v}</div>
            <div className="text-[10px] uppercase font-bold text-gray-400 tracking-wider">{k}</div>
          </div>
        ))}
      </div>

      <div className="flex flex-col items-center">
        <div className="w-full max-w-lg bg-white rounded-[2.5rem] shadow-2xl border border-white/50 p-8 text-center relative overflow-hidden transition-all duration-300 transform">
          <div className="absolute top-0 left-0 w-full h-2 bg-indigo-600 opacity-20" />
          <div className="mb-8">
            <span className="text-xs font-bold text-indigo-400 uppercase tracking-widest block mb-2">Ciclo {gameState.currentCycle}</span>
            <h2 className="text-4xl md:text-5xl font-black text-gray-900 mb-6">{displayTerm}</h2>
            <div className="h-px w-20 bg-gray-100 mx-auto" />
          </div>

          <div className="min-h-[120px] flex flex-col justify-center">
            {list.settings.mode === 'real' ? (
              <div className="w-full space-y-4">
                <input 
                  type="text" autoFocus
                  value={gameState.userInput}
                  onChange={(e) => setGameState(prev => ({ ...prev, userInput: e.target.value }))}
                  onKeyDown={(e) => e.key === 'Enter' && checkInput()}
                  placeholder="Escribe la respuesta..."
                  className="w-full text-center text-2xl font-bold py-4 bg-gray-50 border-2 border-gray-100 rounded-2xl focus:border-indigo-600 outline-none transition"
                />
                {gameState.lastMatchScore !== null && (
                  <div className={`text-sm font-bold ${gameState.lastMatchScore >= list.settings.threshold ? 'text-green-500' : 'text-red-400'}`}>
                    Similitud: {Math.round(gameState.lastMatchScore * 100)}%
                  </div>
                )}
              </div>
            ) : (
              <div className="text-3xl font-black text-indigo-600">
                {gameState.revealed ? (
                  <div className="animate-in zoom-in-95 fade-in duration-300">{targetDefinition}</div>
                ) : (
                  <div className="text-gray-100 tracking-tighter select-none">••••••••••</div>
                )}
              </div>
            )}
            {gameState.revealed && list.settings.mode === 'real' && (
              <div className="mt-4 p-3 bg-red-50 text-red-500 rounded-xl text-xs font-bold animate-bounce">
                ¡Revelado! No contará para "Aprendida" este turno.
              </div>
            )}
          </div>
        </div>
      </div>

      <div className="fixed bottom-0 left-0 right-0 p-6 bg-gradient-to-t from-gray-50 via-gray-50 to-transparent flex justify-center z-40">
        <div className="max-w-md w-full flex gap-3">
          <button onClick={handleNext} className="flex-1 h-16 bg-white border-2 border-gray-100 text-gray-600 rounded-2xl font-black hover:bg-gray-50 transition shadow-lg active:scale-95">Siguiente</button>
          <button 
