import React, { useState, useEffect, useMemo } from 'react';
import { AssociationList, Association, AssociationStatus, GameCycle, GameState, FlipOrder, GameMode } from '../types';
import { calculateSimilarity } from '../utils/similarity';

interface GameViewProps {
  list: AssociationList;
  onUpdateList: (list: AssociationList) => void;
  onBack: () => void;
}

interface Toast {
  message: string;
  type: 'success' | 'error' | 'info';
}

export const GameView: React.FC<GameViewProps> = ({ list, onUpdateList, onBack }) => {
  const [gameState, setGameState] = useState<GameState>({
    listId: list.id,
    currentCycle: 1,
    currentIndex: 0,
    queue: [],
    history: [],
    isFinished: false,
    revealed: false,
    userInput: '',
    lastMatchScore: null,
    wasRevealed: false
  });

  const [associations, setAssociations] = useState<Association[]>(list.associations);
  const [showSettings, setShowSettings] = useState(false);
  const [toast, setToast] = useState<Toast | null>(null);

  useEffect(() => {
    if (toast) {
      const timer = setTimeout(() => setToast(null), 3000);
      return () => clearTimeout(timer);
    }
  }, [toast]);

  const showNotification = (message: string, type: 'success' | 'error' | 'info' = 'success') => {
    setToast({ message, type });
  };

  useEffect(() => { 
    startCycle(1, associations); 
  }, []);

  const startCycle = (cycle: GameCycle, currentAssocs: Association[]) => {
    let targetStatus: AssociationStatus;
    switch (cycle) {
      case 1: targetStatus = AssociationStatus.DESCONOCIDA; break;
      case 2: targetStatus = AssociationStatus.DESCUBIERTA; break;
      case 3: targetStatus = AssociationStatus.RECONOCIDA; break;
      case 4: targetStatus = AssociationStatus.CONOCIDA; break;
      default: targetStatus = AssociationStatus.DESCONOCIDA;
    }

    const availableIds = currentAssocs
      .filter(a => a.status === targetStatus && !a.history)
      .map(a => a.id);

    const shuffled = [...availableIds].sort(() => Math.random() - 0.5);

    if (shuffled.length === 0 && cycle < 4) {
      startCycle((cycle + 1) as GameCycle, currentAssocs);
      return;
    }

    setGameState({
      listId: list.id,
      currentCycle: cycle,
      currentIndex: 0,
      queue: shuffled,
      history: [],
      isFinished: shuffled.length === 0,
      revealed: false,
      userInput: '',
      wasRevealed: false,
      lastMatchScore: null
    });
  };

  const handleResetAll = () => {
    if (!confirm('¿Estás seguro de que quieres volver todo a fojas cero? Se perderá todo el progreso de esta lista.')) return;

    const reset = associations.map(a => ({ ...a, status: AssociationStatus.DESCONOCIDA, history: false }));
    setAssociations(reset);
    onUpdateList({ ...list, associations: reset });
    setShowSettings(false);
    showNotification("Progreso reiniciado por completo", "info");

    // Forzamos el inicio del ciclo 1 con las asociaciones recién reseteadas
    startCycle(1, reset);
  };

  const handleArchiveLearned = () => {
    const toArchiveCount = associations.filter(a => a.status === AssociationStatus.APRENDIDA).length;
    if (toArchiveCount === 0) {
      showNotification("No hay asociaciones aprendidas para archivar", "error");
      return;
    }
    const archived = associations.map(a => a.status === AssociationStatus.APRENDIDA ? { ...a, history: true } : a);
    setAssociations(archived);
    onUpdateList({ ...list, associations: archived });
    showNotification(`${toArchiveCount} asociaciones enviadas al histórico`, "success");

    // Reiniciamos para la siguiente ronda sin las archivadas
    const nextRoundAssocs = archived.map(a => !a.history ? { ...a, status: AssociationStatus.DESCONOCIDA } : a);
    setAssociations(nextRoundAssocs);
    startCycle(1, nextRoundAssocs);
  };

  const handleContinue = () => {
    const reset = associations.map(a => !a.history ? { ...a, status: AssociationStatus.DESCONOCIDA } : a);
    setAssociations(reset);
    onUpdateList({ ...list, associations: reset });
    showNotification("Iniciando nueva sesión de práctica", "success");
    startCycle(1, reset);
  };

  const currentAssocId = gameState.queue[gameState.currentIndex];
  const currentAssoc = associations.find(a => a.id === currentAssocId);

  const displayTerm = useMemo(() => {
    if (!currentAssoc) return '';
    return list.settings.flipOrder === 'reversed' ? currentAssoc.definition : currentAssoc.term;
  }, [currentAssoc, list.settings.flipOrder]);

  const targetDefinition = useMemo(() => {
    if (!currentAssoc) return '';
    return list.settings.flipOrder === 'reversed' ? currentAssoc.term : currentAssoc.definition;
  }, [currentAssoc, list.settings.flipOrder]);

  const handleNext = () => {
    if (!currentAssoc) return;
    let nextStatus = currentAssoc.status;
    if (gameState.currentCycle === 1) nextStatus = AssociationStatus.DESCUBIERTA;
    else if (gameState.currentCycle === 2) nextStatus = AssociationStatus.RECONOCIDA;
    else if (gameState.currentCycle === 3) nextStatus = AssociationStatus.CONOCIDA;

    advance(nextStatus);
  };

  const handleCorrect = () => {
    if (!currentAssoc) return;
    let nextStatus = currentAssoc.status;
    if (gameState.currentCycle === 1) {
      nextStatus = gameState.wasRevealed ? AssociationStatus.DESCUBIERTA : AssociationStatus.APRENDIDA;
    }
    advance(nextStatus);
  };

  const advance = (nextStatus: AssociationStatus) => {
    const updatedAssociations = associations.map(a => a.id === currentAssocId ? { ...a, status: nextStatus } : a);
    setAssociations(updatedAssociations);

    if (gameState.currentIndex < gameState.queue.length - 1) {
      setGameState(prev => ({
        ...prev,
        currentIndex: prev.currentIndex + 1,
        revealed: false,
        userInput: '',
        wasRevealed: false,
        lastMatchScore: null
      }));
    } else {
      onUpdateList({ ...list, associations: updatedAssociations });
      if (gameState.currentCycle < 4) {
        startCycle((gameState.currentCycle + 1) as GameCycle, updatedAssociations);
      } else {
        setGameState(prev => ({ ...prev, isFinished: true }));
      }
    }
  };

  const checkInput = () => {
    const score = calculateSimilarity(gameState.userInput, targetDefinition);
    setGameState(prev => ({ ...prev, lastMatchScore: score }));
    if (score >= list.settings.threshold) {
      handleCorrect();
    } else {
      showNotification("Sigue intentando...", "error");
    }
  };

  const stats = useMemo(() => ({
    learned: associations.filter(a => a.status === 'APRENDIDA' && !a.history).length,
    known: associations.filter(a => a.status === 'CONOCIDA' && !a.history).length,
    recognized: associations.filter(a => a.status === 'RECONOCIDA' && !a.history).length,
    discovered: associations.filter(a => a.status === 'DESCUBIERTA' && !a.history).length,
    archived: associations.filter(a => a.history).length,
    missing: gameState.queue.length - gameState.currentIndex
  }), [associations, gameState]);

  if (gameState.isFinished) {
    return (
      <div className="relative min-h-screen">
        <FinishedPanel 
          stats={stats} 
          onBack={onBack} 
          onResetAll={handleResetAll}
          onArchive={handleArchiveLearned}
          onContinue={handleContinue}
        />
        {toast && <ToastNotification toast={toast} onClose={() => setToast(null)} />}
      </div>
    );
  }

  return (
    <div className="max-w-4xl mx-auto p-4 md:p-6 pb-32 relative">
      {toast && <ToastNotification toast={toast} onClose={() => setToast(null)} />}

      <button 
        onClick={() => setShowSettings(true)}
        className="fixed top-20 right-6 z-50 p-3 bg-white rounded-full shadow-lg border text-gray-400 hover:text-indigo-600 transition"
      >
        <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" /></svg>
      </button>

      <div className="grid grid-cols-2 md:grid-cols-6 gap-2 mb-8 animate-in fade-in duration-500">
        {Object.entries(stats).map(([k, v]) => (
          <div key={k} className="bg-white p-3 rounded-xl border border-gray-100 shadow-sm">
            <div className="text-xl font-black text-gray-900">{v}</div>
            <div className="text-[10px] uppercase font-bold text-gray-400 tracking-wider">{k}</div>
          </div>
        ))}
      </div>

      <div className="flex flex-col items-center">
        <div className="w-full max-w-lg bg-white rounded-[2.5rem] shadow-2xl border border-white/50 p-8 text-center relative overflow-hidden transition-all duration-300 transform">
          <div className="absolute top-0 left-0 w-full h-2 bg-indigo-600 opacity-20" />
          <div className="mb-8">
            <span className="text-xs font-bold text-indigo-400 uppercase tracking-widest block mb-2">Ciclo {gameState.currentCycle}</span>
            <h2 className="text-4xl md:text-5xl font-black text-gray-900 mb-6">{displayTerm || 'Sin palabras'}</h2>
            <div className="h-px w-20 bg-gray-100 mx-auto" />
          </div>

          <div className="min-h-[120px] flex flex-col justify-center">
            {list.settings.mode === 'real' ? (
              <div className="w-full space-y-4">
                <input 
                  type="text" autoFocus
                  value={gameState.userInput}
                  onChange={(e) => setGameState(prev => ({ ...prev, userInput: e.target.value }))}
                  onKeyDown={(e) => e.key === 'Enter' && checkInput()}
                  placeholder="Escribe la respuesta..."
                  className="w-full text-center text-2xl font-bold py-4 bg-gray-50 border-2 border-gray-100 rounded-2xl focus:border-indigo-600 outline-none transition"
                />
                {gameState.lastMatchScore !== null && (
                  <div className={`text-sm font-bold ${gameState.lastMatchScore >= list.settings.threshold ? 'text-green-500' : 'text-red-400'}`}>
                    Similitud: {Math.round(gameState.lastMatchScore * 100)}%
                  </div>
                )}
              </div>
            ) : (
              <div className="text-3xl font-black text-indigo-600">
                {gameState.revealed ? (
                  <div className="animate-in zoom-in-95 fade-in duration-300">{targetDefinition}</div>
                ) : (
                  <div className="text-gray-100 tracking-tighter select-none">••••••••••</div>
                )}
              </div>
            )}
          </div>
        </div>
      </div>

      <div className="fixed bottom-0 left-0 right-0 p-6 bg-gradient-to-t from-gray-50 via-gray-50 to-transparent flex justify-center z-40">
        <div className="max-w-md w-full flex gap-3">
          <button onClick={handleNext} className="flex-1 h-16 bg-white border-2 border-gray-100 text-gray-600 rounded-2xl font-black hover:bg-gray-50 transition shadow-lg active:scale-95">Siguiente</button>
          <button 
            onClick={() => setGameState(prev => ({ ...prev, revealed: !prev.revealed, wasRevealed: true }))}
            className={`flex-1 h-16 rounded-2xl font-black transition shadow-lg active:scale-95 ${gameState.revealed ? 'bg-indigo-100 text-indigo-700' : 'bg-indigo-50 text-indigo-600'}`}
          >
            {gameState.revealed ? 'Ocultar' : 'Revelar'}
          </button>
          {list.settings.mode === 'training' ? (
            <button onClick={handleCorrect} className="flex-1 h-16 bg-indigo-600 text-white rounded-2xl font-black hover:bg-indigo-700 transition shadow-xl active:scale-95 flex items-center justify-center gap-2">
              <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg>
              Correcta
            </button>
          ) : (
            <button onClick={checkInput} className="flex-1 h-16 bg-indigo-600 text-white rounded-2xl font-black hover:bg-indigo-700 transition shadow-xl active:scale-95">Check</button>
          )}
        </div>
      </div>

      {showSettings && (
        <div className="fixed inset-0 bg-black/50 backdrop-blur-sm z-[100] flex items-center justify-center p-6 animate-in fade-in duration-200">
          <div className="bg-white w-full max-w-sm rounded-[2rem] p-8 shadow-2xl animate-in zoom-in-95 duration-200 overflow-y-auto max-h-[90vh]">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-2xl font-black text-gray-900">Ajustes</h3>
              <button onClick={() => setShowSettings(false)} className="text-gray-400 hover:text-gray-600 p-1">
                <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>

            <div className="space-y-6">
              <div>
                <label className="block text-xs font-black text-gray-400 uppercase tracking-widest mb-3">Modo de Juego</label>
                <div className="flex bg-gray-50 p-1 rounded-xl">
                  {(['training', 'real'] as GameMode[]).map(m => (
                    <button key={m} onClick={() => onUpdateList({ ...list, settings: { ...list.settings, mode: m } })} className={`flex-1 py-2 rounded-lg text-sm font-bold transition ${list.settings.mode === m ? 'bg-white text-indigo-600 shadow-sm' : 'text-gray-400'}`}>{m === 'training' ? 'Práctica' : 'Escritura'}</button>
                  ))}
                </div>
              </div>
              <div>
                <label className="block text-xs font-black text-gray-400 uppercase tracking-widest mb-3">Invertir Pares</label>
                <div className="flex bg-gray-50 p-1 rounded-xl">
                  {(['normal', 'reversed'] as FlipOrder[]).map(o => (
                    <button key={o} onClick={() => onUpdateList({ ...list, settings: { ...list.settings, flipOrder: o } })} className={`flex-1 py-2 rounded-lg text-sm font-bold transition ${list.settings.flipOrder === o ? 'bg-white text-indigo-600 shadow-sm' : 'text-gray-400'}`}>{o === 'normal' ? 'Normal' : 'Inverso'}</button>
                  ))}
                </div>
              </div>
              <div>
                <label className="block text-xs font-black text-gray-400 uppercase tracking-widest mb-3">Umbral ({Math.round(list.settings.threshold * 100)}%)</label>
                <input type="range" min="0.5" max="1" step="0.05" value={list.settings.threshold} onChange={(e) => onUpdateList({ ...list, settings: { ...list.settings, threshold: parseFloat(e.target.value) } })} className="w-full h-2 bg-indigo-100 rounded-lg appearance-none cursor-pointer accent-indigo-600" />
              </div>

              <div className="pt-6 border-t border-red-50">
                <label className="block text-xs font-black text-red-400 uppercase tracking-widest mb-3">Zona de Peligro</label>
                <button 
                  onClick={handleResetAll}
                  className="w-full flex items-center justify-center gap-2 bg-red-50 text-red-600 py-3 rounded-xl font-bold hover:bg-red-100 transition border border-red-100 active:scale-95"
                >
                  <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                  Reiniciar todo a fojas cero
                </button>
              </div>
            </div>

            <button onClick={() => setShowSettings(false)} className="w-full mt-8 bg-gray-900 text-white py-4 rounded-2xl font-black hover:bg-gray-800 transition">Cerrar y Aplicar</button>
          </div>
        </div>
      )}
    </div>
  );
};

const ToastNotification = ({ toast, onClose }: { toast: Toast, onClose: () => void }) => (
  <div 
    onClick={onClose}
    className={`fixed top-10 left-1/2 -translate-x-1/2 z-[300] px-6 py-4 rounded-2xl shadow-2xl font-bold text-sm cursor-pointer animate-in slide-in-from-top-4 fade-in duration-300 flex items-center gap-3 border ${
      toast.type === 'success' ? 'bg-green-600 text-white border-green-500' : 
      toast.type === 'error' ? 'bg-red-600 text-white border-red-500' : 
      'bg-indigo-600 text-white border-indigo-500'
    }`}
  >
    {toast.type === 'success' && <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg>}
    {toast.type === 'error' && <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" /></svg>}
    {toast.type === 'info' && <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>}
    {toast.message}
  </div>
);

const FinishedPanel = ({ stats, onBack, onResetAll, onArchive, onContinue }: { stats: any, onBack: () => void, onResetAll: () => void, onArchive: () => void, onContinue: () => void }) => (
  <div className="max-w-xl mx-auto p-6 text-center animate-in zoom-in duration-500 pb-20">
    <div className="bg-white rounded-[3rem] shadow-2xl p-10 border border-indigo-50">
      <div className="w-20 h-20 bg-green-100 text-green-600 rounded-full flex items-center justify-center mx-auto mb-6">
        <svg className="w-10 h-10" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg>
      </div>
      <h2 className="text-4xl font-black text-gray-900 mb-2">Resultados</h2>
      <p className="text-gray-500 mb-8">Has completado los ciclos de aprendizaje.</p>

      <div className="grid grid-cols-3 gap-3 mb-10">
        <div className="bg-green-50 p-4 rounded-2xl">
          <div className="text-2xl font-black text-green-600">{stats.learned}</div>
          <div className="text-[9px] uppercase font-bold text-green-400">Aprendidas</div>
        </div>
        <div className="bg-indigo-50 p-4 rounded-2xl">
          <div className="text-2xl font-black text-indigo-600">{stats.known + stats.recognized + stats.discovered}</div>
          <div className="text-[9px] uppercase font-bold text-indigo-400">En Proceso</div>
        </div>
        <div className="bg-gray-50 p-4 rounded-2xl">
          <div className="text-2xl font-black text-gray-400">{stats.archived}</div>
          <div className="text-[9px] uppercase font-bold text-gray-400">Histórico</div>
        </div>
      </div>

      <div className="grid grid-cols-1 gap-3">
        <button 
          onClick={onContinue} 
          className="w-full bg-indigo-600 text-white py-4 rounded-2xl font-black hover:bg-indigo-700 transition shadow-xl flex items-center justify-center gap-2 active:scale-95"
        >
          <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg>
          Continuar Práctica
        </button>

        <div className="grid grid-cols-2 gap-3">
          <button 
            onClick={onArchive} 
            className="bg-emerald-50 text-emerald-700 py-4 rounded-2xl font-bold hover:bg-emerald-100 transition border border-emerald-100 text-sm active:scale-95"
          >
            Mover al Histórico
          </button>
          <button 
            onClick={onResetAll} 
            className="bg-red-50 text-red-700 py-4 rounded-2xl font-bold hover:bg-red-100 transition border border-red-100 text-sm active:scale-95"
          >
            Reiniciar a Cero
          </button>
        </div>

        <button 
          onClick={onBack} 
          className="w-full bg-white border border-gray-100 text-gray-400 py-4 rounded-2xl font-bold hover:bg-gray-50 transition mt-4 active:scale-95"
        >
          Volver al Panel
        </button>
      </div>
    </div>
  </div>
);

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { AssociationList, Association, AssociationStatus, GameCycle, GameState, FlipOrder, GameMode } from '../types';
import { calculateSimilarity } from '../utils/similarity';

interface GameViewProps {
  list: AssociationList;
  onUpdateList: (list: AssociationList) => void;
  onBack: () => void;
}

interface Toast {
  message: string;
  type: 'success' | 'error' | 'info';
  id: number;
}

export const GameView: React.FC<GameViewProps> = ({ list, onUpdateList, onBack }) => {
  const [associations, setAssociations] = useState<Association[]>(list.associations);
  const [gameState, setGameState] = useState<GameState>({
    listId: list.id,
    currentCycle: 1,
    currentIndex: 0,
    queue: [],
    history: [],
    isFinished: false,
    revealed: false,
    userInput: '',
    lastMatchScore: null,
    wasRevealed: false
  });

  const [showSettings, setShowSettings] = useState(false);
  const [toast, setToast] = useState<Toast | null>(null);

  // Sistema de notificaciones robusto
  const showNotification = useCallback((message: string, type: 'success' | 'error' | 'info' = 'success') => {
    setToast({ message, type, id: Date.now() });
  }, []);

  useEffect(() => {
    if (toast) {
      const timer = setTimeout(() => setToast(null), 3000);
      return () => clearTimeout(timer);
    }
  }, [toast]);

  // Motor de ciclos del juego
  const startCycle = useCallback((cycle: GameCycle, currentAssocs: Association[]) => {
    let targetStatus: AssociationStatus;
    switch (cycle) {
      case 1: targetStatus = AssociationStatus.DESCONOCIDA; break;
      case 2: targetStatus = AssociationStatus.DESCUBIERTA; break;
      case 3: targetStatus = AssociationStatus.RECONOCIDA; break;
      case 4: targetStatus = AssociationStatus.CONOCIDA; break;
      default: targetStatus = AssociationStatus.DESCONOCIDA;
    }

    const availableIds = currentAssocs
      .filter(a => a.status === targetStatus && !a.history)
      .map(a => a.id);

    const shuffled = [...availableIds].sort(() => Math.random() - 0.5);

    // Si no hay palabras en este ciclo, saltar al siguiente automáticamente
    if (shuffled.length === 0 && cycle < 4) {
      startCycle((cycle + 1) as GameCycle, currentAssocs);
      return;
    }

    setGameState({
      listId: list.id,
      currentCycle: cycle,
      currentIndex: 0,
      queue: shuffled,
      history: [],
      isFinished: shuffled.length === 0,
      revealed: false,
      userInput: '',
      wasRevealed: false,
      lastMatchScore: null
    });
  }, [list.id]);

  // Inicialización
  useEffect(() => { 
    startCycle(1, associations); 
  }, []);

  // Función de REINICIO CRÍTICA
  const handleResetAll = () => {
    const confirmacion = window.confirm('¿Estás seguro de que quieres volver todo a fojas cero? Se borrará todo el progreso de estudio de esta lista.');
    if (!confirmacion) return;

    // 1. Crear el nuevo set de datos
    const resetData = associations.map(a => ({ 
      ...a, 
      status: AssociationStatus.DESCONOCIDA, 
      history: false 
    }));

    // 2. Actualizar estados locales de forma inmediata
    setAssociations(resetData);
    setShowSettings(false);

    // 3. Notificar al usuario (Toast)
    showNotification("Progreso reiniciado por completo", "info");

    // 4. Sincronizar con el padre
    onUpdateList({ ...list, associations: resetData });

    // 5. Reiniciar el motor del juego con los nuevos datos
    setTimeout(() => {
      startCycle(1, resetData);
    }, 50);
  };

  const handleArchiveLearned = () => {
    const toArchiveCount = associations.filter(a => a.status === AssociationStatus.APRENDIDA).length;
    if (toArchiveCount === 0) {
      showNotification("No hay palabras 'Aprendidas' para archivar", "error");
      return;
    }
    const archived = associations.map(a => a.status === AssociationStatus.APRENDIDA ? { ...a, history: true } : a);
    setAssociations(archived);
    onUpdateList({ ...list, associations: archived });
    showNotification(`${toArchiveCount} asociaciones archivadas`, "success");

    const nextRoundAssocs = archived.map(a => !a.history ? { ...a, status: AssociationStatus.DESCONOCIDA } : a);
    setAssociations(nextRoundAssocs);
    startCycle(1, nextRoundAssocs);
  };

  const handleContinue = () => {
    const reset = associations.map(a => !a.history ? { ...a, status: AssociationStatus.DESCONOCIDA } : a);
    setAssociations(reset);
    onUpdateList({ ...list, associations: reset });
    showNotification("Iniciando nueva sesión", "success");
    startCycle(1, reset);
  };

  const currentAssocId = gameState.queue[gameState.currentIndex];
  const currentAssoc = associations.find(a => a.id === currentAssocId);

  const displayTerm = useMemo(() => {
    if (!currentAssoc) return '';
    return list.settings.flipOrder === 'reversed' ? currentAssoc.definition : currentAssoc.term;
  }, [currentAssoc, list.settings.flipOrder]);

  const targetDefinition = useMemo(() => {
    if (!currentAssoc) return '';
    return list.settings.flipOrder === 'reversed' ? currentAssoc.term : currentAssoc.definition;
  }, [currentAssoc, list.settings.flipOrder]);

  const handleNext = () => {
    if (!currentAssoc) return;
    let nextStatus = currentAssoc.status;
    if (gameState.currentCycle === 1) nextStatus = AssociationStatus.DESCUBIERTA;
    else if (gameState.currentCycle === 2) nextStatus = AssociationStatus.RECONOCIDA;
    else if (gameState.currentCycle === 3) nextStatus = AssociationStatus.CONOCIDA;

    advance(nextStatus);
  };

  const handleCorrect = () => {
    if (!currentAssoc) return;
    let nextStatus = currentAssoc.status;
    if (gameState.currentCycle === 1) {
      nextStatus = gameState.wasRevealed ? AssociationStatus.DESCUBIERTA : AssociationStatus.APRENDIDA;
    }
    advance(nextStatus);
  };

  const advance = (nextStatus: AssociationStatus) => {
    const updatedAssociations = associations.map(a => a.id === currentAssocId ? { ...a, status: nextStatus } : a);
    setAssociations(updatedAssociations);

    if (gameState.currentIndex < gameState.queue.length - 1) {
      setGameState(prev => ({
        ...prev,
        currentIndex: prev.currentIndex + 1,
        revealed: false,
        userInput: '',
        wasRevealed: false,
        lastMatchScore: null
      }));
    } else {
      onUpdateList({ ...list, associations: updatedAssociations });
      if (gameState.currentCycle < 4) {
        startCycle((gameState.currentCycle + 1) as GameCycle, updatedAssociations);
      } else {
        setGameState(prev => ({ ...prev, isFinished: true }));
      }
    }
  };

  const checkInput = () => {
    const score = calculateSimilarity(gameState.userInput, targetDefinition);
    setGameState(prev => ({ ...prev, lastMatchScore: score }));
    if (score >= list.settings.threshold) {
      handleCorrect();
    } else {
      showNotification("Casi... intenta otra vez", "error");
    }
  };

  const stats = useMemo(() => ({
    learned: associations.filter(a => a.status === 'APRENDIDA' && !a.history).length,
    known: associations.filter(a => a.status === 'CONOCIDA' && !a.history).length,
    recognized: associations.filter(a => a.status === 'RECONOCIDA' && !a.history).length,
    discovered: associations.filter(a => a.status === 'DESCUBIERTA' && !a.history).length,
    archived: associations.filter(a => a.history).length,
    missing: gameState.queue.length - gameState.currentIndex
  }), [associations, gameState]);

  return (
    <div className="min-h-screen relative flex flex-col">
      {/* TOAST PORTAL-LIKE RENDERING */}
      {toast && <ToastNotification key={toast.id} toast={toast} onClose={() => setToast(null)} />}

      {gameState.isFinished ? (
        <FinishedPanel 
          stats={stats} 
          onBack={onBack} 
          onResetAll={handleResetAll}
          onArchive={handleArchiveLearned}
          onContinue={handleContinue}
        />
      ) : (
        <div className="max-w-4xl mx-auto p-4 md:p-6 pb-32 w-full flex-1">
          <button 
            onClick={() => setShowSettings(true)}
            className="fixed top-20 right-6 z-40 p-3 bg-white rounded-full shadow-lg border text-gray-400 hover:text-indigo-600 transition active:scale-90"
          >
            <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" /></svg>
          </button>

          <div className="grid grid-cols-2 md:grid-cols-6 gap-2 mb-8 animate-in fade-in duration-500">
            {Object.entries(stats).map(([k, v]) => (
              <div key={k} className="bg-white p-3 rounded-xl border border-gray-100 shadow-sm">
                <div className="text-xl font-black text-gray-900">{v}</div>
                <div className="text-[10px] uppercase font-bold text-gray-400 tracking-wider">{k}</div>
              </div>
            ))}
          </div>

          <div className="flex flex-col items-center">
            <div className="w-full max-w-lg bg-white rounded-[2.5rem] shadow-2xl border border-white/50 p-8 text-center relative overflow-hidden transition-all duration-300 transform">
              <div className="absolute top-0 left-0 w-full h-2 bg-indigo-600 opacity-20" />
              <div className="mb-8">
                <span className="text-xs font-bold text-indigo-400 uppercase tracking-widest block mb-2">Ciclo {gameState.currentCycle}</span>
                <h2 className="text-4xl md:text-5xl font-black text-gray-900 mb-6 break-words">{displayTerm || 'Lista Vacía'}</h2>
                <div className="h-px w-20 bg-gray-100 mx-auto" />
              </div>

              <div className="min-h-[120px] flex flex-col justify-center">
                {list.settings.mode === 'real' ? (
                  <div className="w-full space-y-4">
                    <input 
                      type="text" autoFocus
                      value={gameState.userInput}
                      onChange={(e) => setGameState(prev => ({ ...prev, userInput: e.target.value }))}
                      onKeyDown={(e) => e.key === 'Enter' && checkInput()}
                      placeholder="Escribe la respuesta..."
                      className="w-full text-center text-2xl font-bold py-4 bg-gray-50 border-2 border-gray-100 rounded-2xl focus:border-indigo-600 outline-none transition"
                    />
                    {gameState.lastMatchScore !== null && (
                      <div className={`text-sm font-bold ${gameState.lastMatchScore >= list.settings.threshold ? 'text-green-500' : 'text-red-400'}`}>
                        Similitud: {Math.round(gameState.lastMatchScore * 100)}%
                      </div>
                    )}
                  </div>
                ) : (
                  <div className="text-3xl font-black text-indigo-600">
                    {gameState.revealed ? (
                      <div className="animate-in zoom-in-95 fade-in duration-300 break-words">{targetDefinition}</div>
                    ) : (
                      <div className="text-gray-100 tracking-tighter select-none">••••••••••</div>
                    )}
                  </div>
                )}
              </div>
            </div>
          </div>

          <div className="fixed bottom-0 left-0 right-0 p-6 bg-gradient-to-t from-gray-50 via-gray-50 to-transparent flex justify-center z-30">
            <div className="max-w-md w-full flex gap-3">
              <button onClick={handleNext} className="flex-1 h-16 bg-white border-2 border-gray-100 text-gray-600 rounded-2xl font-black hover:bg-gray-50 transition shadow-lg active:scale-95">Siguiente</button>
              <button 
                onClick={() => setGameState(prev => ({ ...prev, revealed: !prev.revealed, wasRevealed: true }))}
                className={`flex-1 h-16 rounded-2xl font-black transition shadow-lg active:scale-95 ${gameState.revealed ? 'bg-indigo-100 text-indigo-700' : 'bg-indigo-50 text-indigo-600'}`}
              >
                {gameState.revealed ? 'Ocultar' : 'Revelar'}
              </button>
              {list.settings.mode === 'training' ? (
                <button onClick={handleCorrect} className="flex-1 h-16 bg-indigo-600 text-white rounded-2xl font-black hover:bg-indigo-700 transition shadow-xl active:scale-95 flex items-center justify-center gap-2">
                  <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg>
                  Correcta
                </button>
              ) : (
                <button onClick={checkInput} className="flex-1 h-16 bg-indigo-600 text-white rounded-2xl font-black hover:bg-indigo-700 transition shadow-xl active:scale-95">Check</button>
              )}
            </div>
          </div>
        </div>
      )}

      {/* SETTINGS MODAL */}
      {showSettings && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-md z-[100] flex items-center justify-center p-6 animate-in fade-in duration-200">
          <div className="bg-white w-full max-w-sm rounded-[2.5rem] p-8 shadow-2xl animate-in zoom-in-95 duration-200 overflow-y-auto max-h-[90vh]">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-2xl font-black text-gray-900 tracking-tight">Estudiar</h3>
              <button onClick={() => setShowSettings(false)} className="text-gray-400 hover:text-gray-600 p-2 rounded-full hover:bg-gray-50">
                <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>

            <div className="space-y-6">
              <div>
                <label className="block text-xs font-black text-gray-400 uppercase tracking-widest mb-3">Modo de Juego</label>
                <div className="flex bg-gray-100 p-1.5 rounded-2xl">
                  {(['training', 'real'] as GameMode[]).map(m => (
                    <button key={m} onClick={() => onUpdateList({ ...list, settings: { ...list.settings, mode: m } })} className={`flex-1 py-3 rounded-xl text-sm font-black transition-all ${list.settings.mode === m ? 'bg-white text-indigo-600 shadow-sm scale-[1.02]' : 'text-gray-400 hover:text-gray-600'}`}>{m === 'training' ? 'Práctica' : 'Escritura'}</button>
                  ))}
                </div>
              </div>

              <div>
                <label className="block text-xs font-black text-gray-400 uppercase tracking-widest mb-3">Invertir Pares</label>
                <div className="flex bg-gray-100 p-1.5 rounded-2xl">
                  {(['normal', 'reversed'] as FlipOrder[]).map(o => (
                    <button key={o} onClick={() => onUpdateList({ ...list, settings: { ...list.settings, flipOrder: o } })} className={`flex-1 py-3 rounded-xl text-sm font-black transition-all ${list.settings.flipOrder === o ? 'bg-white text-indigo-600 shadow-sm scale-[1.02]' : 'text-gray-400 hover:text-gray-600'}`}>{o === 'normal' ? 'Normal' : 'Inverso'}</button>
                  ))}
                </div>
              </div>

              <div className="pt-6 border-t border-red-50">
                <label className="block text-xs font-black text-red-400 uppercase tracking-widest mb-4 text-center">Zona de Peligro</label>
                <button 
                  onClick={handleResetAll}
                  className="w-full flex items-center justify-center gap-3 bg-red-600 text-white py-4 rounded-2xl font-black hover:bg-red-700 transition shadow-lg active:scale-90"
                >
                  <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                  Reiniciar todo a cero
                </button>
              </div>
            </div>

            <button onClick={() => setShowSettings(false)} className="w-full mt-8 bg-gray-900 text-white py-4 rounded-2xl font-black hover:bg-gray-800 transition active:scale-95">Cerrar Ajustes</button>
          </div>
        </div>
      )}
    </div>
  );
};

const ToastNotification = ({ toast, onClose }: { toast: Toast, onClose: () => void }) => (
  <div 
    onClick={onClose}
    className={`fixed top-12 left-1/2 -translate-x-1/2 z-[9999] px-8 py-5 rounded-[2rem] shadow-[0_20px_50px_rgba(0,0,0,0.2)] font-black text-base cursor-pointer animate-in slide-in-from-top-12 fade-in duration-500 flex items-center gap-4 border-2 ${
      toast.type === 'success' ? 'bg-green-600 text-white border-green-400' : 
      toast.type === 'error' ? 'bg-red-600 text-white border-red-400' : 
      'bg-indigo-700 text-white border-indigo-500'
    }`}
  >
    <div className="bg-white/20 p-2 rounded-full">
      {toast.type === 'success' && <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={4} d="M5 13l4 4L19 7" /></svg>}
      {toast.type === 'error' && <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={4} d="M6 18L18 6M6 6l12 12" /></svg>}
      {toast.type === 'info' && <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={4} d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>}
    </div>
    <span className="tracking-tight">{toast.message}</span>
  </div>
);

const FinishedPanel = ({ stats, onBack, onResetAll, onArchive, onContinue }: { stats: any, onBack: () => void, onResetAll: () => void, onArchive: () => void, onContinue: () => void }) => (
  <div className="max-w-xl mx-auto p-6 text-center animate-in zoom-in duration-500 flex-1 flex flex-col justify-center">
    <div className="bg-white rounded-[3.5rem] shadow-2xl p-10 border border-indigo-50">
      <div className="w-24 h-24 bg-green-100 text-green-600 rounded-full flex items-center justify-center mx-auto mb-8 shadow-inner">
        <svg className="w-12 h-12" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg>
      </div>
      <h2 className="text-4xl font-black text-gray-900 mb-2 tracking-tight">¡Objetivo Logrado!</h2>
      <p className="text-gray-500 mb-10 font-medium">Has procesado todas las asociaciones disponibles.</p>

      <div className="grid grid-cols-3 gap-4 mb-10">
        <div className="bg-green-50 p-5 rounded-3xl border border-green-100">
          <div className="text-3xl font-black text-green-600">{stats.learned}</div>
          <div className="text-[10px] uppercase font-black text-green-400 tracking-widest mt-1">Aprendidas</div>
        </div>
        <div className="bg-indigo-50 p-5 rounded-3xl border border-indigo-100">
          <div className="text-3xl font-black text-indigo-600">{stats.known + stats.recognized + stats.discovered}</div>
          <div className="text-[10px] uppercase font-black text-indigo-400 tracking-widest mt-1">En Proceso</div>
        </div>
        <div className="bg-gray-50 p-5 rounded-3xl border border-gray-100">
          <div className="text-3xl font-black text-gray-400">{stats.archived}</div>
          <div className="text-[10px] uppercase font-black text-gray-400 tracking-widest mt-1">Histórico</div>
        </div>
      </div>

      <div className="space-y-4">
        <button 
          onClick={onContinue} 
          className="w-full bg-indigo-600 text-white py-5 rounded-[2rem] font-black hover:bg-indigo-700 transition shadow-xl shadow-indigo-200 flex items-center justify-center gap-3 active:scale-95 text-lg"
        >
          <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg>
          Continuar Práctica
        </button>

        <div className="grid grid-cols-2 gap-4">
          <button 
            onClick={onArchive} 
            className="bg-emerald-50 text-emerald-700 py-5 rounded-[2rem] font-black hover:bg-emerald-100 transition border-2 border-emerald-100 text-sm active:scale-95"
          >
            Mover al Histórico
          </button>
          <button 
            onClick={onResetAll} 
            className="bg-red-50 text-red-700 py-5 rounded-[2rem] font-black hover:bg-red-100 transition border-2 border-red-100 text-sm active:scale-95"
          >
            Reiniciar a Cero
          </button>
        </div>

        <button 
          onClick={onBack} 
          className="w-full bg-white text-gray-400 py-4 rounded-2xl font-bold hover:bg-gray-50 transition active:scale-95"
        >
          Volver al Dashboard
        </button>
      </div>
    </div>
  </div>
);

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { AssociationList, Association, AssociationStatus, GameCycle, GameState, FlipOrder, GameMode } from '../types';
import { calculateSimilarity } from '../utils/similarity';

interface GameViewProps {
  list: AssociationList;
  onUpdateList: (list: AssociationList) => void;
  onBack: () => void;
}

interface Toast {
  message: string;
  type: 'success' | 'error' | 'info';
  id: number;
}

export const GameView: React.FC<GameViewProps> = ({ list, onUpdateList, onBack }) => {
  const [associations, setAssociations] = useState<Association[]>(list.associations);
  const [gameState, setGameState] = useState<GameState>({
    listId: list.id,
    currentCycle: 1,
    currentIndex: 0,
    queue: [],
    history: [],
    isFinished: false,
    revealed: false,
    userInput: '',
    lastMatchScore: null,
    wasRevealed: false
  });

  const [showSettings, setShowSettings] = useState(false);
  const [toast, setToast] = useState<Toast | null>(null);

  // Sistema de notificaciones robusto
  const showNotification = useCallback((message: string, type: 'success' | 'error' | 'info' = 'success') => {
    setToast({ message, type, id: Date.now() });
  }, []);

  useEffect(() => {
    if (toast) {
      const timer = setTimeout(() => setToast(null), 3000);
      return () => clearTimeout(timer);
    }
  }, [toast]);

  // Motor de ciclos del juego
  const startCycle = useCallback((cycle: GameCycle, currentAssocs: Association[]) => {
    let targetStatus: AssociationStatus;
    switch (cycle) {
      case 1: targetStatus = AssociationStatus.DESCONOCIDA; break;
      case 2: targetStatus = AssociationStatus.DESCUBIERTA; break;
      case 3: targetStatus = AssociationStatus.RECONOCIDA; break;
      case 4: targetStatus = AssociationStatus.CONOCIDA; break;
      default: targetStatus = AssociationStatus.DESCONOCIDA;
    }

    const availableIds = currentAssocs
      .filter(a => a.status === targetStatus && !a.history)
      .map(a => a.id);

    const shuffled = [...availableIds].sort(() => Math.random() - 0.5);

    // Si no hay palabras en este ciclo, saltar al siguiente automáticamente
    if (shuffled.length === 0 && cycle < 4) {
      startCycle((cycle + 1) as GameCycle, currentAssocs);
      return;
    }

    setGameState({
      listId: list.id,
      currentCycle: cycle,
      currentIndex: 0,
      queue: shuffled,
      history: [],
      isFinished: shuffled.length === 0,
      revealed: false,
      userInput: '',
      wasRevealed: false,
      lastMatchScore: null
    });
  }, [list.id]);

  // Inicialización
  useEffect(() => { 
    startCycle(1, associations); 
  }, []);

  // Función de REINICIO CRÍTICA
  const handleResetAll = () => {
    const confirmacion = window.confirm('¿Estás seguro de que quieres volver todo a fojas cero? Se borrará todo el progreso de estudio de esta lista.');
    if (!confirmacion) return;

    // 1. Crear el nuevo set de datos
    const resetData = associations.map(a => ({ 
      ...a, 
      status: AssociationStatus.DESCONOCIDA, 
      history: false 
    }));

    // 2. Actualizar estados locales de forma inmediata
    setAssociations(resetData);
    setShowSettings(false);

    // 3. Notificar al usuario (Toast)
    showNotification("Progreso reiniciado por completo", "info");

    // 4. Sincronizar con el padre
    onUpdateList({ ...list, associations: resetData });

    // 5. Reiniciar el motor del juego con los nuevos datos
    setTimeout(() => {
      startCycle(1, resetData);
    }, 50);
  };

  const handleArchiveLearned = () => {
    const toArchiveCount = associations.filter(a => a.status === AssociationStatus.APRENDIDA).length;
    if (toArchiveCount === 0) {
      showNotification("No hay palabras 'Aprendidas' para archivar", "error");
      return;
    }
    const archived = associations.map(a => a.status === AssociationStatus.APRENDIDA ? { ...a, history: true } : a);
    setAssociations(archived);
    onUpdateList({ ...list, associations: archived });
    showNotification(`${toArchiveCount} asociaciones archivadas`, "success");

    const nextRoundAssocs = archived.map(a => !a.history ? { ...a, status: AssociationStatus.DESCONOCIDA } : a);
    setAssociations(nextRoundAssocs);
    startCycle(1, nextRoundAssocs);
  };

  const handleContinue = () => {
    const reset = associations.map(a => !a.history ? { ...a, status: AssociationStatus.DESCONOCIDA } : a);
    setAssociations(reset);
    onUpdateList({ ...list, associations: reset });
    showNotification("Iniciando nueva sesión", "success");
    startCycle(1, reset);
  };

  const currentAssocId = gameState.queue[gameState.currentIndex];
  const currentAssoc = associations.find(a => a.id === currentAssocId);

  const displayTerm = useMemo(() => {
    if (!currentAssoc) return '';
    return list.settings.flipOrder === 'reversed' ? currentAssoc.definition : currentAssoc.term;
  }, [currentAssoc, list.settings.flipOrder]);

  const targetDefinition = useMemo(() => {
    if (!currentAssoc) return '';
    return list.settings.flipOrder === 'reversed' ? currentAssoc.term : currentAssoc.definition;
  }, [currentAssoc, list.settings.flipOrder]);

  const handleNext = () => {
    if (!currentAssoc) return;
    let nextStatus = currentAssoc.status;
    if (gameState.currentCycle === 1) nextStatus = AssociationStatus.DESCUBIERTA;
    else if (gameState.currentCycle === 2) nextStatus = AssociationStatus.RECONOCIDA;
    else if (gameState.currentCycle === 3) nextStatus = AssociationStatus.CONOCIDA;

    advance(nextStatus);
  };

  const handleCorrect = () => {
    if (!currentAssoc) return;
    let nextStatus = currentAssoc.status;
    if (gameState.currentCycle === 1) {
      nextStatus = gameState.wasRevealed ? AssociationStatus.DESCUBIERTA : AssociationStatus.APRENDIDA;
    }
    advance(nextStatus);
  };

  const advance = (nextStatus: AssociationStatus) => {
    const updatedAssociations = associations.map(a => a.id === currentAssocId ? { ...a, status: nextStatus } : a);
    setAssociations(updatedAssociations);

    if (gameState.currentIndex < gameState.queue.length - 1) {
      setGameState(prev => ({
        ...prev,
        currentIndex: prev.currentIndex + 1,
        revealed: false,
        userInput: '',
        wasRevealed: false,
        lastMatchScore: null
      }));
    } else {
      onUpdateList({ ...list, associations: updatedAssociations });
      if (gameState.currentCycle < 4) {
        startCycle((gameState.currentCycle + 1) as GameCycle, updatedAssociations);
      } else {
        setGameState(prev => ({ ...prev, isFinished: true }));
      }
    }
  };

  const checkInput = () => {
    const score = calculateSimilarity(gameState.userInput, targetDefinition);
    setGameState(prev => ({ ...prev, lastMatchScore: score }));
    if (score >= list.settings.threshold) {
      handleCorrect();
    } else {
      showNotification("Casi... intenta otra vez", "error");
    }
  };

  const stats = useMemo(() => ({
    learned: associations.filter(a => a.status === 'APRENDIDA' && !a.history).length,
    known: associations.filter(a => a.status === 'CONOCIDA' && !a.history).length,
    recognized: associations.filter(a => a.status === 'RECONOCIDA' && !a.history).length,
    discovered: associations.filter(a => a.status === 'DESCUBIERTA' && !a.history).length,
    archived: associations.filter(a => a.history).length,
    missing: gameState.queue.length - gameState.currentIndex
  }), [associations, gameState]);

  return (
    <div className="min-h-screen relative flex flex-col">
      {/* TOAST PORTAL-LIKE RENDERING */}
      {toast && <ToastNotification key={toast.id} toast={toast} onClose={() => setToast(null)} />}

      {gameState.isFinished ? (
        <FinishedPanel 
          stats={stats} 
          onBack={onBack} 
          onResetAll={handleResetAll}
          onArchive={handleArchiveLearned}
          onContinue={handleContinue}
        />
      ) : (
        <div className="max-w-4xl mx-auto p-4 md:p-6 pb-32 w-full flex-1">
          <button 
            onClick={() => setShowSettings(true)}
            className="fixed top-20 right-6 z-40 p-3 bg-white rounded-full shadow-lg border text-gray-400 hover:text-indigo-600 transition active:scale-90"
          >
            <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" /></svg>
          </button>

          <div className="grid grid-cols-2 md:grid-cols-6 gap-2 mb-8 animate-in fade-in duration-500">
            {Object.entries(stats).map(([k, v]) => (
              <div key={k} className="bg-white p-3 rounded-xl border border-gray-100 shadow-sm">
                <div className="text-xl font-black text-gray-900">{v}</div>
                <div className="text-[10px] uppercase font-bold text-gray-400 tracking-wider">{k}</div>
              </div>
            ))}
          </div>

          <div className="flex flex-col items-center">
            <div className="w-full max-w-lg bg-white rounded-[2.5rem] shadow-2xl border border-white/50 p-8 text-center relative overflow-hidden transition-all duration-300 transform">
              <div className="absolute top-0 left-0 w-full h-2 bg-indigo-600 opacity-20" />
              <div className="mb-8">
                <span className="text-xs font-bold text-indigo-400 uppercase tracking-widest block mb-2">Ciclo {gameState.currentCycle}</span>
                <h2 className="text-4xl md:text-5xl font-black text-gray-900 mb-6 break-words">{displayTerm || 'Lista Vacía'}</h2>
                <div className="h-px w-20 bg-gray-100 mx-auto" />
              </div>

              <div className="min-h-[120px] flex flex-col justify-center">
                {list.settings.mode === 'real' ? (
                  <div className="w-full space-y-4">
                    <input 
                      type="text" autoFocus
                      value={gameState.userInput}
                      onChange={(e) => setGameState(prev => ({ ...prev, userInput: e.target.value }))}
                      onKeyDown={(e) => e.key === 'Enter' && checkInput()}
                      placeholder="Escribe la respuesta..."
                      className="w-full text-center text-2xl font-bold py-4 bg-gray-50 border-2 border-gray-100 rounded-2xl focus:border-indigo-600 outline-none transition"
                    />
                    {gameState.lastMatchScore !== null && (
                      <div className={`text-sm font-bold ${gameState.lastMatchScore >= list.settings.threshold ? 'text-green-500' : 'text-red-400'}`}>
                        Similitud: {Math.round(gameState.lastMatchScore * 100)}%
                      </div>
                    )}
                  </div>
                ) : (
                  <div className="text-3xl font-black text-indigo-600">
                    {gameState.revealed ? (
                      <div className="animate-in zoom-in-95 fade-in duration-300 break-words">{targetDefinition}</div>
                    ) : (
                      <div className="text-gray-100 tracking-tighter select-none">••••••••••</div>
                    )}
                  </div>
                )}
              </div>
            </div>
          </div>

          <div className="fixed bottom-0 left-0 right-0 p-6 bg-gradient-to-t from-gray-50 via-gray-50 to-transparent flex justify-center z-30">
            <div className="max-w-md w-full flex gap-3">
              <button onClick={handleNext} className="flex-1 h-16 bg-white border-2 border-gray-100 text-gray-600 rounded-2xl font-black hover:bg-gray-50 transition shadow-lg active:scale-95">Siguiente</button>
              <button 
                onClick={() => setGameState(prev => ({ ...prev, revealed: !prev.revealed, wasRevealed: true }))}
                className={`flex-1 h-16 rounded-2xl font-black transition shadow-lg active:scale-95 ${gameState.revealed ? 'bg-indigo-100 text-indigo-700' : 'bg-indigo-50 text-indigo-600'}`}
              >
                {gameState.revealed ? 'Ocultar' : 'Revelar'}
              </button>
              {list.settings.mode === 'training' ? (
                <button onClick={handleCorrect} className="flex-1 h-16 bg-indigo-600 text-white rounded-2xl font-black hover:bg-indigo-700 transition shadow-xl active:scale-95 flex items-center justify-center gap-2">
                  <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg>
                  Correcta
                </button>
              ) : (
                <button onClick={checkInput} className="flex-1 h-16 bg-indigo-600 text-white rounded-2xl font-black hover:bg-indigo-700 transition shadow-xl active:scale-95">Check</button>
              )}
            </div>
          </div>
        </div>
      )}

      {/* SETTINGS MODAL */}
      {showSettings && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-md z-[100] flex items-center justify-center p-6 animate-in fade-in duration-200">
          <div className="bg-white w-full max-w-sm rounded-[2.5rem] p-8 shadow-2xl animate-in zoom-in-95 duration-200 overflow-y-auto max-h-[90vh]">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-2xl font-black text-gray-900 tracking-tight">Estudiar</h3>
              <button onClick={() => setShowSettings(false)} className="text-gray-400 hover:text-gray-600 p-2 rounded-full hover:bg-gray-50">
                <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>

            <div className="space-y-6">
              <div>
                <label className="block text-xs font-black text-gray-400 uppercase tracking-widest mb-3">Modo de Juego</label>
                <div className="flex bg-gray-100 p-1.5 rounded-2xl">
                  {(['training', 'real'] as GameMode[]).map(m => (
                    <button key={m} onClick={() => onUpdateList({ ...list, settings: { ...list.settings, mode: m } })} className={`flex-1 py-3 rounded-xl text-sm font-black transition-all ${list.settings.mode === m ? 'bg-white text-indigo-600 shadow-sm scale-[1.02]' : 'text-gray-400 hover:text-gray-600'}`}>{m === 'training' ? 'Práctica' : 'Escritura'}</button>
                  ))}
                </div>
              </div>

              <div>
                <label className="block text-xs font-black text-gray-400 uppercase tracking-widest mb-3">Invertir Pares</label>
                <div className="flex bg-gray-100 p-1.5 rounded-2xl">
                  {(['normal', 'reversed'] as FlipOrder[]).map(o => (
                    <button key={o} onClick={() => onUpdateList({ ...list, settings: { ...list.settings, flipOrder: o } })} className={`flex-1 py-3 rounded-xl text-sm font-black transition-all ${list.settings.flipOrder === o ? 'bg-white text-indigo-600 shadow-sm scale-[1.02]' : 'text-gray-400 hover:text-gray-600'}`}>{o === 'normal' ? 'Normal' : 'Inverso'}</button>
                  ))}
                </div>
              </div>

              <div className="pt-6 border-t border-red-50">
                <label className="block text-xs font-black text-red-400 uppercase tracking-widest mb-4 text-center">Zona de Peligro</label>
                <button 
                  onClick={handleResetAll}
                  className="w-full flex items-center justify-center gap-3 bg-red-600 text-white py-4 rounded-2xl font-black hover:bg-red-700 transition shadow-lg active:scale-90"
                >
                  <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                  Reiniciar todo a cero
                </button>
              </div>
            </div>

            <button onClick={() => setShowSettings(false)} className="w-full mt-8 bg-gray-900 text-white py-4 rounded-2xl font-black hover:bg-gray-800 transition active:scale-95">Cerrar Ajustes</button>
          </div>
        </div>
      )}
    </div>
  );
};

