import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { AssociationList, Association, AssociationStatus, GameCycle, GameState, FlipOrder, GameMode } from '../types';
import { calculateSimilarity } from '../utils/similarity';

interface GameViewProps {
  list: AssociationList;
  onUpdateList: (list: AssociationList) => void;
  onBack: () => void;
}

interface Toast {
  message: string;
  type: 'success' | 'error' | 'info';
  id: number;
}

export const GameView: React.FC<GameViewProps> = ({ list, onUpdateList, onBack }) => {
  const [associations, setAssociations] = useState<Association[]>(list.associations);
  const [gameState, setGameState] = useState<GameState>({
    listId: list.id,
    currentCycle: 1,
    currentIndex: 0,
    queue: [],
    history: [],
    isFinished: false,
    revealed: false,
    userInput: '',
    lastMatchScore: null,
    wasRevealed: false
  });

  const [showSettings, setShowSettings] = useState(false);
  const [showConfirmReset, setShowConfirmReset] = useState(false);
  const [toast, setToast] = useState<Toast | null>(null);

  const showNotification = useCallback((message: string, type: 'success' | 'error' | 'info' = 'success') => {
    setToast({ message, type, id: Date.now() });
  }, []);

  useEffect(() => {
    if (toast) {
      const timer = setTimeout(() => setToast(null), 3000);
      return () => clearTimeout(timer);
    }
  }, [toast]);

  const startCycle = useCallback((cycle: GameCycle, currentAssocs: Association[]) => {
    let targetStatus: AssociationStatus;
    switch (cycle) {
      case 1: targetStatus = AssociationStatus.DESCONOCIDA; break;
      case 2: targetStatus = AssociationStatus.DESCUBIERTA; break;
      case 3: targetStatus = AssociationStatus.RECONOCIDA; break;
      case 4: targetStatus = AssociationStatus.CONOCIDA; break;
      default: targetStatus = AssociationStatus.DESCONOCIDA;
    }

    const availableIds = currentAssocs
      .filter(a => a.status === targetStatus && !a.history)
      .map(a => a.id);

    const shuffled = [...availableIds].sort(() => Math.random() - 0.5);

    if (shuffled.length === 0 && cycle < 4) {
      startCycle((cycle + 1) as GameCycle, currentAssocs);
      return;
    }

    setGameState({
      listId: list.id,
      currentCycle: cycle,
      currentIndex: 0,
      queue: shuffled,
      history: [],
      isFinished: shuffled.length === 0,
      revealed: false,
      userInput: '',
      wasRevealed: false,
      lastMatchScore: null
    });
  }, [list.id]);

  useEffect(() => { 
    startCycle(1, associations); 
  }, []);

  const executeFullReset = () => {
    const resetData = associations.map(a => ({ 
      ...a, 
      status: AssociationStatus.DESCONOCIDA, 
      history: false 
    }));

    setAssociations(resetData);
    setShowConfirmReset(false);
    setShowSettings(false);
    showNotification("Progreso reiniciado por completo", "info");
    onUpdateList({ ...list, associations: resetData });

    // Forzamos el reinicio del motor del juego
    startCycle(1, resetData);
  };

  const handleArchiveLearned = () => {
    const toArchiveCount = associations.filter(a => a.status === AssociationStatus.APRENDIDA).length;
    if (toArchiveCount === 0) {
      showNotification("No hay palabras para archivar", "error");
      return;
    }
    const archived = associations.map(a => a.status === AssociationStatus.APRENDIDA ? { ...a, history: true } : a);
    setAssociations(archived);
    onUpdateList({ ...list, associations: archived });
    showNotification(`${toArchiveCount} asociaciones archivadas`, "success");

    const nextRoundAssocs = archived.map(a => !a.history ? { ...a, status: AssociationStatus.DESCONOCIDA } : a);
    setAssociations(nextRoundAssocs);
    startCycle(1, nextRoundAssocs);
  };

  const handleContinue = () => {
    const reset = associations.map(a => !a.history ? { ...a, status: AssociationStatus.DESCONOCIDA } : a);
    setAssociations(reset);
    onUpdateList({ ...list, associations: reset });
    showNotification("Nueva sesión de estudio", "success");
    startCycle(1, reset);
  };

  const currentAssocId = gameState.queue[gameState.currentIndex];
  const currentAssoc = associations.find(a => a.id === currentAssocId);

  const displayTerm = useMemo(() => {
    if (!currentAssoc) return '';
    return list.settings.flipOrder === 'reversed' ? currentAssoc.definition : currentAssoc.term;
  }, [currentAssoc, list.settings.flipOrder]);

  const targetDefinition = useMemo(() => {
    if (!currentAssoc) return '';
    return list.settings.flipOrder === 'reversed' ? currentAssoc.term : currentAssoc.definition;
  }, [currentAssoc, list.settings.flipOrder]);

  const handleNext = () => {
    if (!currentAssoc) return;
    let nextStatus = currentAssoc.status;
    if (gameState.currentCycle === 1) nextStatus = AssociationStatus.DESCUBIERTA;
    else if (gameState.currentCycle === 2) nextStatus = AssociationStatus.RECONOCIDA;
    else if (gameState.currentCycle === 3) nextStatus = AssociationStatus.CONOCIDA;

    advance(nextStatus);
  };

  const handleCorrect = () => {
    if (!currentAssoc) return;
    let nextStatus = currentAssoc.status;
    if (gameState.currentCycle === 1) {
      nextStatus = gameState.wasRevealed ? AssociationStatus.DESCUBIERTA : AssociationStatus.APRENDIDA;
    }
    advance(nextStatus);
  };

  const advance = (nextStatus: AssociationStatus) => {
    const updatedAssociations = associations.map(a => a.id === currentAssocId ? { ...a, status: nextStatus } : a);
    setAssociations(updatedAssociations);

    if (gameState.currentIndex < gameState.queue.length - 1) {
      setGameState(prev => ({
        ...prev,
        currentIndex: prev.currentIndex + 1,
        revealed: false,
        userInput: '',
        wasRevealed: false,
        lastMatchScore: null
      }));
    } else {
      onUpdateList({ ...list, associations: updatedAssociations });
      if (gameState.currentCycle < 4) {
        startCycle((gameState.currentCycle + 1) as GameCycle, updatedAssociations);
      } else {
        setGameState(prev => ({ ...prev, isFinished: true }));
      }
    }
  };

  const checkInput = () => {
    const score = calculateSimilarity(gameState.userInput, targetDefinition);
    setGameState(prev => ({ ...prev, lastMatchScore: score }));
    if (score >= list.settings.threshold) {
      handleCorrect();
    } else {
      showNotification("Sigue intentando", "error");
    }
  };

  const stats = useMemo(() => ({
    learned: associations.filter(a => a.status === 'APRENDIDA' && !a.history).length,
    known: associations.filter(a => a.status === 'CONOCIDA' && !a.history).length,
    recognized: associations.filter(a => a.status === 'RECONOCIDA' && !a.history).length,
    discovered: associations.filter(a => a.status === 'DESCUBIERTA' && !a.history).length,
    archived: associations.filter(a => a.history).length,
    missing: gameState.queue.length - gameState.currentIndex
  }), [associations, gameState]);

  return (
    <div className="min-h-screen relative flex flex-col bg-slate-50 overflow-x-hidden">
      {/* CAPA DE NOTIFICACIONES (SIEMPRE VISIBLE) */}
      {toast && <ToastNotification key={toast.id} toast={toast} onClose={() => setToast(null)} />}

      {/* MODAL DE CONFIRMACIÓN DE REINICIO (Sustituye a window.confirm) */}
      {showConfirmReset && (
        <div className="fixed inset-0 bg-black/70 backdrop-blur-md z-[200] flex items-center justify-center p-6 animate-in fade-in duration-200">
          <div className="bg-white w-full max-w-sm rounded-[2.5rem] p-10 text-center shadow-2xl animate-in zoom-in-95 duration-200">
            <div className="w-20 h-20 bg-red-100 text-red-600 rounded-full flex items-center justify-center mx-auto mb-6">
              <svg className="w-10 h-10" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>
            </div>
            <h3 className="text-2xl font-black text-gray-900 mb-3">¿Reiniciar todo?</h3>
            <p className="text-gray-500 mb-8 font-medium">Esta acción devolverá todas las palabras al estado de "Desconocidas" y borrará tu progreso actual.</p>
            <div className="space-y-3">
              <button onClick={executeFullReset} className="w-full bg-red-600 text-white py-4 rounded-2xl font-black shadow-lg hover:bg-red-700 active:scale-95 transition">Sí, reiniciar todo</button>
              <button onClick={() => setShowConfirmReset(false)} className="w-full bg-gray-100 text-gray-600 py-4 rounded-2xl font-bold hover:bg-gray-200 active:scale-95 transition">Cancelar</button>
            </div>
          </div>
        </div>
      )}

      {gameState.isFinished ? (
        <FinishedPanel 
          stats={stats} 
          onBack={onBack} 
          onResetAll={() => setShowConfirmReset(true)}
          onArchive={handleArchiveLearned}
          onContinue={handleContinue}
        />
      ) : (
        <div className="max-w-4xl mx-auto p-4 md:p-6 pb-32 w-full flex-1 flex flex-col">
          <button 
            onClick={() => setShowSettings(true)}
            className="fixed top-20 right-6 z-40 p-3 bg-white rounded-full shadow-lg border border-gray-100 text-gray-400 hover:text-indigo-600 transition active:scale-90"
          >
            <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" /></svg>
          </button>

          <div className="grid grid-cols-2 md:grid-cols-6 gap-2 mb-8 animate-in fade-in duration-500">
            {Object.entries(stats).map(([k, v]) => (
              <div key={k} className="bg-white p-3 rounded-xl border border-gray-100 shadow-sm">
                <div className="text-xl font-black text-gray-900">{v}</div>
                <div className="text-[10px] uppercase font-bold text-gray-400 tracking-wider">{k}</div>
              </div>
            ))}
          </div>

          <div className="flex-1 flex flex-col items-center justify-center -mt-12">
            <div className="w-full max-w-lg bg-white rounded-[3rem] shadow-2xl border border-white/50 p-10 text-center relative overflow-hidden transition-all duration-300">
              <div className="absolute top-0 left-0 w-full h-2 bg-indigo-600 opacity-20" />
              <div className="mb-10">
                <span className="text-xs font-bold text-indigo-400 uppercase tracking-[0.2em] block mb-3">Ciclo de Aprendizaje {gameState.currentCycle}</span>
                <h2 className="text-4xl md:text-5xl font-black text-gray-900 mb-8 break-words leading-tight">{displayTerm || 'Fin de lista'}</h2>
                <div className="h-1.5 w-16 bg-gray-50 mx-auto rounded-full" />
              </div>

              <div className="min-h-[140px] flex flex-col justify-center">
                {list.settings.mode === 'real' ? (
                  <div className="w-full space-y-4">
                    <input 
                      type="text" autoFocus
                      value={gameState.userInput}
                      onChange={(e) => setGameState(prev => ({ ...prev, userInput: e.target.value }))}
                      onKeyDown={(e) => e.key === 'Enter' && checkInput()}
                      placeholder="Escribe aquí..."
                      className="w-full text-center text-2xl font-black py-5 bg-slate-50 border-2 border-slate-100 rounded-[2rem] focus:border-indigo-600 focus:bg-white outline-none transition-all shadow-inner"
                    />
                    {gameState.lastMatchScore !== null && (
                      <div className={`text-sm font-black uppercase tracking-widest ${gameState.lastMatchScore >= list.settings.threshold ? 'text-emerald-500' : 'text-rose-400'}`}>
                        {Math.round(gameState.lastMatchScore * 100)}% de coincidencia
                      </div>
                    )}
                  </div>
                ) : (
                  <div className="text-3xl font-black text-indigo-600 px-4">
                    {gameState.revealed ? (
                      <div className="animate-in zoom-in-95 slide-in-from-bottom-2 fade-in duration-300 break-words">{targetDefinition}</div>
                    ) : (
                      <div className="text-slate-100 tracking-tighter select-none scale-y-75 py-2">•••••••••••••</div>
                    )}
                  </div>
                )}
              </div>
            </div>
          </div>

          <div className="fixed bottom-0 left-0 right-0 p-8 bg-gradient-to-t from-slate-50 via-slate-50/90 to-transparent flex justify-center z-30">
            <div className="max-w-md w-full flex gap-4">
              <button onClick={handleNext} className="flex-1 h-16 bg-white border-2 border-slate-100 text-slate-600 rounded-2xl font-black hover:bg-slate-50 transition shadow-lg active:scale-95 text-sm uppercase tracking-widest">Pasar</button>
              <button 
                onClick={() => setGameState(prev => ({ ...prev, revealed: !prev.revealed, wasRevealed: true }))}
                className={`flex-1 h-16 rounded-2xl font-black transition shadow-lg active:scale-95 text-sm uppercase tracking-widest ${gameState.revealed ? 'bg-indigo-100 text-indigo-700' : 'bg-indigo-50 text-indigo-600'}`}
              >
                {gameState.revealed ? 'Ocultar' : 'Revelar'}
              </button>
              {list.settings.mode === 'training' ? (
                <button onClick={handleCorrect} className="flex-1 h-16 bg-indigo-600 text-white rounded-2xl font-black hover:bg-indigo-700 transition shadow-xl shadow-indigo-200 active:scale-95 flex items-center justify-center gap-2 text-sm uppercase tracking-widest">
                  Correcta
                </button>
              ) : (
                <button onClick={checkInput} className="flex-1 h-16 bg-indigo-600 text-white rounded-2xl font-black hover:bg-indigo-700 transition shadow-xl shadow-indigo-200 active:scale-95 text-sm uppercase tracking-widest">Validar</button>
              )}
            </div>
          </div>
        </div>
      )}

      {/* AJUSTES MODAL */}
      {showSettings && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-md z-[100] flex items-center justify-center p-6 animate-in fade-in duration-200">
          <div className="bg-white w-full max-w-sm rounded-[3rem] p-10 shadow-[0_25px_60px_-15px_rgba(0,0,0,0.3)] animate-in zoom-in-95 duration-200 overflow-y-auto max-h-[90vh]">
            <div className="flex justify-between items-center mb-8">
              <h3 className="text-2xl font-black text-slate-900">Configuración</h3>
              <button onClick={() => setShowSettings(false)} className="text-slate-300 hover:text-slate-600 p-2 rounded-full hover:bg-slate-50 transition">
                <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>

            <div className="space-y-8">
              <div>
                <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-4">Modo de Evaluación</label>
                <div className="flex bg-slate-100 p-1.5 rounded-2xl">
                  {(['training', 'real'] as GameMode[]).map(m => (
                    <button key={m} onClick={() => onUpdateList({ ...list, settings: { ...list.settings, mode: m } })} className={`flex-1 py-3 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${list.settings.mode === m ? 'bg-white text-indigo-600 shadow-sm scale-100' : 'text-slate-400'}`}>{m === 'training' ? 'Práctica' : 'Escritura'}</button>
                  ))}
                </div>
              </div>

              <div>
                <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-4">Invertir Par</label>
                <div className="flex bg-slate-100 p-1.5 rounded-2xl">
                  {(['normal', 'reversed'] as FlipOrder[]).map(o => (
                    <button key={o} onClick={() => onUpdateList({ ...list, settings: { ...list.settings, flipOrder: o } })} className={`flex-1 py-3 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${list.settings.flipOrder === o ? 'bg-white text-indigo-600 shadow-sm scale-100' : 'text-slate-400'}`}>{o === 'normal' ? 'Original' : 'Inverso'}</button>
                  ))}
                </div>
              </div>

              <div className="pt-8 border-t border-slate-100">
                <label className="block text-xs font-black text-rose-400 uppercase tracking-widest mb-4 text-center">Acciones Críticas</label>
                <button 
                  onClick={() => setShowConfirmReset(true)}
                  className="w-full flex items-center justify-center gap-3 bg-rose-500 text-white py-4 rounded-2xl font-black hover:bg-rose-600 transition shadow-lg shadow-rose-100 active:scale-95 uppercase text-xs tracking-widest"
                >
                  <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                  Reiniciar todo
                </button>
              </div>
            </div>

            <button onClick={() => setShowSettings(false)} className="w-full mt-10 bg-slate-900 text-white py-5 rounded-[2rem] font-black hover:bg-slate-800 transition active:scale-95 uppercase text-xs tracking-widest">Aplicar Cambios</button>
          </div>
        </div>
      )}
    </div>
  );
};

