          <div className="text-[8px] uppercase font-black text-emerald-400 tracking-widest mt-1">Aprendidas</div>
        </div>
        <div className="bg-indigo-50 p-4 rounded-3xl border border-indigo-100">
          <div className="text-2xl font-black text-indigo-600">{stats.known + stats.recognized + stats.discovered}</div>
          <div className="text-[8px] uppercase font-black text-indigo-400 tracking-widest mt-1">En Repaso</div>
        </div>
        <div className="bg-rose-50 p-4 rounded-3xl border border-rose-100">
          <div className="text-2xl font-black text-rose-500">{stats.unknown}</div>
          <div className="text-[8px] uppercase font-black text-rose-400 tracking-widest mt-1">No Vistas</div>
        </div>
        <div className="bg-slate-50 p-4 rounded-3xl border border-slate-100">
          <div className="text-2xl font-black text-slate-400">{stats.archived}</div>
          <div className="text-[8px] uppercase font-black text-slate-400 tracking-widest mt-1">Histórico</div>
        </div>
      </div>

      <div className="flex flex-col gap-3">
        <button onClick={onContinue} className="w-full bg-indigo-600 text-white py-5 rounded-[2rem] font-black hover:bg-indigo-700 transition shadow-xl shadow-indigo-100 active:scale-95 text-xs uppercase tracking-widest">Continuar Aprendiendo</button>
        <div className="grid grid-cols-2 gap-3">
          <button onClick={onArchive} className="bg-slate-100 text-slate-600 py-4 rounded-[2rem] font-black hover:bg-slate-200 transition text-[9px] uppercase tracking-widest active:scale-95">Archivar Logros</button>
          <button onClick={onResetAll} className="bg-rose-50 text-rose-600 py-4 rounded-[2rem] font-black hover:bg-rose-100 transition text-[9px] uppercase tracking-widest active:scale-95">Borrar Todo</button>
        </div>
        <button onClick={onBack} className="w-full bg-white text-slate-300 py-4 rounded-2xl font-bold hover:bg-slate-50 transition active:scale-95 text-[10px] uppercase tracking-widest">Salir al Inicio</button>
      </div>
    </div>
  </div>
);

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { AssociationList, Association, AssociationStatus, GameCycle, GameState, FlipOrder, GameMode } from '../types';
import { calculateSimilarity } from '../utils/similarity';

interface GameViewProps {
  list: AssociationList;
  onUpdateList: (list: AssociationList) => void;
  onBack: () => void;
}

interface Toast {
  message: string;
  type: 'success' | 'error' | 'info';
  id: number;
}

export const GameView: React.FC<GameViewProps> = ({ list, onUpdateList, onBack }) => {
  const [associations, setAssociations] = useState<Association[]>(list.associations);
  const [gameState, setGameState] = useState<GameState>({
    listId: list.id,
    currentCycle: 1,
    currentIndex: 0,
    queue: [],
    history: [],
    isFinished: false,
    revealed: false,
    userInput: '',
    lastMatchScore: null,
    wasRevealed: false
  });

  const [showSettings, setShowSettings] = useState(false);
  const [showConfirmReset, setShowConfirmReset] = useState(false);
  const [toast, setToast] = useState<Toast | null>(null);

  const showNotification = useCallback((message: string, type: 'success' | 'error' | 'info' = 'success') => {
    setToast({ message, type, id: Date.now() });
  }, []);

  useEffect(() => {
    if (toast) {
      const timer = setTimeout(() => setToast(null), 3000);
      return () => clearTimeout(timer);
    }
  }, [toast]);

  const startCycle = useCallback((cycle: GameCycle, currentAssocs: Association[]) => {
    let targetStatus: AssociationStatus;
    switch (cycle) {
      case 1: targetStatus = AssociationStatus.DESCONOCIDA; break;
      case 2: targetStatus = AssociationStatus.DESCONOCIDA; break;
      case 3: targetStatus = AssociationStatus.DESCUBIERTA; break;
      case 4: targetStatus = AssociationStatus.RECONOCIDA; break;
      case 5: targetStatus = AssociationStatus.CONOCIDA; break;
      default: targetStatus = AssociationStatus.DESCONOCIDA;
    }

    const availableIds = currentAssocs
      .filter(a => a.status === targetStatus && !a.history)
      .map(a => a.id);

    const shuffled = [...availableIds].sort(() => Math.random() - 0.5);

    // Si este ciclo no tiene palabras, intentamos el siguiente automáticamente
    if (shuffled.length === 0 && cycle < 5) {
      startCycle((cycle + 1) as GameCycle, currentAssocs);
      return;
    }

    setGameState({
      listId: list.id,
      currentCycle: cycle,
      currentIndex: 0,
      queue: shuffled,
      history: [],
      isFinished: shuffled.length === 0,
      revealed: false,
      userInput: '',
      wasRevealed: false,
      lastMatchScore: null
    });
  }, [list.id]);

  useEffect(() => { 
    startCycle(1, associations); 
  }, []);

  const executeFullReset = () => {
    const resetData = associations.map(a => ({ 
      ...a, 
      status: AssociationStatus.DESCONOCIDA, 
      history: false 
    }));

    setAssociations(resetData);
    setShowConfirmReset(false);
    setShowSettings(false);
    onUpdateList({ ...list, associations: resetData });
    startCycle(1, resetData);
    showNotification("Progreso reiniciado", "info");
  };

  const handleArchiveLearned = () => {
    const learned = associations.filter(a => a.status === AssociationStatus.APRENDIDA && !a.history);
    if (learned.length === 0) {
      showNotification("No hay palabras aprendidas", "error");
      return;
    }
    const archived = associations.map(a => a.status === AssociationStatus.APRENDIDA ? { ...a, history: true } : a);
    setAssociations(archived);
    onUpdateList({ ...list, associations: archived });
    showNotification(`${learned.length} archivadas`, "success");

    const nextRoundAssocs = archived.map(a => !a.history ? { ...a, status: AssociationStatus.DESCONOCIDA } : a);
    setAssociations(nextRoundAssocs);
    startCycle(1, nextRoundAssocs);
  };

  const handleContinue = () => {
    const reset = associations.map(a => !a.history ? { ...a, status: AssociationStatus.DESCONOCIDA } : a);
    setAssociations(reset);
    onUpdateList({ ...list, associations: reset });
    startCycle(1, reset);
    showNotification("Reiniciando ciclos", "info");
  };

  const currentAssocId = gameState.queue[gameState.currentIndex];
  const currentAssoc = associations.find(a => a.id === currentAssocId);

  const displayTerm = useMemo(() => {
    if (!currentAssoc) return '';
    return list.settings.flipOrder === 'reversed' ? currentAssoc.definition : currentAssoc.term;
  }, [currentAssoc, list.settings.flipOrder]);

  const targetDefinition = useMemo(() => {
    if (!currentAssoc) return '';
    return list.settings.flipOrder === 'reversed' ? currentAssoc.term : currentAssoc.definition;
  }, [currentAssoc, list.settings.flipOrder]);

  const handlePasar = () => {
    if (!currentAssoc) return;
    advance(currentAssoc.status); // El estado no cambia al "pasar"
  };

  const handleCorrect = () => {
    if (!currentAssoc) return;
    let nextStatus = currentAssoc.status;

    if (gameState.currentCycle === 1) {
      nextStatus = AssociationStatus.APRENDIDA;
    } else if (gameState.currentCycle === 2) {
      nextStatus = AssociationStatus.DESCUBIERTA;
    } else if (gameState.currentCycle === 3) {
      nextStatus = AssociationStatus.RECONOCIDA;
    } else if (gameState.currentCycle === 4) {
      nextStatus = AssociationStatus.CONOCIDA;
    } else if (gameState.currentCycle === 5) {
      nextStatus = AssociationStatus.APRENDIDA;
    }

    advance(nextStatus);
  };

  const advance = (nextStatus: AssociationStatus) => {
    const updatedAssociations = associations.map(a => a.id === currentAssocId ? { ...a, status: nextStatus } : a);
    setAssociations(updatedAssociations);

    if (gameState.currentIndex < gameState.queue.length - 1) {
      setGameState(prev => ({
        ...prev,
        currentIndex: prev.currentIndex + 1,
        revealed: false,
        userInput: '',
        wasRevealed: false,
        lastMatchScore: null
      }));
    } else {
      onUpdateList({ ...list, associations: updatedAssociations });
      if (gameState.currentCycle < 5) {
        // Al terminar el queue, intentamos el siguiente ciclo
        startCycle((gameState.currentCycle + 1) as GameCycle, updatedAssociations);
      } else {
        // Solo finaliza si terminamos el ciclo 5
        setGameState(prev => ({ ...prev, isFinished: true }));
      }
    }
  };

  const checkInput = () => {
    const score = calculateSimilarity(gameState.userInput, targetDefinition);
    setGameState(prev => ({ ...prev, lastMatchScore: score }));
    if (score >= list.settings.threshold) {
      handleCorrect();
    } else {
      showNotification("Error en la asociación", "error");
    }
  };

  const stats = useMemo(() => ({
    learned: associations.filter(a => a.status === 'APRENDIDA' && !a.history).length,
    known: associations.filter(a => a.status === 'CONOCIDA' && !a.history).length,
    recognized: associations.filter(a => a.status === 'RECONOCIDA' && !a.history).length,
    discovered: associations.filter(a => a.status === 'DESCUBIERTA' && !a.history).length,
    unknown: associations.filter(a => a.status === 'DESCONOCIDA' && !a.history).length,
    archived: associations.filter(a => a.history).length
  }), [associations]);

  const stages = [
    { label: 'Inicia', status: 'INIT' },
    { label: 'Descubrir', status: AssociationStatus.DESCONOCIDA },
    { label: 'Reconocer', status: AssociationStatus.DESCUBIERTA },
    { label: 'Conocer', status: AssociationStatus.RECONOCIDA },
    { label: 'Aprender', status: AssociationStatus.CONOCIDA },
  ];

  return (
    <div className="min-h-screen relative flex flex-col bg-slate-50">
      {toast && <ToastNotification key={toast.id} toast={toast} onClose={() => setToast(null)} />}

      {showConfirmReset && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-sm z-[200] flex items-center justify-center p-6 animate-in fade-in duration-200">
          <div className="bg-white w-full max-w-sm rounded-[2.5rem] p-10 text-center shadow-2xl animate-in zoom-in-95 duration-200">
            <h3 className="text-xl font-black text-slate-900 mb-6">¿Reiniciar progreso?</h3>
            <div className="flex flex-col gap-2">
              <button onClick={executeFullReset} className="w-full bg-rose-600 text-white py-4 rounded-2xl font-black shadow-lg hover:bg-rose-700 active:scale-95 transition">Sí, reiniciar</button>
              <button onClick={() => setShowConfirmReset(false)} className="w-full bg-slate-100 text-slate-600 py-4 rounded-2xl font-bold hover:bg-slate-200 active:scale-95 transition">Cancelar</button>
            </div>
          </div>
        </div>
      )}

      {gameState.isFinished ? (
        <FinishedPanel 
          stats={stats} 
          onBack={onBack} 
          onResetAll={() => setShowConfirmReset(true)}
          onArchive={handleArchiveLearned}
          onContinue={handleContinue}
        />
      ) : (
        <div className="max-w-4xl mx-auto p-4 md:p-6 pb-32 w-full flex-1 flex flex-col">
          {/* INDICADOR DE PROGRESO */}
          <div className="w-full mb-12 mt-4 px-2">
            <div className="flex items-center justify-between relative">
              <div className="absolute top-1/2 left-0 w-full h-0.5 bg-slate-200 -translate-y-1/2 -z-10"></div>
              {stages.map((stage, idx) => {
                const isCurrent = idx + 1 === gameState.currentCycle;
                const isPast = idx + 1 < gameState.currentCycle;
                return (
                  <div key={idx} className="flex flex-col items-center relative bg-slate-50 px-2">
                    <div className={`w-10 h-10 rounded-full flex items-center justify-center font-black text-xs border-4 transition-all duration-500 ${
                      isCurrent ? 'bg-indigo-600 border-white text-white scale-125 shadow-xl shadow-indigo-100' :
                      isPast ? 'bg-emerald-500 border-white text-white' : 'bg-white border-slate-100 text-slate-300'
                    }`}>
                      {isPast ? '✓' : idx + 1}
                    </div>
                    <span className={`text-[8px] font-black uppercase tracking-widest mt-3 whitespace-nowrap ${isCurrent ? 'text-indigo-600' : 'text-slate-400'}`}>
                      {stage.label}
                    </span>
                  </div>
                );
              })}
              {/* META FINAL (ESPECIAL) */}
              <div className="flex flex-col items-center relative bg-slate-50 px-2">
                <div className={`w-10 h-10 rounded-full flex items-center justify-center font-black text-xs border-4 transition-all duration-500 ${
                  stats.learned === associations.length ? 'bg-amber-400 border-white text-white scale-125' : 'bg-white border-slate-100 text-amber-200'
                }`}>
                  ★
                </div>
                <span className={`text-[8px] font-black uppercase tracking-widest mt-3 ${stats.learned === associations.length ? 'text-amber-500' : 'text-slate-300'}`}>
                  Aprendida
                </span>
              </div>
            </div>
          </div>

          <button 
            onClick={() => setShowSettings(true)}
            className="fixed top-24 right-6 z-40 p-3 bg-white rounded-full shadow-lg border border-slate-100 text-slate-400 hover:text-indigo-600 transition active:scale-90"
          >
            <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" /></svg>
          </button>

          <div className="flex-1 flex flex-col items-center justify-center -mt-12">
            <div className="w-full max-w-lg bg-white rounded-[3rem] shadow-2xl border border-white/50 p-12 text-center relative overflow-hidden">
              <div className="absolute top-0 left-0 w-full h-2 bg-indigo-600 opacity-20" />
              <div className="mb-10">
                <span className="text-[10px] font-black text-indigo-400 uppercase tracking-[0.3em] block mb-4">Palabra actual ({gameState.currentIndex + 1}/{gameState.queue.length})</span>
                <h2 className="text-4xl md:text-5xl font-black text-slate-900 mb-10 break-words leading-tight">{displayTerm}</h2>
              </div>

              <div className="min-h-[140px] flex flex-col justify-center">
                {list.settings.mode === 'real' ? (
                  <div className="w-full space-y-4">
                    <input 
                      type="text" autoFocus
                      value={gameState.userInput}
                      onChange={(e) => setGameState(prev => ({ ...prev, userInput: e.target.value }))}
                      onKeyDown={(e) => e.key === 'Enter' && checkInput()}
                      placeholder="Escribe la respuesta..."
                      className="w-full text-center text-xl font-bold py-5 bg-slate-50 border-2 border-slate-100 rounded-[2rem] focus:border-indigo-600 focus:bg-white outline-none transition-all shadow-inner"
                    />
                  </div>
                ) : (
                  <div className="text-3xl font-black text-indigo-600 px-4">
                    {gameState.revealed ? (
                      <div className="animate-in slide-in-from-bottom-3 fade-in duration-300 break-words">{targetDefinition}</div>
                    ) : (
                      <div className="text-slate-100 tracking-[0.4em] select-none scale-y-75 py-2">••••••••</div>
                    )}
                  </div>
                )}
              </div>
            </div>
          </div>

          <div className="fixed bottom-0 left-0 right-0 p-8 bg-gradient-to-t from-slate-50 via-slate-50/90 to-transparent flex justify-center z-30">
            <div className="max-w-md w-full flex gap-3">
              <button onClick={handlePasar} className="flex-1 h-16 bg-white border-2 border-slate-100 text-slate-400 rounded-2xl font-black hover:bg-slate-50 transition shadow-lg active:scale-95 text-[10px] uppercase tracking-widest">Pasar</button>
              <button 
                onClick={() => setGameState(prev => ({ ...prev, revealed: !prev.revealed, wasRevealed: true }))}
                className={`flex-1 h-16 rounded-2xl font-black transition shadow-lg active:scale-95 text-[10px] uppercase tracking-widest ${gameState.revealed ? 'bg-indigo-100 text-indigo-700' : 'bg-indigo-50 text-indigo-600'}`}
              >
                {gameState.revealed ? 'Ocultar' : 'Revelar'}
              </button>
              <button onClick={handleCorrect} className="flex-[1.5] h-16 bg-indigo-600 text-white rounded-2xl font-black hover:bg-indigo-700 transition shadow-xl shadow-indigo-100 active:scale-95 text-[10px] uppercase tracking-widest">
                Correcta
              </button>
            </div>
          </div>
        </div>
      )}

      {/* MODAL CONFIGURACIÓN */}
      {showSettings && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-[100] flex items-center justify-center p-6 animate-in fade-in duration-200">
          <div className="bg-white w-full max-w-sm rounded-[3rem] p-10 shadow-2xl animate-in zoom-in-95 duration-200">
            <div className="flex justify-between items-center mb-8">
              <h3 className="text-2xl font-black text-slate-900">Ajustes</h3>
              <button onClick={() => setShowSettings(false)} className="text-slate-300 hover:text-slate-600 p-2">
                <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>

            <div className="space-y-6">
              <div>
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">Modo de Evaluación</label>
                <div className="flex bg-slate-100 p-1.5 rounded-2xl">
                  {(['training', 'real'] as GameMode[]).map(m => (
                    <button key={m} onClick={() => onUpdateList({ ...list, settings: { ...list.settings, mode: m } })} className={`flex-1 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${list.settings.mode === m ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-400'}`}>{m === 'training' ? 'Práctica' : 'Escritura'}</button>
                  ))}
                </div>
              </div>
              <button 
                onClick={() => setShowConfirmReset(true)}
                className="w-full bg-rose-500 text-white py-4 rounded-2xl font-black shadow-lg active:scale-95 uppercase text-[10px] tracking-widest mt-4"
              >
                Reiniciar Proceso
              </button>
            </div>
            <button onClick={() => setShowSettings(false)} className="w-full mt-8 bg-slate-900 text-white py-5 rounded-[2rem] font-black hover:bg-slate-800 transition text-[10px] uppercase tracking-widest">Cerrar</button>
          </div>
        </div>
      )}
    </div>
  );
};

const ToastNotification: React.FC<{ toast: Toast, onClose: () => void }> = ({ toast, onClose }) => (
  <div 
    onClick={onClose}
    className={`fixed top-12 left-1/2 -translate-x-1/2 z-[300] px-8 py-4 rounded-[2rem] shadow-2xl font-black text-[11px] uppercase tracking-widest cursor-pointer animate-in slide-in-from-top-12 fade-in duration-500 flex items-center gap-4 border-2 ${
      toast.type === 'success' ? 'bg-emerald-600 text-white border-emerald-400' : 
      toast.type === 'error' ? 'bg-rose-600 text-white border-rose-400' : 
      'bg-indigo-700 text-white border-indigo-500'
    }`}
  >
    {toast.message}
  </div>
);

const FinishedPanel: React.FC<{ stats: any, onBack: () => void, onResetAll: () => void, onArchive: () => void, onContinue: () => void }> = ({ stats, onBack, onResetAll, onArchive, onContinue }) => (
  <div className="max-w-xl mx-auto p-6 text-center animate-in zoom-in duration-500 flex-1 flex flex-col justify-center min-h-screen">
    <div className="bg-white rounded-[4rem] shadow-2xl p-12 border border-slate-100">
      <h2 className="text-3xl font-black text-slate-900 mb-2 tracking-tight">Entrenamiento Finalizado</h2>
      <p className="text-slate-400 mb-10 text-sm font-medium">Mira el estado final de tus asociaciones:</p>

      <div className="grid grid-cols-2 gap-4 mb-12">
        <div className="bg-amber-50 p-6 rounded-3xl border border-amber-100 flex flex-col items-center">
          <div className="text-4xl font-black text-amber-500 mb-1">{stats.learned}</div>
          <div className="text-[10px] uppercase font-black text-amber-400 tracking-widest">★ Aprendidas</div>
        </div>
        <div className="bg-indigo-50 p-6 rounded-3xl border border-indigo-100 flex flex-col items-center">
          <div className="text-4xl font-black text-indigo-600 mb-1">{stats.known + stats.recognized + stats.discovered}</div>
          <div className="text-[10px] uppercase font-black text-indigo-400 tracking-widest">En Proceso</div>
        </div>
      </div>

      <div className="flex flex-col gap-3">
        <button onClick={onContinue} className="w-full bg-indigo-600 text-white py-5 rounded-[2rem] font-black shadow-xl shadow-indigo-100 active:scale-95 text-xs uppercase tracking-[0.2em]">Volver a Empezar</button>
        <div className="grid grid-cols-2 gap-3">
          <button onClick={onArchive} className="bg-slate-100 text-slate-600 py-4 rounded-[2rem] font-black text-[9px] uppercase tracking-widest active:scale-95 transition hover:bg-slate-200">Archivar Logros</button>
          <button onClick={onResetAll} className="bg-rose-50 text-rose-600 py-4 rounded-[2rem] font-black text-[9px] uppercase tracking-widest active:scale-95 transition hover:bg-rose-100">Borrar Todo</button>
        </div>
        <button onClick={onBack} className="w-full bg-white text-slate-300 py-4 rounded-2xl font-bold active:scale-95 text-[10px] uppercase tracking-widest mt-4">Dashboard</button>
      </div>
    </div>
  </div>
);

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { AssociationList, Association, AssociationStatus, GameCycle, GameState, FlipOrder, GameMode } from '../types';
import { calculateSimilarity } from '../utils/similarity';

interface GameViewProps {
  list: AssociationList;
  onUpdateList: (list: AssociationList) => void;
  onBack: () => void;
}

interface Toast {
  message: string;
  type: 'success' | 'error' | 'info';
  id: number;
}

export const GameView: React.FC<GameViewProps> = ({ list, onUpdateList, onBack }) => {
  const [associations, setAssociations] = useState<Association[]>(list.associations);
  const [gameState, setGameState] = useState<GameState>({
    listId: list.id,
    currentCycle: 1,
    currentIndex: 0,
    queue: [],
    history: [],
    isFinished: false,
    revealed: false,
    userInput: '',
    lastMatchScore: null,
    wasRevealed: false
  });

  const [showSettings, setShowSettings] = useState(false);
  const [showConfirmReset, setShowConfirmReset] = useState(false);
  const [toast, setToast] = useState<Toast | null>(null);

  const showNotification = useCallback((message: string, type: 'success' | 'error' | 'info' = 'success') => {
    setToast({ message, type, id: Date.now() });
  }, []);

  useEffect(() => {
    if (toast) {
      const timer = setTimeout(() => setToast(null), 3000);
      return () => clearTimeout(timer);
    }
  }, [toast]);

  const startCycle = useCallback((cycle: GameCycle, currentAssocs: Association[]) => {
    let targetStatus: AssociationStatus;
    switch (cycle) {
      case 1: targetStatus = AssociationStatus.DESCONOCIDA; break;
      case 2: targetStatus = AssociationStatus.DESCONOCIDA; break;
      case 3: targetStatus = AssociationStatus.DESCUBIERTA; break;
      case 4: targetStatus = AssociationStatus.RECONOCIDA; break;
      case 5: targetStatus = AssociationStatus.CONOCIDA; break;
      default: targetStatus = AssociationStatus.DESCONOCIDA;
    }

    const availableIds = currentAssocs
      .filter(a => a.status === targetStatus && !a.history)
      .map(a => a.id);

    const shuffled = [...availableIds].sort(() => Math.random() - 0.5);

    // Si este ciclo no tiene palabras pero no es el último, intentamos saltar al siguiente
    if (shuffled.length === 0 && cycle < 5) {
      startCycle((cycle + 1) as GameCycle, currentAssocs);
      return;
    }

    // Si llegamos al final de los ciclos y no hay nada, el juego termina
    const allLearned = currentAssocs.every(a => a.status === AssociationStatus.APRENDIDA || a.history);

    setGameState({
      listId: list.id,
      currentCycle: cycle,
      currentIndex: 0,
      queue: shuffled,
      history: [],
      isFinished: allLearned || (shuffled.length === 0 && cycle === 5),
      revealed: false,
      userInput: '',
      wasRevealed: false,
      lastMatchScore: null
    });
  }, [list.id]);

  useEffect(() => { 
    startCycle(1, associations); 
  }, []);

  const executeFullReset = () => {
    const resetData = associations.map(a => ({ 
      ...a, 
      status: AssociationStatus.DESCONOCIDA, 
      history: false 
    }));

    setAssociations(resetData);
    setShowConfirmReset(false);
    setShowSettings(false);
    onUpdateList({ ...list, associations: resetData });
    startCycle(1, resetData);
    showNotification("Progreso reiniciado", "info");
  };

  const handleArchiveLearned = () => {
    const learned = associations.filter(a => a.status === AssociationStatus.APRENDIDA && !a.history);
    if (learned.length === 0) {
      showNotification("No hay nada que archivar", "error");
      return;
    }
    const archived = associations.map(a => a.status === AssociationStatus.APRENDIDA ? { ...a, history: true } : a);
    setAssociations(archived);
    onUpdateList({ ...list, associations: archived });
    showNotification("Palabras archivadas", "success");

    const nextRoundAssocs = archived.map(a => !a.history ? { ...a, status: AssociationStatus.DESCONOCIDA } : a);
    setAssociations(nextRoundAssocs);
    startCycle(1, nextRoundAssocs);
  };

  const handleContinue = () => {
    const reset = associations.map(a => !a.history ? { ...a, status: AssociationStatus.DESCONOCIDA } : a);
    setAssociations(reset);
    onUpdateList({ ...list, associations: reset });
    startCycle(1, reset);
    showNotification("Reiniciando aprendizaje", "info");
  };

  const currentAssocId = gameState.queue[gameState.currentIndex];
  const currentAssoc = associations.find(a => a.id === currentAssocId);

  const displayTerm = useMemo(() => {
    if (!currentAssoc) return '';
    return list.settings.flipOrder === 'reversed' ? currentAssoc.definition : currentAssoc.term;
  }, [currentAssoc, list.settings.flipOrder]);

  const targetDefinition = useMemo(() => {
    if (!currentAssoc) return '';
    return list.settings.flipOrder === 'reversed' ? currentAssoc.term : currentAssoc.definition;
  }, [currentAssoc, list.settings.flipOrder]);

  const handlePasar = () => {
    if (!currentAssoc) return;
    advance(currentAssoc.status); 
  };

  const handleCorrect = () => {
    if (!currentAssoc) return;
    let nextStatus = currentAssoc.status;

    // Progresión estricta de estados
    if (gameState.currentCycle === 1) {
      nextStatus = AssociationStatus.APRENDIDA; // Salto directo
    } else if (gameState.currentCycle === 2) {
      nextStatus = AssociationStatus.DESCUBIERTA;
    } else if (gameState.currentCycle === 3) {
      nextStatus = AssociationStatus.RECONOCIDA;
    } else if (gameState.currentCycle === 4) {
      nextStatus = AssociationStatus.CONOCIDA;
    } else if (gameState.currentCycle === 5) {
      nextStatus = AssociationStatus.APRENDIDA;
    }

    advance(nextStatus);
  };

  const advance = (nextStatus: AssociationStatus) => {
    const updatedAssociations = associations.map(a => a.id === currentAssocId ? { ...a, status: nextStatus } : a);
    setAssociations(updatedAssociations);

    if (gameState.currentIndex < gameState.queue.length - 1) {
      setGameState(prev => ({
        ...prev,
        currentIndex: prev.currentIndex + 1,
        revealed: false,
        userInput: '',
        wasRevealed: false,
        lastMatchScore: null
      }));
    } else {
      // Al terminar el lote de este ciclo, notificamos a la App y pasamos al siguiente
      onUpdateList({ ...list, associations: updatedAssociations });

      if (gameState.currentCycle < 5) {
        startCycle((gameState.currentCycle + 1) as GameCycle, updatedAssociations);
      } else {
        // Verificamos si realmente terminamos o si quedan palabras pendientes
        const pending = updatedAssociations.some(a => a.status !== AssociationStatus.APRENDIDA && !a.history);
        if (!pending) {
          setGameState(prev => ({ ...prev, isFinished: true }));
        } else {
          // Si quedan pendientes después del ciclo 5, podríamos reiniciar o terminar
          setGameState(prev => ({ ...prev, isFinished: true }));
        }
      }
    }
  };

  const checkInput = () => {
    const score = calculateSimilarity(gameState.userInput, targetDefinition);
    setGameState(prev => ({ ...prev, lastMatchScore: score }));
    if (score >= list.settings.threshold) {
      handleCorrect();
    } else {
      showNotification("Sigue intentando", "error");
    }
  };

  const stats = useMemo(() => ({
    learned: associations.filter(a => a.status === 'APRENDIDA' && !a.history).length,
    known: associations.filter(a => a.status === 'CONOCIDA' && !a.history).length,
    recognized: associations.filter(a => a.status === 'RECONOCIDA' && !a.history).length,
    discovered: associations.filter(a => a.status === 'DESCUBIERTA' && !a.history).length,
    unknown: associations.filter(a => a.status === 'DESCONOCIDA' && !a.history).length,
    archived: associations.filter(a => a.history).length
  }), [associations]);

  const stages = [
    { label: 'Inicia', cycle: 1 },
    { label: 'Desconocida', cycle: 2 },
    { label: 'Descubierta', cycle: 3 },
    { label: 'Reconocida', cycle: 4 },
    { label: 'Conocida', cycle: 5 },
  ];

  return (
    <div className="min-h-screen relative flex flex-col bg-slate-50 overflow-x-hidden">
      {toast && <ToastNotification key={toast.id} toast={toast} onClose={() => setToast(null)} />}

      {showConfirmReset && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-sm z-[200] flex items-center justify-center p-6 animate-in fade-in duration-200">
          <div className="bg-white w-full max-w-sm rounded-[2.5rem] p-10 text-center shadow-2xl">
            <h3 className="text-xl font-black text-slate-900 mb-6 tracking-tight">¿Reiniciar todo el progreso?</h3>
            <div className="flex flex-col gap-2">
              <button onClick={executeFullReset} className="w-full bg-rose-600 text-white py-4 rounded-2xl font-black shadow-lg hover:bg-rose-700 active:scale-95 transition">Limpiar historial</button>
              <button onClick={() => setShowConfirmReset(false)} className="w-full bg-slate-100 text-slate-600 py-4 rounded-2xl font-bold hover:bg-slate-200 transition">Volver</button>
            </div>
          </div>
        </div>
      )}

      {gameState.isFinished ? (
        <FinishedPanel 
          stats={stats} 
          onBack={onBack} 
          onResetAll={() => setShowConfirmReset(true)}
          onArchive={handleArchiveLearned}
          onContinue={handleContinue}
        />
      ) : (
        <div className="max-w-4xl mx-auto p-4 md:p-6 pb-32 w-full flex-1 flex flex-col">
          {/* ESCALERA DE PROGRESO MEJORADA */}
          <div className="w-full mb-12 mt-4 px-2">
            <div className="flex items-center justify-between relative max-w-2xl mx-auto">
              <div className="absolute top-5 left-0 w-full h-0.5 bg-slate-200 -z-10"></div>
              {stages.map((stage, idx) => {
                const isActive = stage.cycle === gameState.currentCycle;
                const isDone = stage.cycle < gameState.currentCycle;
                return (
                  <div key={idx} className="flex flex-col items-center relative bg-slate-50 px-1">
                    <div className={`w-10 h-10 rounded-full flex items-center justify-center font-black text-xs border-4 transition-all duration-700 ${
                      isActive ? 'bg-indigo-600 border-white text-white scale-125 shadow-xl shadow-indigo-100' :
                      isDone ? 'bg-emerald-500 border-white text-white' : 'bg-white border-slate-100 text-slate-300'
                    }`}>
                      {isDone ? '✓' : stage.cycle}
                    </div>
                    <span className={`text-[8px] font-black uppercase tracking-widest mt-4 whitespace-nowrap transition-colors duration-500 ${isActive ? 'text-indigo-600' : 'text-slate-400'}`}>
                      {stage.label}
                    </span>
                  </div>
                );
              })}
              <div className="flex flex-col items-center relative bg-slate-50 px-1">
                <div className={`w-10 h-10 rounded-full flex items-center justify-center font-black text-xs border-4 transition-all duration-700 ${
                  stats.learned === associations.length ? 'bg-amber-400 border-white text-white scale-125 shadow-xl shadow-amber-100' : 'bg-white border-slate-100 text-amber-200'
                }`}>
                  ★
                </div>
                <span className={`text-[8px] font-black uppercase tracking-widest mt-4 whitespace-nowrap ${stats.learned === associations.length ? 'text-amber-500' : 'text-slate-300'}`}>
                  Aprendida
                </span>
              </div>
            </div>
          </div>

          <button 
            onClick={() => setShowSettings(true)}
            className="fixed top-24 right-6 z-40 p-3 bg-white rounded-full shadow-lg border border-slate-100 text-slate-400 hover:text-indigo-600 transition active:scale-90"
          >
            <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" /></svg>
          </button>

          <div className="flex-1 flex flex-col items-center justify-center -mt-12">
            <div className="w-full max-w-lg bg-white rounded-[3.5rem] shadow-2xl border border-white p-12 text-center relative overflow-hidden transition-all">
              <div className="absolute top-0 left-0 w-full h-2 bg-indigo-600 opacity-20" />
              <div className="mb-10">
                <span className="text-[10px] font-black text-indigo-400 uppercase tracking-[0.4em] block mb-4">Procesando {gameState.currentIndex + 1} de {gameState.queue.length}</span>
                <h2 className="text-4xl md:text-5xl font-black text-slate-900 mb-10 break-words leading-tight">{displayTerm}</h2>
                <div className="h-1.5 w-10 bg-slate-50 mx-auto rounded-full" />
              </div>

              <div className="min-h-[140px] flex flex-col justify-center">
                {list.settings.mode === 'real' ? (
                  <div className="w-full space-y-4">
                    <input 
                      type="text" autoFocus
                      value={gameState.userInput}
                      onChange={(e) => setGameState(prev => ({ ...prev, userInput: e.target.value }))}
                      onKeyDown={(e) => e.key === 'Enter' && checkInput()}
                      placeholder="Asociación..."
                      className="w-full text-center text-xl font-bold py-6 bg-slate-50 border-2 border-slate-100 rounded-[2.5rem] focus:border-indigo-600 focus:bg-white outline-none transition-all shadow-inner"
                    />
                  </div>
                ) : (
                  <div className="text-3xl font-black text-indigo-600 px-4">
                    {gameState.revealed ? (
                      <div className="animate-in slide-in-from-bottom-3 fade-in duration-300 break-words">{targetDefinition}</div>
                    ) : (
                      <div className="text-slate-100 tracking-[0.5em] select-none scale-y-50 py-2 opacity-30">XXXXXXXX</div>
                    )}
                  </div>
                )}
              </div>
            </div>

            <div className="mt-8 flex gap-4">
              <div className="bg-white/50 px-4 py-2 rounded-full border border-slate-100 text-[10px] font-black text-slate-400 uppercase tracking-widest">
                Pendientes: {gameState.queue.length - gameState.currentIndex}
              </div>
            </div>
          </div>

          <div className="fixed bottom-0 left-0 right-0 p-8 bg-gradient-to-t from-slate-50 via-slate-50/95 to-transparent flex justify-center z-30">
            <div className="max-w-md w-full flex gap-3">
              <button onClick={handlePasar} className="flex-1 h-16 bg-white border-2 border-slate-100 text-slate-400 rounded-2xl font-black hover:bg-slate-50 transition shadow-lg active:scale-95 text-[10px] uppercase tracking-widest">Pasar</button>
              <button 
                onClick={() => setGameState(prev => ({ ...prev, revealed: !prev.revealed, wasRevealed: true }))}
                className={`flex-1 h-16 rounded-2xl font-black transition shadow-lg active:scale-95 text-[10px] uppercase tracking-widest ${gameState.revealed ? 'bg-indigo-100 text-indigo-700' : 'bg-indigo-50 text-indigo-600'}`}
              >
                {gameState.revealed ? 'Ocultar' : 'Revelar'}
              </button>
              <button onClick={handleCorrect} className="flex-[1.5] h-16 bg-indigo-600 text-white rounded-2xl font-black hover:bg-indigo-700 transition shadow-xl shadow-indigo-100 active:scale-95 text-[10px] uppercase tracking-widest">
                Correcta
              </button>
            </div>
          </div>
        </div>
      )}

      {/* MODAL CONFIGURACIÓN */}
      {showSettings && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-[100] flex items-center justify-center p-6 animate-in fade-in duration-200">
          <div className="bg-white w-full max-w-sm rounded-[3rem] p-10 shadow-2xl animate-in zoom-in-95 duration-200">
            <div className="flex justify-between items-center mb-8">
              <h3 className="text-2xl font-black text-slate-900 tracking-tight">Ajustes</h3>
              <button onClick={() => setShowSettings(false)} className="text-slate-300 hover:text-slate-600 p-2">
                <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>

            <div className="space-y-6">
              <div>
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">Método</label>
                <div className="flex bg-slate-100 p-1.5 rounded-2xl">
                  {(['training', 'real'] as GameMode[]).map(m => (
                    <button key={m} onClick={() => onUpdateList({ ...list, settings: { ...list.settings, mode: m } })} className={`flex-1 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${list.settings.mode === m ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-400'}`}>{m === 'training' ? 'Práctica' : 'Escritura'}</button>
                  ))}
                </div>
              </div>
              <button 
                onClick={() => setShowConfirmReset(true)}
                className="w-full bg-rose-500 text-white py-4 rounded-2xl font-black shadow-lg active:scale-95 uppercase text-[10px] tracking-widest mt-4"
              >
                Reiniciar Proceso
              </button>
            </div>
            <button onClick={() => setShowSettings(false)} className="w-full mt-8 bg-slate-900 text-white py-5 rounded-[2rem] font-black hover:bg-slate-800 transition text-[10px] uppercase tracking-widest">Listo</button>
          </div>
        </div>
      )}
    </div>
  );
};

const ToastNotification: React.FC<{ toast: Toast, onClose: () => void }> = ({ toast, onClose }) => (
  <div 
    onClick={onClose}
    className={`fixed top-12 left-1/2 -translate-x-1/2 z-[300] px-8 py-4 rounded-[2rem] shadow-2xl font-black text-[11px] uppercase tracking-widest cursor-pointer animate-in slide-in-from-top-12 fade-in duration-500 flex items-center gap-4 border-2 ${
      toast.type === 'success' ? 'bg-emerald-600 text-white border-emerald-400' : 
      toast.type === 'error' ? 'bg-rose-600 text-white border-rose-400' : 
      'bg-indigo-700 text-white border-indigo-500'
    }`}
  >
    {toast.message}
  </div>
);

const FinishedPanel: React.FC<{ stats: any, onBack: () => void, onResetAll: () => void, onArchive: () => void, onContinue: () => void }> = ({ stats, onBack, onResetAll, onArchive, onContinue }) => (
  <div className="max-w-xl mx-auto p-6 text-center animate-in zoom-in duration-500 flex-1 flex flex-col justify-center min-h-screen">
    <div className="bg-white rounded-[4rem] shadow-2xl p-12 border border-slate-100">
      <div className="w-20 h-20 bg-indigo-50 text-indigo-600 rounded-full flex items-center justify-center mx-auto mb-8">
        <svg className="w-10 h-10" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg>
      </div>
      <h2 className="text-3xl font-black text-slate-900 mb-2 tracking-tight">Sesión Terminada</h2>
      <p className="text-slate-400 mb-10 text-sm font-medium">Has completado los ciclos de aprendizaje para estas asociaciones.</p>

      <div className="grid grid-cols-2 gap-4 mb-12">
        <div className="bg-amber-50 p-6 rounded-[2.5rem] border border-amber-100 flex flex-col items-center">
          <div className="text-4xl font-black text-amber-500 mb-1">{stats.learned}</div>
          <div className="text-[10px] uppercase font-black text-amber-400 tracking-widest">★ Aprendidas</div>
        </div>
        <div className="bg-indigo-50 p-6 rounded-[2.5rem] border border-indigo-100 flex flex-col items-center">
          <div className="text-4xl font-black text-indigo-600 mb-1">{stats.known + stats.recognized + stats.discovered + stats.unknown}</div>
          <div className="text-[10px] uppercase font-black text-indigo-400 tracking-widest">Restantes</div>
        </div>
      </div>

      <div className="flex flex-col gap-3">
        <button onClick={onContinue} className="w-full bg-indigo-600 text-white py-5 rounded-[2rem] font-black shadow-xl shadow-indigo-100 active:scale-95 text-xs uppercase tracking-[0.2em]">Nueva Ronda</button>
        <div className="grid grid-cols-2 gap-3">
          <button onClick={onArchive} className="bg-slate-100 text-slate-600 py-4 rounded-[2rem] font-black text-[9px] uppercase tracking-widest active:scale-95 transition hover:bg-slate-200">Archivar Logros</button>
          <button onClick={onResetAll} className="bg-rose-50 text-rose-600 py-4 rounded-[2rem] font-black text-[9px] uppercase tracking-widest active:scale-95 transition hover:bg-rose-100">Limpiar Todo</button>
        </div>
        <button onClick={onBack} className="w-full bg-white text-slate-300 py-4 rounded-2xl font-bold active:scale-95 text-[10px] uppercase tracking-widest mt-4">Volver al Inicio</button>
      </div>
    </div>
  </div>
);

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { AssociationList, Association, AssociationStatus, GameCycle, GameState, FlipOrder, GameMode } from '../types';
import { calculateSimilarity } from '../utils/similarity';

interface GameViewProps {
  list: AssociationList;
  onUpdateList: (list: AssociationList) => void;
  onBack: () => void;
}

interface Toast {
  message: string;
  type: 'success' | 'error' | 'info';
  id: number;
}

const STAGES_ORDER = [
  AssociationStatus.DESCONOCIDA,
  AssociationStatus.DESCUBIERTA,
  AssociationStatus.RECONOCIDA,
  AssociationStatus.CONOCIDA,
  AssociationStatus.APRENDIDA
];

export const GameView: React.FC<GameViewProps> = ({ list, onUpdateList, onBack }) => {
  const [associations, setAssociations] = useState<Association[]>(list.associations);
  const [gameState, setGameState] = useState<GameState>({
    listId: list.id,
    currentCycle: 1,
    currentIndex: 0,
    queue: [],
    history: [],
    isFinished: false,
    revealed: false,
    userInput: '',
    lastMatchScore: null,
    wasRevealed: false
  });

  const [showSettings, setShowSettings] = useState(false);
  const [showConfirmReset, setShowConfirmReset] = useState(false);
  const [toast, setToast] = useState<Toast | null>(null);

  const showNotification = useCallback((message: string, type: 'success' | 'error' | 'info' = 'success') => {
    setToast({ message, type, id: Date.now() });
  }, []);

  useEffect(() => {
    if (toast) {
      const timer = setTimeout(() => setToast(null), 3000);
      return () => clearTimeout(timer);
    }
  }, [toast]);

  // Motor de ciclos corregido
  const startCycle = useCallback((cycle: GameCycle, currentAssocs: Association[]) => {
    let availableIds: string[] = [];

    if (cycle === 1) {
      // Ciclo 1: Solo las que están en Desconocida (Filtro inicial)
      availableIds = currentAssocs
        .filter(a => a.status === AssociationStatus.DESCONOCIDA && !a.history)
        .map(a => a.id);
    } else {
      // Ciclos 2-5: TODAS las que aún no están APRENDIDAS
      // Esto permite que el usuario "Pase" y la palabra siga apareciendo en el siguiente ciclo
      availableIds = currentAssocs
        .filter(a => a.status !== AssociationStatus.APRENDIDA && !a.history)
        .map(a => a.id);
    }

    const shuffled = [...availableIds].sort(() => Math.random() - 0.5);

    // Si ya no quedan palabras por aprender en toda la lista, terminamos
    const totalPending = currentAssocs.filter(a => a.status !== AssociationStatus.APRENDIDA && !a.history).length;

    setGameState({
      listId: list.id,
      currentCycle: cycle,
      currentIndex: 0,
      queue: shuffled,
      history: [],
      // El juego solo termina si no hay palabras en el queue Y estamos en el ciclo 5 
      // O si ya no quedan palabras pendientes de aprender en absoluto.
      isFinished: totalPending === 0 || (shuffled.length === 0 && cycle === 5),
      revealed: false,
      userInput: '',
      wasRevealed: false,
      lastMatchScore: null
    });
  }, [list.id]);

  useEffect(() => { 
    startCycle(1, associations); 
  }, []);

  const executeFullReset = () => {
    const resetData = associations.map(a => ({ 
      ...a, 
      status: AssociationStatus.DESCONOCIDA, 
      history: false 
    }));
    setAssociations(resetData);
    setShowConfirmReset(false);
    setShowSettings(false);
    onUpdateList({ ...list, associations: resetData });
    startCycle(1, resetData);
    showNotification("Progreso reiniciado", "info");
  };

  const handleArchiveLearned = () => {
    const learnedCount = associations.filter(a => a.status === AssociationStatus.APRENDIDA && !a.history).length;
    if (learnedCount === 0) {
      showNotification("No hay logros para archivar", "error");
      return;
    }
    const archived = associations.map(a => a.status === AssociationStatus.APRENDIDA ? { ...a, history: true } : a);
    setAssociations(archived);
    onUpdateList({ ...list, associations: archived });
    showNotification("Aprendidas enviadas al historial", "success");

    const nextRoundAssocs = archived.map(a => !a.history ? { ...a, status: AssociationStatus.DESCONOCIDA } : a);
    setAssociations(nextRoundAssocs);
    startCycle(1, nextRoundAssocs);
  };

  const handleContinue = () => {
    const reset = associations.map(a => !a.history ? { ...a, status: AssociationStatus.DESCONOCIDA } : a);
    setAssociations(reset);
    onUpdateList({ ...list, associations: reset });
    startCycle(1, reset);
    showNotification("Nueva sesión iniciada", "info");
  };

  const currentAssocId = gameState.queue[gameState.currentIndex];
  const currentAssoc = associations.find(a => a.id === currentAssocId);

  const displayTerm = useMemo(() => {
    if (!currentAssoc) return '';
    return list.settings.flipOrder === 'reversed' ? currentAssoc.definition : currentAssoc.term;
  }, [currentAssoc, list.settings.flipOrder]);

  const targetDefinition = useMemo(() => {
    if (!currentAssoc) return '';
    return list.settings.flipOrder === 'reversed' ? currentAssoc.term : currentAssoc.definition;
  }, [currentAssoc, list.settings.flipOrder]);

  const handlePasar = () => {
    if (!currentAssoc) return;
    advance(currentAssoc.status); // Sigue en el mismo estado
  };

  const handleCorrect = () => {
    if (!currentAssoc) return;

    if (gameState.currentCycle === 1) {
      // Ciclo 1: Salto directo a aprendida si es correcta
      advance(AssociationStatus.APRENDIDA);
    } else {
      // Ciclos 2-5: Progresión secuencial
      const currentIndex = STAGES_ORDER.indexOf(currentAssoc.status);
      const nextStatus = STAGES_ORDER[Math.min(currentIndex + 1, STAGES_ORDER.length - 1)];
      advance(nextStatus);
    }
  };

  const advance = (nextStatus: AssociationStatus) => {
    const updatedAssociations = associations.map(a => a.id === currentAssocId ? { ...a, status: nextStatus } : a);
    setAssociations(updatedAssociations);

    if (gameState.currentIndex < gameState.queue.length - 1) {
      setGameState(prev => ({
        ...prev,
        currentIndex: prev.currentIndex + 1,
        revealed: false,
        userInput: '',
        wasRevealed: false,
        lastMatchScore: null
      }));
    } else {
      // Terminó el queue de este ciclo
      onUpdateList({ ...list, associations: updatedAssociations });

      if (gameState.currentCycle < 5) {
        startCycle((gameState.currentCycle + 1) as GameCycle, updatedAssociations);
      } else {
        setGameState(prev => ({ ...prev, isFinished: true }));
      }
    }
  };

  const checkInput = () => {
    const score = calculateSimilarity(gameState.userInput, targetDefinition);
    setGameState(prev => ({ ...prev, lastMatchScore: score }));
    if (score >= list.settings.threshold) {
      handleCorrect();
    } else {
      showNotification("Sigue intentando", "error");
    }
  };

  const stats = useMemo(() => ({
    learned: associations.filter(a => a.status === 'APRENDIDA' && !a.history).length,
    known: associations.filter(a => a.status === 'CONOCIDA' && !a.history).length,
    recognized: associations.filter(a => a.status === 'RECONOCIDA' && !a.history).length,
    discovered: associations.filter(a => a.status === 'DESCUBIERTA' && !a.history).length,
    unknown: associations.filter(a => a.status === 'DESCONOCIDA' && !a.history).length,
    archived: associations.filter(a => a.history).length
  }), [associations]);

  const stagesUI = [
    { label: 'Inicia', cycle: 1 },
    { label: 'Descubrir', cycle: 2 },
    { label: 'Reconocer', cycle: 3 },
    { label: 'Conocer', cycle: 4 },
    { label: 'Aprender', cycle: 5 },
  ];

  return (
    <div className="min-h-screen relative flex flex-col bg-slate-50 overflow-x-hidden">
      {toast && <ToastNotification key={toast.id} toast={toast} onClose={() => setToast(null)} />}

      {showConfirmReset && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-sm z-[200] flex items-center justify-center p-6 animate-in fade-in duration-200">
          <div className="bg-white w-full max-w-sm rounded-[2.5rem] p-10 text-center shadow-2xl">
            <h3 className="text-xl font-black text-slate-900 mb-6">¿Reiniciar progreso?</h3>
            <div className="flex flex-col gap-2">
              <button onClick={executeFullReset} className="w-full bg-rose-600 text-white py-4 rounded-2xl font-black shadow-lg hover:bg-rose-700 active:scale-95 transition">Limpiar todo</button>
              <button onClick={() => setShowConfirmReset(false)} className="w-full bg-slate-100 text-slate-600 py-4 rounded-2xl font-bold hover:bg-slate-200 transition">Cancelar</button>
            </div>
          </div>
        </div>
      )}

      {gameState.isFinished ? (
        <FinishedPanel 
          stats={stats} 
          onBack={onBack} 
          onResetAll={() => setShowConfirmReset(true)}
          onArchive={handleArchiveLearned}
          onContinue={handleContinue}
        />
      ) : (
        <div className="max-w-4xl mx-auto p-4 md:p-6 pb-32 w-full flex-1 flex flex-col">
          {/* INDICADOR DE PROGRESO (ESCALERA) */}
          <div className="w-full mb-12 mt-4 px-2">
            <div className="flex items-center justify-between relative max-w-2xl mx-auto">
              <div className="absolute top-5 left-0 w-full h-0.5 bg-slate-200 -z-10"></div>
              {stagesUI.map((stage, idx) => {
                const isActive = stage.cycle === gameState.currentCycle;
                const isDone = stage.cycle < gameState.currentCycle;
                return (
                  <div key={idx} className="flex flex-col items-center relative bg-slate-50 px-1">
                    <div className={`w-10 h-10 rounded-full flex items-center justify-center font-black text-xs border-4 transition-all duration-700 ${
                      isActive ? 'bg-indigo-600 border-white text-white scale-125 shadow-xl shadow-indigo-100' :
                      isDone ? 'bg-emerald-500 border-white text-white' : 'bg-white border-slate-100 text-slate-300'
                    }`}>
                      {isDone ? '✓' : stage.cycle}
                    </div>
                    <span className={`text-[8px] font-black uppercase tracking-widest mt-4 whitespace-nowrap transition-colors duration-500 ${isActive ? 'text-indigo-600' : 'text-slate-400'}`}>
                      {stage.label}
                    </span>
                  </div>
                );
              })}
              <div className="flex flex-col items-center relative bg-slate-50 px-1">
                <div className={`w-10 h-10 rounded-full flex items-center justify-center font-black text-xs border-4 transition-all duration-700 ${
                  stats.learned === associations.length && associations.length > 0 ? 'bg-amber-400 border-white text-white scale-125 shadow-xl shadow-amber-100' : 'bg-white border-slate-100 text-amber-200'
                }`}>
                  ★
                </div>
                <span className={`text-[8px] font-black uppercase tracking-widest mt-4 whitespace-nowrap ${stats.learned === associations.length ? 'text-amber-500' : 'text-slate-300'}`}>
                  Aprendida
                </span>
              </div>
            </div>
          </div>

          <button 
            onClick={() => setShowSettings(true)}
            className="fixed top-24 right-6 z-40 p-3 bg-white rounded-full shadow-lg border border-slate-100 text-slate-400 hover:text-indigo-600 transition active:scale-90"
          >
            <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" /></svg>
          </button>

          <div className="flex-1 flex flex-col items-center justify-center -mt-12">
            <div className="w-full max-w-lg bg-white rounded-[3.5rem] shadow-2xl border border-white p-12 text-center relative overflow-hidden transition-all">
              <div className="absolute top-0 left-0 w-full h-2 bg-indigo-600 opacity-20" />
              <div className="mb-10">
                <span className="text-[10px] font-black text-indigo-400 uppercase tracking-[0.4em] block mb-4">Procesando {gameState.currentIndex + 1} de {gameState.queue.length}</span>
                <h2 className="text-4xl md:text-5xl font-black text-slate-900 mb-10 break-words leading-tight">{displayTerm || '---'}</h2>
                <div className="h-1.5 w-10 bg-slate-50 mx-auto rounded-full" />
              </div>

              <div className="min-h-[140px] flex flex-col justify-center">
                {list.settings.mode === 'real' ? (
                  <div className="w-full space-y-4">
                    <input 
                      type="text" autoFocus
                      value={gameState.userInput}
                      onChange={(e) => setGameState(prev => ({ ...prev, userInput: e.target.value }))}
                      onKeyDown={(e) => e.key === 'Enter' && checkInput()}
                      placeholder="Asociación..."
                      className="w-full text-center text-xl font-bold py-6 bg-slate-50 border-2 border-slate-100 rounded-[2.5rem] focus:border-indigo-600 focus:bg-white outline-none transition-all shadow-inner"
                    />
                  </div>
                ) : (
                  <div className="text-3xl font-black text-indigo-600 px-4">
                    {gameState.revealed ? (
                      <div className="animate-in slide-in-from-bottom-3 fade-in duration-300 break-words">{targetDefinition}</div>
                    ) : (
                      <div className="text-slate-100 tracking-[0.5em] select-none scale-y-50 py-2 opacity-30">XXXXXXXX</div>
                    )}
                  </div>
                )}
              </div>
            </div>

            <div className="mt-8 flex gap-4">
              <div className="bg-white/50 px-4 py-2 rounded-full border border-slate-100 text-[10px] font-black text-slate-400 uppercase tracking-widest">
                Pendientes: {gameState.queue.length - gameState.currentIndex}
              </div>
            </div>
          </div>

          <div className="fixed bottom-0 left-0 right-0 p-8 bg-gradient-to-t from-slate-50 via-slate-50/95 to-transparent flex justify-center z-30">
            <div className="max-w-md w-full flex gap-3">
              <button onClick={handlePasar} className="flex-1 h-16 bg-white border-2 border-slate-100 text-slate-400 rounded-2xl font-black hover:bg-slate-50 transition shadow-lg active:scale-95 text-[10px] uppercase tracking-widest">Pasar</button>
              <button 
                onClick={() => setGameState(prev => ({ ...prev, revealed: !prev.revealed, wasRevealed: true }))}
                className={`flex-1 h-16 rounded-2xl font-black transition shadow-lg active:scale-95 text-[10px] uppercase tracking-widest ${gameState.revealed ? 'bg-indigo-100 text-indigo-700' : 'bg-indigo-50 text-indigo-600'}`}
              >
                {gameState.revealed ? 'Ocultar' : 'Revelar'}
              </button>
              <button onClick={handleCorrect} className="flex-[1.5] h-16 bg-indigo-600 text-white rounded-2xl font-black hover:bg-indigo-700 transition shadow-xl shadow-indigo-100 active:scale-95 text-[10px] uppercase tracking-widest">
                Correcta
              </button>
            </div>
          </div>
        </div>
      )}

      {/* MODAL CONFIGURACIÓN */}
      {showSettings && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-[100] flex items-center justify-center p-6 animate-in fade-in duration-200">
          <div className="bg-white w-full max-w-sm rounded-[3rem] p-10 shadow-2xl animate-in zoom-in-95 duration-200">
            <h3 className="text-2xl font-black text-slate-900 mb-8 tracking-tight">Ajustes</h3>
            <div className="space-y-6">
              <div>
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">Método</label>
                <div className="flex bg-slate-100 p-1.5 rounded-2xl">
                  {(['training', 'real'] as GameMode[]).map(m => (
                    <button key={m} onClick={() => onUpdateList({ ...list, settings: { ...list.settings, mode: m } })} className={`flex-1 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${list.settings.mode === m ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-400'}`}>{m === 'training' ? 'Práctica' : 'Escritura'}</button>
                  ))}
                </div>
              </div>
              <button 
                onClick={() => setShowConfirmReset(true)}
                className="w-full bg-rose-500 text-white py-4 rounded-2xl font-black shadow-lg active:scale-95 uppercase text-[10px] tracking-widest mt-4"
              >
                Reiniciar Proceso
              </button>
            </div>
            <button onClick={() => setShowSettings(false)} className="w-full mt-8 bg-slate-900 text-white py-5 rounded-[2rem] font-black hover:bg-slate-800 transition text-[10px] uppercase tracking-widest">Listo</button>
          </div>
        </div>
      )}
    </div>
  );
};

const ToastNotification: React.FC<{ toast: Toast, onClose: () => void }> = ({ toast, onClose }) => (
  <div 
    onClick={onClose}
    className={`fixed top-12 left-1/2 -translate-x-1/2 z-[300] px-8 py-4 rounded-[2rem] shadow-2xl font-black text-[11px] uppercase tracking-widest cursor-pointer animate-in slide-in-from-top-12 fade-in duration-500 flex items-center gap-4 border-2 ${
      toast.type === 'success' ? 'bg-emerald-600 text-white border-emerald-400' : 
      toast.type === 'error' ? 'bg-rose-600 text-white border-rose-400' : 
      'bg-indigo-700 text-white border-indigo-500'
    }`}
  >
    {toast.message}
  </div>
);

const FinishedPanel: React.FC<{ stats: any, onBack: () => void, onResetAll: () => void, onArchive: () => void, onContinue: () => void }> = ({ stats, onBack, onResetAll, onArchive, onContinue }) => (
  <div className="max-w-xl mx-auto p-6 text-center animate-in zoom-in duration-500 flex-1 flex flex-col justify-center min-h-screen">
    <div className="bg-white rounded-[4rem] shadow-2xl p-12 border border-slate-100">
      <div className="w-20 h-20 bg-indigo-50 text-indigo-600 rounded-full flex items-center justify-center mx-auto mb-8">
        <svg className="w-10 h-10" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg>
      </div>
      <h2 className="text-3xl font-black text-slate-900 mb-2 tracking-tight">Sesión Terminada</h2>
      <p className="text-slate-400 mb-10 text-sm font-medium">Resultados finales:</p>

      <div className="grid grid-cols-2 gap-4 mb-12">
        <div className="bg-amber-50 p-6 rounded-[2.5rem] border border-amber-100 flex flex-col items-center">
          <div className="text-4xl font-black text-amber-500 mb-1">{stats.learned}</div>
          <div className="text-[10px] uppercase font-black text-amber-400 tracking-widest">★ Aprendidas</div>
        </div>
        <div className="bg-indigo-50 p-6 rounded-[2.5rem] border border-indigo-100 flex flex-col items-center">
          <div className="text-4xl font-black text-indigo-600 mb-1">{stats.unknown + stats.discovered + stats.recognized + stats.known}</div>
          <div className="text-[10px] uppercase font-black text-indigo-400 tracking-widest">En Proceso</div>
        </div>
      </div>

      <div className="flex flex-col gap-3">
        <button onClick={onContinue} className="w-full bg-indigo-600 text-white py-5 rounded-[2rem] font-black shadow-xl shadow-indigo-100 active:scale-95 text-xs uppercase tracking-[0.2em]">Nueva Ronda</button>
        <div className="grid grid-cols-2 gap-3">
          <button onClick={onArchive} className="bg-slate-100 text-slate-600 py-4 rounded-[2rem] font-black text-[9px] uppercase tracking-widest active:scale-95 transition hover:bg-slate-200">Archivar Logros</button>
          <button onClick={onResetAll} className="bg-rose-50 text-rose-600 py-4 rounded-[2rem] font-black text-[9px] uppercase tracking-widest active:scale-95 transition hover:bg-rose-100">Limpiar Todo</button>
        </div>
        <button onClick={onBack} className="w-full bg-white text-slate-300 py-4 rounded-2xl font-bold active:scale-95 text-[10px] uppercase tracking-widest mt-4">Cerrar</button>
      </div>
    </div>
  </div>
);

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { AssociationList, Association, AssociationStatus, GameCycle, GameState, FlipOrder, GameMode } from '../types';
import { calculateSimilarity } from '../utils/similarity';

interface GameViewProps {
  list: AssociationList;
  onUpdateList: (list: AssociationList) => void;
  onBack: () => void;
}

interface Toast {
  message: string;
  type: 'success' | 'error' | 'info';
  id: number;
}

export const GameView: React.FC<GameViewProps> = ({ list, onUpdateList, onBack }) => {
  const [associations, setAssociations] = useState<Association[]>(list.associations);
  const [gameState, setGameState] = useState<GameState>({
    listId: list.id,
    currentCycle: 1,
    currentIndex: 0,
    queue: [],
    history: [],
    isFinished: false,
    revealed: false,
    userInput: '',
    lastMatchScore: null,
    wasRevealed: false
  });

  const [showSettings, setShowSettings] = useState(false);
  const [showConfirmReset, setShowConfirmReset] = useState(false);
  const [toast, setToast] = useState<Toast | null>(null);

  const showNotification = useCallback((message: string, type: 'success' | 'error' | 'info' = 'success') => {
    setToast({ message, type, id: Date.now() });
  }, []);

  useEffect(() => {
    if (toast) {
      const timer = setTimeout(() => setToast(null), 3000);
      return () => clearTimeout(timer);
    }
  }, [toast]);

  /**
   * Lógica de Ciclos según requerimiento:
   * 1. Inicia: Filtra DESCONOCIDA. Correcta -> APRENDIDA.
   * 2. Desconocida: Filtra DESCONOCIDA. Correcta -> DESCUBIERTA.
   * 3. Descubierta: Filtra DESCUBIERTA. Correcta -> RECONOCIDA.
   * 4. Reconocida: Filtra RECONOCIDA. Correcta -> CONOCIDA.
   * 5. Conocida: Filtra CONOCIDA. Correcta -> APRENDIDA.
   */
  const startCycle = useCallback((cycle: GameCycle, currentAssocs: Association[]) => {
    let availableIds: string[] = [];

    switch (cycle) {
      case 1:
        availableIds = currentAssocs.filter(a => a.status === AssociationStatus.DESCONOCIDA && !a.history).map(a => a.id);
        break;
      case 2:
        availableIds = currentAssocs.filter(a => a.status === AssociationStatus.DESCONOCIDA && !a.history).map(a => a.id);
        break;
      case 3:
        availableIds = currentAssocs.filter(a => a.status === AssociationStatus.DESCUBIERTA && !a.history).map(a => a.id);
        break;
      case 4:
        availableIds = currentAssocs.filter(a => a.status === AssociationStatus.RECONOCIDA && !a.history).map(a => a.id);
        break;
      case 5:
        availableIds = currentAssocs.filter(a => a.status === AssociationStatus.CONOCIDA && !a.history).map(a => a.id);
        break;
    }

    const shuffled = [...availableIds].sort(() => Math.random() - 0.5);

    // Si un ciclo intermedio no tiene palabras, intentamos saltar al siguiente automáticamente
    if (shuffled.length === 0 && cycle < 5) {
      startCycle((cycle + 1) as GameCycle, currentAssocs);
      return;
    }

    const allLearned = currentAssocs.every(a => a.status === AssociationStatus.APRENDIDA || a.history);

    setGameState({
      listId: list.id,
      currentCycle: cycle,
      currentIndex: 0,
      queue: shuffled,
      history: [],
      // Terminamos solo si llegamos al final del ciclo 5 o todo está aprendido
      isFinished: allLearned || (shuffled.length === 0 && cycle === 5),
      revealed: false,
      userInput: '',
      wasRevealed: false,
      lastMatchScore: null
    });
  }, [list.id]);

  useEffect(() => { 
    startCycle(1, associations); 
  }, []);

  const executeFullReset = () => {
    const resetData = associations.map(a => ({ 
      ...a, 
      status: AssociationStatus.DESCONOCIDA, 
      history: false 
    }));
    setAssociations(resetData);
    setShowConfirmReset(false);
    setShowSettings(false);
    onUpdateList({ ...list, associations: resetData });
    startCycle(1, resetData);
    showNotification("Progreso reiniciado correctamente", "info");
  };

  const handleArchiveLearned = () => {
    const learnedCount = associations.filter(a => a.status === AssociationStatus.APRENDIDA && !a.history).length;
    if (learnedCount === 0) {
      showNotification("No hay palabras aprendidas para archivar", "error");
      return;
    }
    const archived = associations.map(a => a.status === AssociationStatus.APRENDIDA ? { ...a, history: true } : a);
    setAssociations(archived);
    onUpdateList({ ...list, associations: archived });
    showNotification("Aprendidas movidas al historial", "success");

    // Continuar con las restantes devolviéndolas a desconocidas para nueva sesión si el usuario quiere
    const nextRoundAssocs = archived.map(a => !a.history ? { ...a, status: AssociationStatus.DESCONOCIDA } : a);
    setAssociations(nextRoundAssocs);
    startCycle(1, nextRoundAssocs);
  };

  const handleContinue = () => {
    const reset = associations.map(a => !a.history ? { ...a, status: AssociationStatus.DESCONOCIDA } : a);
    setAssociations(reset);
    onUpdateList({ ...list, associations: reset });
    startCycle(1, reset);
    showNotification("Sesión reiniciada", "info");
  };

  const currentAssocId = gameState.queue[gameState.currentIndex];
  const currentAssoc = associations.find(a => a.id === currentAssocId);

  const displayTerm = useMemo(() => {
    if (!currentAssoc) return '';
    return list.settings.flipOrder === 'reversed' ? currentAssoc.definition : currentAssoc.term;
  }, [currentAssoc, list.settings.flipOrder]);

  const targetDefinition = useMemo(() => {
    if (!currentAssoc) return '';
    return list.settings.flipOrder === 'reversed' ? currentAssoc.term : currentAssoc.definition;
  }, [currentAssoc, list.settings.flipOrder]);

  const handlePasar = () => {
    if (!currentAssoc) return;
    // No cambiamos el estado al pasar, simplemente avanzamos en el queue
    advance(currentAssoc.status); 
  };

  const handleCorrect = () => {
    if (!currentAssoc) return;
    let nextStatus = currentAssoc.status;

    switch (gameState.currentCycle) {
      case 1: 
        nextStatus = AssociationStatus.APRENDIDA; 
        break;
      case 2: 
        nextStatus = AssociationStatus.DESCUBIERTA; 
        break;
      case 3: 
        nextStatus = AssociationStatus.RECONOCIDA; 
        break;
      case 4: 
        nextStatus = AssociationStatus.CONOCIDA; 
        break;
      case 5: 
        nextStatus = AssociationStatus.APRENDIDA; 
        break;
    }

    advance(nextStatus);
  };

  const advance = (nextStatus: AssociationStatus) => {
    const updatedAssociations = associations.map(a => a.id === currentAssocId ? { ...a, status: nextStatus } : a);
    setAssociations(updatedAssociations);

    if (gameState.currentIndex < gameState.queue.length - 1) {
      setGameState(prev => ({
        ...prev,
        currentIndex: prev.currentIndex + 1,
        revealed: false,
        userInput: '',
        wasRevealed: false,
        lastMatchScore: null
      }));
    } else {
      // Fin del queue de este ciclo
      onUpdateList({ ...list, associations: updatedAssociations });
      if (gameState.currentCycle < 5) {
        startCycle((gameState.currentCycle + 1) as GameCycle, updatedAssociations);
      } else {
        setGameState(prev => ({ ...prev, isFinished: true }));
      }
    }
  };

  const checkInput = () => {
    const score = calculateSimilarity(gameState.userInput, targetDefinition);
    setGameState(prev => ({ ...prev, lastMatchScore: score }));
    if (score >= list.settings.threshold) {
      handleCorrect();
    } else {
      showNotification("Asociación incorrecta", "error");
    }
  };

  const stats = useMemo(() => ({
    learned: associations.filter(a => a.status === 'APRENDIDA' && !a.history).length,
    known: associations.filter(a => a.status === 'CONOCIDA' && !a.history).length,
    recognized: associations.filter(a => a.status === 'RECONOCIDA' && !a.history).length,
    discovered: associations.filter(a => a.status === 'DESCUBIERTA' && !a.history).length,
    unknown: associations.filter(a => a.status === 'DESCONOCIDA' && !a.history).length,
    archived: associations.filter(a => a.history).length
  }), [associations]);

  const stagesUI = [
    { label: 'Inicia', cycle: 1, count: stats.unknown },
    { label: 'Descubrir', cycle: 2, count: stats.discovered },
    { label: 'Reconocer', cycle: 3, count: stats.recognized },
    { label: 'Conocer', cycle: 4, count: stats.known },
    { label: 'Aprender', cycle: 5, count: stats.learned },
  ];

  return (
    <div className="min-h-screen relative flex flex-col bg-slate-50 overflow-x-hidden">
      {toast && <ToastNotification key={toast.id} toast={toast} onClose={() => setToast(null)} />}

      {showConfirmReset && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-sm z-[200] flex items-center justify-center p-6 animate-in fade-in duration-200">
          <div className="bg-white w-full max-w-sm rounded-[2.5rem] p-10 text-center shadow-2xl">
            <h3 className="text-xl font-black text-slate-900 mb-6 tracking-tight">¿Confirmar reinicio?</h3>
            <p className="text-slate-500 text-sm mb-8 font-medium">Se perderán todos los estados de esta lista.</p>
            <div className="flex flex-col gap-2">
              <button onClick={executeFullReset} className="w-full bg-rose-600 text-white py-4 rounded-2xl font-black shadow-lg hover:bg-rose-700 active:scale-95 transition">Resetear Progreso</button>
              <button onClick={() => setShowConfirmReset(false)} className="w-full bg-slate-100 text-slate-600 py-4 rounded-2xl font-bold hover:bg-slate-200 transition">Cancelar</button>
            </div>
          </div>
        </div>
      )}

      {gameState.isFinished ? (
        <FinishedPanel 
          stats={stats} 
          onBack={onBack} 
          onResetAll={() => setShowConfirmReset(true)}
          onArchive={handleArchiveLearned}
          onContinue={handleContinue}
        />
      ) : (
        <div className="max-w-4xl mx-auto p-4 md:p-6 pb-32 w-full flex-1 flex flex-col">
          {/* LADDER PROGRESS INDICATOR WITH COUNTS */}
          <div className="w-full mb-14 mt-6 px-2">
            <div className="flex items-center justify-between relative max-w-3xl mx-auto">
              <div className="absolute top-5 left-0 w-full h-0.5 bg-slate-200 -z-10"></div>
              {stagesUI.map((stage, idx) => {
                const isActive = stage.cycle === gameState.currentCycle;
                const isDone = stage.cycle < gameState.currentCycle;

                return (
                  <div key={idx} className="flex flex-col items-center relative bg-slate-50 px-2 group">
                    <div className={`w-11 h-11 rounded-full flex items-center justify-center font-black text-xs border-4 transition-all duration-500 relative ${
                      isActive ? 'bg-indigo-600 border-white text-white scale-125 shadow-xl shadow-indigo-100' :
                      isDone ? 'bg-emerald-500 border-white text-white' : 'bg-white border-slate-100 text-slate-300'
                    }`}>
                      {isDone ? '✓' : stage.cycle}

                      {/* Counter Badge */}
                      <div className={`absolute -top-3 -right-3 min-w-[22px] h-[22px] px-1.5 flex items-center justify-center rounded-full text-[10px] font-black border-2 transition-all duration-500 ${
                        isActive ? 'bg-indigo-500 text-white border-white' : 
                        stage.count > 0 ? 'bg-white text-slate-600 border-slate-100 shadow-sm' : 
                        'bg-slate-50 text-slate-200 border-slate-50'
                      }`}>
                        {stage.count}
                      </div>
                    </div>

                    <span className={`text-[9px] font-black uppercase tracking-widest mt-5 whitespace-nowrap transition-colors duration-500 ${isActive ? 'text-indigo-600' : 'text-slate-400'}`}>
                      {stage.label}
                    </span>
                  </div>
                );
              })}

              <div className="flex flex-col items-center relative bg-slate-50 px-2">
                <div className={`w-11 h-11 rounded-full flex items-center justify-center font-black text-xs border-4 transition-all duration-500 relative ${
                  stats.learned === associations.length && associations.length > 0 ? 'bg-amber-400 border-white text-white scale-125 shadow-xl shadow-amber-100' : 'bg-white border-slate-100 text-amber-200'
                }`}>
                  ★
                  <div className="absolute -top-3 -right-3 min-w-[22px] h-[22px] px-1.5 flex items-center justify-center rounded-full text-[10px] font-black border-2 bg-amber-50 text-amber-500 border-white shadow-sm">
                    {stats.learned}
                  </div>
                </div>
                <span className={`text-[9px] font-black uppercase tracking-widest mt-5 whitespace-nowrap ${stats.learned === associations.length ? 'text-amber-500' : 'text-slate-300'}`}>
                  Aprendidas
                </span>
              </div>
            </div>
          </div>

          <button 
            onClick={() => setShowSettings(true)}
            className="fixed top-28 right-6 z-40 p-3 bg-white rounded-full shadow-lg border border-slate-100 text-slate-400 hover:text-indigo-600 transition active:scale-90"
          >
            <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" /></svg>
          </button>

          <div className="flex-1 flex flex-col items-center justify-center -mt-12">
            <div className="w-full max-w-lg bg-white rounded-[4rem] shadow-2xl border border-white p-12 text-center relative overflow-hidden group">
              <div className={`absolute top-0 left-0 w-full h-2 bg-indigo-600 transition-opacity duration-300 ${gameState.revealed ? 'opacity-100' : 'opacity-10'}`} />

              <div className="mb-10">
                <span className="text-[10px] font-black text-indigo-400 uppercase tracking-[0.4em] block mb-4">Carta {gameState.currentIndex + 1} de {gameState.queue.length}</span>
                <h2 className="text-4xl md:text-5xl font-black text-slate-900 mb-10 break-words leading-tight tracking-tight">{displayTerm || '---'}</h2>
                <div className="h-2 w-16 bg-indigo-50 mx-auto rounded-full" />
              </div>

              <div className="min-h-[140px] flex flex-col justify-center">
                {list.settings.mode === 'real' ? (
                  <div className="w-full">
                    <input 
                      type="text" autoFocus
                      value={gameState.userInput}
                      onChange={(e) => setGameState(prev => ({ ...prev, userInput: e.target.value }))}
                      onKeyDown={(e) => e.key === 'Enter' && checkInput()}
                      placeholder="Escribe la asociación..."
                      className="w-full text-center text-xl font-bold py-6 bg-slate-50 border-2 border-slate-100 rounded-[2.5rem] focus:border-indigo-600 focus:bg-white focus:shadow-xl outline-none transition-all"
                    />
                  </div>
                ) : (
                  <div className="text-3xl font-black text-indigo-600 px-6">
                    {gameState.revealed ? (
                      <div className="animate-in slide-in-from-bottom-4 fade-in duration-500 break-words drop-shadow-sm">{targetDefinition}</div>
                    ) : (
                      <div className="text-slate-100 tracking-[0.6em] select-none scale-y-50 py-4 opacity-40">XXXXXXXX</div>
                    )}
                  </div>
                )}
              </div>
            </div>

            <div className="mt-10 flex gap-4">
              <div className="bg-white/60 backdrop-blur px-6 py-2.5 rounded-full border border-slate-100 text-[10px] font-black text-slate-400 uppercase tracking-widest shadow-sm">
                Pendientes en este ciclo: <span className="text-indigo-600 ml-1 font-black">{gameState.queue.length - gameState.currentIndex}</span>
              </div>
            </div>
          </div>

          <div className="fixed bottom-0 left-0 right-0 p-8 bg-gradient-to-t from-slate-50 via-slate-50/98 to-transparent flex justify-center z-30">
            <div className="max-w-md w-full flex gap-4">
              <button 
                onClick={handlePasar} 
                className="flex-1 h-16 bg-white border-2 border-slate-200 text-slate-400 rounded-[1.5rem] font-black hover:bg-slate-50 hover:text-slate-500 transition-all shadow-lg active:scale-95 text-[10px] uppercase tracking-widest"
              >
                Siguiente
              </button>
              <button 
                onClick={() => setGameState(prev => ({ ...prev, revealed: !prev.revealed, wasRevealed: true }))}
                className={`flex-1 h-16 rounded-[1.5rem] font-black transition-all shadow-lg active:scale-95 text-[10px] uppercase tracking-widest border-2 ${gameState.revealed ? 'bg-indigo-100 text-indigo-700 border-indigo-200' : 'bg-white text-indigo-600 border-indigo-50'}`}
              >
                {gameState.revealed ? 'Ocultar' : 'Revelar'}
              </button>
              <button 
                onClick={handleCorrect} 
                className="flex-[1.6] h-16 bg-indigo-600 text-white rounded-[1.5rem] font-black hover:bg-indigo-700 hover:shadow-indigo-200 transition-all shadow-xl active:scale-95 text-[10px] uppercase tracking-widest flex items-center justify-center gap-2"
              >
                <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg>
                Correcta
              </button>
            </div>
          </div>
        </div>
      )}

      {/* MODAL CONFIGURACIÓN */}
      {showSettings && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-[100] flex items-center justify-center p-6 animate-in fade-in duration-200">
          <div className="bg-white w-full max-w-sm rounded-[3.5rem] p-10 shadow-2xl animate-in zoom-in-95 duration-200">
            <div className="flex justify-between items-center mb-10">
              <h3 className="text-2xl font-black text-slate-900 tracking-tight">Preferencias</h3>
              <button onClick={() => setShowSettings(false)} className="text-slate-300 hover:text-slate-600 transition">
                <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>

            <div className="space-y-8">
              <div>
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-4">Modo de Evaluación</label>
                <div className="flex bg-slate-50 p-1.5 rounded-3xl border border-slate-100">
                  {(['training', 'real'] as GameMode[]).map(m => (
                    <button key={m} onClick={() => onUpdateList({ ...list, settings: { ...list.settings, mode: m } })} className={`flex-1 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all ${list.settings.mode === m ? 'bg-white text-indigo-600 shadow-md' : 'text-slate-400'}`}>{m === 'training' ? 'Práctica' : 'Escritura'}</button>
                  ))}
                </div>
              </div>
              <button 
                onClick={() => setShowConfirmReset(true)}
                className="w-full bg-rose-500 text-white py-4 rounded-2xl font-black shadow-lg active:scale-95 uppercase text-[10px] tracking-widest mt-4"
              >
                Borrar Progreso
              </button>
            </div>
            <button onClick={() => setShowSettings(false)} className="w-full mt-10 bg-slate-900 text-white py-5 rounded-[2.5rem] font-black hover:bg-slate-800 transition text-[11px] uppercase tracking-widest">Aceptar</button>
          </div>
        </div>
      )}
    </div>
  );
};

const ToastNotification: React.FC<{ toast: Toast, onClose: () => void }> = ({ toast, onClose }) => (
  <div 
    onClick={onClose}
    className={`fixed top-12 left-1/2 -translate-x-1/2 z-[300] px-8 py-4 rounded-[2rem] shadow-2xl font-black text-[11px] uppercase tracking-widest cursor-pointer animate-in slide-in-from-top-12 fade-in duration-500 flex items-center gap-4 border-2 ${
      toast.type === 'success' ? 'bg-emerald-600 text-white border-emerald-400' : 
      toast.type === 'error' ? 'bg-rose-600 text-white border-rose-400' : 
      'bg-indigo-700 text-white border-indigo-500'
