        <div className="grid grid-cols-2 gap-3">
          <button onClick={onArchive} className="bg-slate-100 text-slate-600 py-4 rounded-[2.5rem] font-black text-[9px] uppercase tracking-widest active:scale-95 transition-all hover:bg-slate-200">Mover a Historial</button>
          <button onClick={onResetAll} className="bg-rose-50 text-rose-600 py-4 rounded-[2.5rem] font-black text-[9px] uppercase tracking-widest active:scale-95 transition-all hover:bg-rose-100">Borrar Todo</button>
        </div>
        <button onClick={onBack} className="w-full bg-white text-slate-300 py-4 rounded-2xl font-bold active:scale-95 text-[10px] uppercase tracking-widest mt-4">Volver al Dashboard</button>
      </div>
    </div>
  </div>
);

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { AssociationList, Association, AssociationStatus, GameCycle, GameState, FlipOrder, GameMode } from '../types';
import { calculateSimilarity } from '../utils/similarity';

interface GameViewProps {
  list: AssociationList;
  onUpdateList: (list: AssociationList) => void;
  onBack: () => void;
}

interface Toast {
  message: string;
  type: 'success' | 'error' | 'info';
  id: number;
}

export const GameView: React.FC<GameViewProps> = ({ list, onUpdateList, onBack }) => {
  const [associations, setAssociations] = useState<Association[]>(list.associations);
  const [gameState, setGameState] = useState<GameState>({
    listId: list.id,
    currentCycle: 1,
    currentIndex: 0,
    queue: [],
    history: [],
    isFinished: false,
    revealed: false,
    userInput: '',
    lastMatchScore: null,
    wasRevealed: false
  });

  const [showSettings, setShowSettings] = useState(false);
  const [showConfirmReset, setShowConfirmReset] = useState(false);
  const [toast, setToast] = useState<Toast | null>(null);

  const showNotification = useCallback((message: string, type: 'success' | 'error' | 'info' = 'success') => {
    setToast({ message, type, id: Date.now() });
  }, []);

  useEffect(() => {
    if (toast) {
      const timer = setTimeout(() => setToast(null), 3000);
      return () => clearTimeout(timer);
    }
  }, [toast]);

  /**
   * Lógica de Ciclos según Requerimiento:
   * 
   * Ciclo 1 (Desconocidas): Solo muestra las Desconocidas.
   *   - Correcta: Pasa a APRENDIDA.
   *   - Siguiente: Pasa a DESCUBIERTA.
   * 
   * Ciclo 2 (Descubiertas): Solo muestra las Descubiertas.
   *   - Correcta: Se queda en DESCUBIERTA.
   *   - Siguiente: Pasa a RECONOCIDA.
   * 
   * Ciclo 3 (Reconocidas): Solo muestra las Reconocidas.
   *   - Correcta: Se queda en RECONOCIDA.
   *   - Siguiente: Pasa a CONOCIDA.
   * 
   * Ciclo 4 (Conocidas): Solo muestra las Conocidas.
   *   - Correcta: Se queda en CONOCIDA.
   *   - Siguiente: Se queda en CONOCIDA.
   */
  const startCycle = useCallback((cycle: GameCycle, currentAssocs: Association[]) => {
    let targetStatus: AssociationStatus;
    switch (cycle) {
      case 1: targetStatus = AssociationStatus.DESCONOCIDA; break;
      case 2: targetStatus = AssociationStatus.DESCUBIERTA; break;
      case 3: targetStatus = AssociationStatus.RECONOCIDA; break;
      case 4: targetStatus = AssociationStatus.CONOCIDA; break;
      default: targetStatus = AssociationStatus.DESCONOCIDA;
    }

    const availableIds = currentAssocs
      .filter(a => a.status === targetStatus && !a.history)
      .map(a => a.id);

    const shuffled = [...availableIds].sort(() => Math.random() - 0.5);

    // Si este ciclo no tiene palabras, intentamos avanzar al siguiente
    if (shuffled.length === 0 && cycle < 4) {
      startCycle((cycle + 1) as GameCycle, currentAssocs);
      return;
    }

    const allLearned = currentAssocs.every(a => a.status === AssociationStatus.APRENDIDA || a.history);

    setGameState({
      listId: list.id,
      currentCycle: cycle,
      currentIndex: 0,
      queue: shuffled,
      history: [],
      // Terminamos solo si ya no hay nada que mostrar en el ciclo 4 o todo está aprendido
      isFinished: allLearned || (shuffled.length === 0 && cycle === 4),
      revealed: false,
      userInput: '',
      wasRevealed: false,
      lastMatchScore: null
    });
  }, [list.id]);

  useEffect(() => { 
    startCycle(1, associations); 
  }, []);

  const executeFullReset = () => {
    const resetData = associations.map(a => ({ 
      ...a, 
      status: AssociationStatus.DESCONOCIDA, 
      history: false 
    }));
    setAssociations(resetData);
    setShowConfirmReset(false);
    setShowSettings(false);
    onUpdateList({ ...list, associations: resetData });
    startCycle(1, resetData);
    showNotification("Progreso reiniciado", "info");
  };

  const handleArchiveLearned = () => {
    const learnedCount = associations.filter(a => a.status === AssociationStatus.APRENDIDA && !a.history).length;
    if (learnedCount === 0) {
      showNotification("Nada que archivar aún", "error");
      return;
    }
    const archived = associations.map(a => a.status === AssociationStatus.APRENDIDA ? { ...a, history: true } : a);
    setAssociations(archived);
    onUpdateList({ ...list, associations: archived });
    showNotification("Aprendidas archivadas correctamente", "success");

    // Reiniciar para los que quedan
    const nextRoundAssocs = archived.map(a => !a.history ? { ...a, status: AssociationStatus.DESCONOCIDA } : a);
    setAssociations(nextRoundAssocs);
    startCycle(1, nextRoundAssocs);
  };

  const handleContinue = () => {
    const reset = associations.map(a => !a.history ? { ...a, status: AssociationStatus.DESCONOCIDA } : a);
    setAssociations(reset);
    onUpdateList({ ...list, associations: reset });
    startCycle(1, reset);
    showNotification("Nueva ronda de estudio", "info");
  };

  const currentAssocId = gameState.queue[gameState.currentIndex];
  const currentAssoc = associations.find(a => a.id === currentAssocId);

  const displayTerm = useMemo(() => {
    if (!currentAssoc) return '';
    return list.settings.flipOrder === 'reversed' ? currentAssoc.definition : currentAssoc.term;
  }, [currentAssoc, list.settings.flipOrder]);

  const targetDefinition = useMemo(() => {
    if (!currentAssoc) return '';
    return list.settings.flipOrder === 'reversed' ? currentAssoc.term : currentAssoc.definition;
  }, [currentAssoc, list.settings.flipOrder]);

  const handlePasar = () => {
    if (!currentAssoc) return;
    let nextStatus = currentAssoc.status;

    // Lógica Siguiente/Pasar: Avanza el estado según el ciclo
    if (gameState.currentCycle === 1) nextStatus = AssociationStatus.DESCUBIERTA;
    else if (gameState.currentCycle === 2) nextStatus = AssociationStatus.RECONOCIDA;
    else if (gameState.currentCycle === 3) nextStatus = AssociationStatus.CONOCIDA;
    // Ciclo 4 se mantiene igual

    advance(nextStatus);
  };

  const handleCorrect = () => {
    if (!currentAssoc) return;
    let nextStatus = currentAssoc.status;

    // Solo en el primer ciclo el botón "Correcta" salta a Aprendida directamente
    if (gameState.currentCycle === 1) {
      nextStatus = AssociationStatus.APRENDIDA;
    }
    // En ciclos posteriores (2, 3, 4), el botón "Correcta" no cambia el estado (se queda igual)

    advance(nextStatus);
  };

  const advance = (nextStatus: AssociationStatus) => {
    const updatedAssociations = associations.map(a => a.id === currentAssocId ? { ...a, status: nextStatus } : a);
    setAssociations(updatedAssociations);

    if (gameState.currentIndex < gameState.queue.length - 1) {
      setGameState(prev => ({
        ...prev,
        currentIndex: prev.currentIndex + 1,
        revealed: false,
        userInput: '',
        wasRevealed: false,
        lastMatchScore: null
      }));
    } else {
      // Fin del queue del ciclo actual
      onUpdateList({ ...list, associations: updatedAssociations });
      if (gameState.currentCycle < 4) {
        startCycle((gameState.currentCycle + 1) as GameCycle, updatedAssociations);
      } else {
        setGameState(prev => ({ ...prev, isFinished: true }));
      }
    }
  };

  const checkInput = () => {
    const score = calculateSimilarity(gameState.userInput, targetDefinition);
    setGameState(prev => ({ ...prev, lastMatchScore: score }));
    if (score >= list.settings.threshold) {
      handleCorrect();
    } else {
      showNotification("Incorrecto, sigue intentando", "error");
    }
  };

  const stats = useMemo(() => ({
    learned: associations.filter(a => a.status === 'APRENDIDA' && !a.history).length,
    known: associations.filter(a => a.status === 'CONOCIDA' && !a.history).length,
    recognized: associations.filter(a => a.status === 'RECONOCIDA' && !a.history).length,
    discovered: associations.filter(a => a.status === 'DESCUBIERTA' && !a.history).length,
    unknown: associations.filter(a => a.status === 'DESCONOCIDA' && !a.history).length,
  }), [associations]);

  const stagesUI = [
    { label: 'Desconocidas', cycle: 1, count: stats.unknown },
    { label: 'Descubiertas', cycle: 2, count: stats.discovered },
    { label: 'Reconocidas', cycle: 3, count: stats.recognized },
    { label: 'Conocidas', cycle: 4, count: stats.known },
  ];

  return (
    <div className="min-h-screen relative flex flex-col bg-slate-50 overflow-x-hidden">
      {toast && <ToastNotification key={toast.id} toast={toast} onClose={() => setToast(null)} />}

      {showConfirmReset && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-sm z-[200] flex items-center justify-center p-6 animate-in fade-in duration-200">
          <div className="bg-white w-full max-w-sm rounded-[2.5rem] p-10 text-center shadow-2xl">
            <h3 className="text-xl font-black text-slate-900 mb-6 tracking-tight">¿Borrar progreso?</h3>
            <div className="flex flex-col gap-2">
              <button onClick={executeFullReset} className="w-full bg-rose-600 text-white py-4 rounded-2xl font-black shadow-lg active:scale-95 transition">Resetear Todo</button>
              <button onClick={() => setShowConfirmReset(false)} className="w-full bg-slate-100 text-slate-600 py-4 rounded-2xl font-bold hover:bg-slate-200 transition">Cancelar</button>
            </div>
          </div>
        </div>
      )}

      {gameState.isFinished ? (
        <FinishedPanel 
          stats={stats} 
          onBack={onBack} 
          onResetAll={() => setShowConfirmReset(true)}
          onArchive={handleArchiveLearned}
          onContinue={handleContinue}
        />
      ) : (
        <div className="max-w-4xl mx-auto p-4 md:p-6 pb-32 w-full flex-1 flex flex-col">
          {/* LADDER INDICATOR WITH STAGE NAMES AND COUNTS */}
          <div className="w-full mb-12 mt-6 px-2">
            <div className="flex items-center justify-between relative max-w-3xl mx-auto">
              <div className="absolute top-5 left-0 w-full h-0.5 bg-slate-200 -z-10"></div>
              {stagesUI.map((stage, idx) => {
                const isActive = stage.cycle === gameState.currentCycle;
                const isDone = stage.cycle < gameState.currentCycle;
                return (
                  <div key={idx} className="flex flex-col items-center relative bg-slate-50 px-3">
                    <div className={`w-10 h-10 rounded-full flex items-center justify-center font-black text-[10px] border-4 transition-all duration-500 relative ${
                      isActive ? 'bg-indigo-600 border-white text-white scale-125 shadow-xl shadow-indigo-100' :
                      isDone ? 'bg-emerald-500 border-white text-white' : 'bg-white border-slate-100 text-slate-300'
                    }`}>
                      {isDone ? '✓' : stage.cycle}
                      <div className={`absolute -top-3 -right-3 min-w-[20px] h-[20px] px-1 rounded-full flex items-center justify-center text-[9px] font-black border-2 transition-all ${
                        isActive ? 'bg-indigo-500 text-white border-white' : 'bg-white text-slate-400 border-slate-50'
                      }`}>
                        {stage.count}
                      </div>
                    </div>
                    <span className={`text-[8px] font-black uppercase tracking-widest mt-4 whitespace-nowrap transition-colors ${isActive ? 'text-indigo-600' : 'text-slate-400'}`}>
                      {stage.label}
                    </span>
                  </div>
                );
              })}
              <div className="flex flex-col items-center relative bg-slate-50 px-3">
                <div className={`w-10 h-10 rounded-full flex items-center justify-center font-black text-xs border-4 relative ${
                  stats.learned > 0 ? 'bg-amber-400 border-white text-white' : 'bg-white border-slate-100 text-amber-200'
                }`}>
                  ★
                  <div className="absolute -top-3 -right-3 min-w-[20px] h-[20px] px-1 rounded-full bg-amber-500 text-white border-white border-2 flex items-center justify-center text-[9px] font-black">
                    {stats.learned}
                  </div>
                </div>
                <span className={`text-[8px] font-black uppercase tracking-widest mt-4 whitespace-nowrap ${stats.learned > 0 ? 'text-amber-500' : 'text-slate-300'}`}>
                  Aprendidas
                </span>
              </div>
            </div>
          </div>

          <button 
            onClick={() => setShowSettings(true)}
            className="fixed top-28 right-6 z-40 p-3 bg-white rounded-full shadow-lg border border-slate-100 text-slate-400 hover:text-indigo-600 transition active:scale-90"
          >
            <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" /></svg>
          </button>

          <div className="flex-1 flex flex-col items-center justify-center -mt-10">
            <div className="w-full max-w-lg bg-white rounded-[4rem] shadow-2xl border border-white p-12 text-center relative overflow-hidden">
              <div className="absolute top-0 left-0 w-full h-2 bg-indigo-600 opacity-20" />

              <div className="mb-10">
                <span className="text-[10px] font-black text-indigo-400 uppercase tracking-[0.4em] block mb-4">Procesando {gameState.currentIndex + 1} de {gameState.queue.length}</span>
                <h2 className="text-4xl md:text-5xl font-black text-slate-900 mb-10 break-words leading-tight">{displayTerm || '---'}</h2>
                <div className="h-1.5 w-12 bg-slate-100 mx-auto rounded-full" />
              </div>

              <div className="min-h-[140px] flex flex-col justify-center">
                {list.settings.mode === 'real' ? (
                  <div className="w-full">
                    <input 
                      type="text" autoFocus
                      value={gameState.userInput}
                      onChange={(e) => setGameState(prev => ({ ...prev, userInput: e.target.value }))}
                      onKeyDown={(e) => e.key === 'Enter' && checkInput()}
                      placeholder="Escribe la asociación..."
                      className="w-full text-center text-xl font-bold py-6 bg-slate-50 border-2 border-slate-100 rounded-[2.5rem] focus:border-indigo-600 focus:bg-white outline-none transition-all shadow-inner"
                    />
                  </div>
                ) : (
                  <div className="text-3xl font-black text-indigo-600 px-6">
                    {gameState.revealed ? (
                      <div className="animate-in slide-in-from-bottom-4 fade-in duration-500 break-words drop-shadow-sm">{targetDefinition}</div>
                    ) : (
                      <div className="text-slate-100 tracking-[0.6em] select-none scale-y-50 py-4 opacity-40">XXXXXXXX</div>
                    )}
                  </div>
                )}
              </div>
            </div>

            {/* PENDIENTES COUNTER DIRECTLY BELOW THE CARD */}
            <div className="mt-8">
              <div className="bg-indigo-600 text-white px-6 py-2.5 rounded-full text-[10px] font-black uppercase tracking-widest shadow-lg shadow-indigo-100">
                Pendientes: {gameState.queue.length - gameState.currentIndex}
              </div>
            </div>
          </div>

          <div className="fixed bottom-0 left-0 right-0 p-8 bg-gradient-to-t from-slate-50 via-slate-50/98 to-transparent flex justify-center z-30">
            <div className="max-w-md w-full flex gap-3">
              <button onClick={handlePasar} className="flex-1 h-16 bg-white border-2 border-slate-100 text-slate-400 rounded-2xl font-black hover:bg-slate-50 transition shadow-lg active:scale-95 text-[10px] uppercase tracking-widest">Siguiente</button>
              <button 
                onClick={() => setGameState(prev => ({ ...prev, revealed: !prev.revealed, wasRevealed: true }))}
                className={`flex-1 h-16 rounded-2xl font-black transition shadow-lg active:scale-95 text-[10px] uppercase tracking-widest ${gameState.revealed ? 'bg-indigo-100 text-indigo-700' : 'bg-indigo-50 text-indigo-600'}`}
              >
                {gameState.revealed ? 'Ocultar' : 'Revelar'}
              </button>
              <button onClick={handleCorrect} className="flex-[1.6] h-16 bg-indigo-600 text-white rounded-2xl font-black hover:bg-indigo-700 transition shadow-xl shadow-indigo-100 active:scale-95 text-[10px] uppercase tracking-widest flex items-center justify-center gap-2">
                <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg>
                Correcta
              </button>
            </div>
          </div>
        </div>
      )}

      {/* MODAL CONFIGURACIÓN */}
      {showSettings && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-[100] flex items-center justify-center p-6 animate-in fade-in duration-200">
          <div className="bg-white w-full max-w-sm rounded-[3.5rem] p-10 shadow-2xl animate-in zoom-in-95 duration-200">
            <h3 className="text-2xl font-black text-slate-900 mb-8 tracking-tight">Preferencias</h3>
            <div className="space-y-8">
              <div>
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">Método</label>
                <div className="flex bg-slate-50 p-1.5 rounded-2xl">
                  {(['training', 'real'] as GameMode[]).map(m => (
                    <button key={m} onClick={() => onUpdateList({ ...list, settings: { ...list.settings, mode: m } })} className={`flex-1 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${list.settings.mode === m ? 'bg-white text-indigo-600 shadow-md' : 'text-slate-400'}`}>{m === 'training' ? 'Práctica' : 'Escritura'}</button>
                  ))}
                </div>
              </div>
              <button 
                onClick={() => setShowConfirmReset(true)}
                className="w-full bg-rose-500 text-white py-4 rounded-2xl font-black shadow-lg active:scale-95 uppercase text-[10px] tracking-widest mt-4"
              >
                Reiniciar Progreso
              </button>
            </div>
            <button onClick={() => setShowSettings(false)} className="w-full mt-10 bg-slate-900 text-white py-5 rounded-[2.5rem] font-black hover:bg-slate-800 transition text-[11px] uppercase tracking-widest">Cerrar</button>
          </div>
        </div>
      )}
    </div>
  );
};

const ToastNotification: React.FC<{ toast: Toast, onClose: () => void }> = ({ toast, onClose }) => (
  <div 
    onClick={onClose}
    className={`fixed top-12 left-1/2 -translate-x-1/2 z-[300] px-8 py-4 rounded-[2rem] shadow-2xl font-black text-[11px] uppercase tracking-widest cursor-pointer animate-in slide-in-from-top-12 fade-in duration-500 flex items-center gap-4 border-2 ${
      toast.type === 'success' ? 'bg-emerald-600 text-white border-emerald-400' : 
      toast.type === 'error' ? 'bg-rose-600 text-white border-rose-400' : 
      'bg-indigo-700 text-white border-indigo-500'
    }`}
  >
    {toast.message}
  </div>
);

const FinishedPanel: React.FC<{ stats: any, onBack: () => void, onResetAll: () => void, onArchive: () => void, onContinue: () => void }> = ({ stats, onBack, onResetAll, onArchive, onContinue }) => (
  <div className="max-w-xl mx-auto p-6 text-center animate-in zoom-in duration-500 flex-1 flex flex-col justify-center min-h-screen">
    <div className="bg-white rounded-[4rem] shadow-2xl p-12 border border-slate-100">
      <div className="w-20 h-20 bg-indigo-50 text-indigo-600 rounded-full flex items-center justify-center mx-auto mb-8">
        <svg className="w-10 h-10" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg>
      </div>
      <h2 className="text-3xl font-black text-slate-900 mb-2 tracking-tight">¡Sesión Terminada!</h2>
      <p className="text-slate-400 mb-10 text-sm font-medium">Revisa tus resultados:</p>

      <div className="grid grid-cols-2 gap-4 mb-12">
        <div className="bg-amber-50 p-6 rounded-[3rem] border border-amber-100 flex flex-col items-center">
          <div className="text-4xl font-black text-amber-500 mb-1">{stats.learned}</div>
          <div className="text-[10px] uppercase font-black text-amber-400 tracking-widest">★ Aprendidas</div>
        </div>
        <div className="bg-indigo-50 p-6 rounded-[3rem] border border-indigo-100 flex flex-col items-center">
          <div className="text-4xl font-black text-indigo-600 mb-1">{stats.unknown + stats.discovered + stats.recognized + stats.known}</div>
          <div className="text-[10px] uppercase font-black text-indigo-400 tracking-widest">En Proceso</div>
        </div>
      </div>

      <div className="flex flex-col gap-3">
        <button onClick={onContinue} className="w-full bg-indigo-600 text-white py-5 rounded-[2.5rem] font-black shadow-xl shadow-indigo-100 active:scale-95 text-xs uppercase tracking-[0.2em]">Continuar</button>
        <div className="grid grid-cols-2 gap-3">
          <button onClick={onArchive} className="bg-slate-100 text-slate-600 py-4 rounded-[2.5rem] font-black text-[9px] uppercase tracking-widest active:scale-95 transition hover:bg-slate-200">Mover al Histórico</button>
          <button onClick={onResetAll} className="bg-rose-50 text-rose-600 py-4 rounded-[2.5rem] font-black text-[9px] uppercase tracking-widest active:scale-95 transition hover:bg-rose-100">Resetear Todo</button>
        </div>
        <button onClick={onBack} className="w-full bg-white text-slate-300 py-4 rounded-2xl font-bold active:scale-95 text-[10px] uppercase tracking-widest mt-4">Cerrar</button>
      </div>
    </div>
  </div>
);

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { AssociationList, Association, AssociationStatus, GameCycle, GameState, FlipOrder, GameMode } from '../types';
import { calculateSimilarity } from '../utils/similarity';

interface GameViewProps {
  list: AssociationList;
  onUpdateList: (list: AssociationList) => void;
  onBack: () => void;
}

interface Toast {
  message: string;
  type: 'success' | 'error' | 'info';
  id: number;
}

export const GameView: React.FC<GameViewProps> = ({ list, onUpdateList, onBack }) => {
  const [associations, setAssociations] = useState<Association[]>(list.associations);
  const [gameState, setGameState] = useState<GameState>({
    listId: list.id,
    currentCycle: 1,
    currentIndex: 0,
    queue: [],
    history: [],
    isFinished: false,
    revealed: false,
    userInput: '',
    lastMatchScore: null,
    wasRevealed: false
  });

  const [showSettings, setShowSettings] = useState(false);
  const [showConfirmReset, setShowConfirmReset] = useState(false);
  const [toast, setToast] = useState<Toast | null>(null);

  const showNotification = useCallback((message: string, type: 'success' | 'error' | 'info' = 'success') => {
    setToast({ message, type, id: Date.now() });
  }, []);

  useEffect(() => {
    if (toast) {
      const timer = setTimeout(() => setToast(null), 3000);
      return () => clearTimeout(timer);
    }
  }, [toast]);

  /**
   * Lógica de Ciclos:
   * 
   * Ciclo 1 (Desconocidas): Solo muestra las Desconocidas.
   *   - Correcta: Pasa a APRENDIDA (Aprendida a la primera).
   *   - Siguiente: Pasa a DESCUBIERTA.
   * 
   * Ciclo 2 (Descubiertas): Solo muestra las Descubiertas.
   *   - Correcta: Se mantiene en DESCUBIERTA.
   *   - Siguiente: Pasa a RECONOCIDA.
   * 
   * Ciclo 3 (Reconocidas): Solo muestra las Reconocidas.
   *   - Correcta: Se mantiene en RECONOCIDA.
   *   - Siguiente: Pasa a CONOCIDA.
   * 
   * Ciclo 4 (Conocidas): Solo muestra las Conocidas.
   *   - Correcta: Se mantiene en CONOCIDA.
   *   - Siguiente: Se mantiene en CONOCIDA.
   */
  const startCycle = useCallback((cycle: GameCycle, currentAssocs: Association[]) => {
    let targetStatus: AssociationStatus;
    switch (cycle) {
      case 1: targetStatus = AssociationStatus.DESCONOCIDA; break;
      case 2: targetStatus = AssociationStatus.DESCUBIERTA; break;
      case 3: targetStatus = AssociationStatus.RECONOCIDA; break;
      case 4: targetStatus = AssociationStatus.CONOCIDA; break;
      default: targetStatus = AssociationStatus.DESCONOCIDA;
    }

    const availableIds = currentAssocs
      .filter(a => a.status === targetStatus && !a.history)
      .map(a => a.id);

    // Aleatorizar el orden del ciclo
    const shuffled = [...availableIds].sort(() => Math.random() - 0.5);

    // Si este ciclo no tiene palabras, avanzar al siguiente automáticamente
    if (shuffled.length === 0 && cycle < 4) {
      startCycle((cycle + 1) as GameCycle, currentAssocs);
      return;
    }

    const allLearned = currentAssocs.every(a => a.status === AssociationStatus.APRENDIDA || a.history);

    setGameState({
      listId: list.id,
      currentCycle: cycle,
      currentIndex: 0,
      queue: shuffled,
      history: [],
      isFinished: allLearned || (shuffled.length === 0 && cycle === 4),
      revealed: false,
      userInput: '',
      wasRevealed: false,
      lastMatchScore: null
    });
  }, [list.id]);

  useEffect(() => { 
    startCycle(1, associations); 
  }, []);

  const executeFullReset = () => {
    const resetData = associations.map(a => ({ 
      ...a, 
      status: AssociationStatus.DESCONOCIDA, 
      history: false 
    }));
    setAssociations(resetData);
    setShowConfirmReset(false);
    setShowSettings(false);
    onUpdateList({ ...list, associations: resetData });
    startCycle(1, resetData);
    showNotification("Progreso reiniciado a cero", "info");
  };

  const handleArchiveLearned = () => {
    const learnedCount = associations.filter(a => a.status === AssociationStatus.APRENDIDA && !a.history).length;
    if (learnedCount === 0) {
      showNotification("No hay asociaciones aprendidas para archivar", "error");
      return;
    }
    const archived = associations.map(a => a.status === AssociationStatus.APRENDIDA ? { ...a, history: true } : a);
    setAssociations(archived);
    onUpdateList({ ...list, associations: archived });
    showNotification("Aprendidas movidas al histórico", "success");

    // Continuar con las restantes
    const nextRoundAssocs = archived.map(a => !a.history ? { ...a, status: AssociationStatus.DESCONOCIDA } : a);
    setAssociations(nextRoundAssocs);
    startCycle(1, nextRoundAssocs);
  };

  const handleContinue = () => {
    // Todas las asociaciones vuelven a Desconocidas para el siguiente juego
    const reset = associations.map(a => !a.history ? { ...a, status: AssociationStatus.DESCONOCIDA } : a);
    setAssociations(reset);
    onUpdateList({ ...list, associations: reset });
    startCycle(1, reset);
    showNotification("Continuando juego: todas a Desconocidas", "info");
  };

  const currentAssocId = gameState.queue[gameState.currentIndex];
  const currentAssoc = associations.find(a => a.id === currentAssocId);

  const displayTerm = useMemo(() => {
    if (!currentAssoc) return '';
    return list.settings.flipOrder === 'reversed' ? currentAssoc.definition : currentAssoc.term;
  }, [currentAssoc, list.settings.flipOrder]);

  const targetDefinition = useMemo(() => {
    if (!currentAssoc) return '';
    return list.settings.flipOrder === 'reversed' ? currentAssoc.term : currentAssoc.definition;
  }, [currentAssoc, list.settings.flipOrder]);

  const handlePasar = () => {
    if (!currentAssoc) return;
    let nextStatus = currentAssoc.status;

    // Lógica "Siguiente": Avanza de nivel de conocimiento
    if (gameState.currentCycle === 1) nextStatus = AssociationStatus.DESCUBIERTA;
    else if (gameState.currentCycle === 2) nextStatus = AssociationStatus.RECONOCIDA;
    else if (gameState.currentCycle === 3) nextStatus = AssociationStatus.CONOCIDA;
    // En ciclo 4 se queda en Conocida

    advance(nextStatus);
  };

  const handleCorrect = () => {
    if (!currentAssoc) return;
    let nextStatus = currentAssoc.status;

    // Solo en ciclo 1 (Desconocidas) pasa a Aprendida si es correcta
    if (gameState.currentCycle === 1) {
      nextStatus = AssociationStatus.APRENDIDA;
    }
    // En ciclos 2, 3 y 4 se queda igual al marcar Correcta

    advance(nextStatus);
  };

  const advance = (nextStatus: AssociationStatus) => {
    const updatedAssociations = associations.map(a => a.id === currentAssocId ? { ...a, status: nextStatus } : a);
    setAssociations(updatedAssociations);

    if (gameState.currentIndex < gameState.queue.length - 1) {
      setGameState(prev => ({
        ...prev,
        currentIndex: prev.currentIndex + 1,
        revealed: false,
        userInput: '',
        wasRevealed: false,
        lastMatchScore: null
      }));
    } else {
      // Fin del ciclo actual
      onUpdateList({ ...list, associations: updatedAssociations });
      if (gameState.currentCycle < 4) {
        startCycle((gameState.currentCycle + 1) as GameCycle, updatedAssociations);
      } else {
        setGameState(prev => ({ ...prev, isFinished: true }));
      }
    }
  };

  const checkInput = () => {
    const score = calculateSimilarity(gameState.userInput, targetDefinition);
    setGameState(prev => ({ ...prev, lastMatchScore: score }));
    if (score >= list.settings.threshold) {
      handleCorrect();
    } else {
      showNotification("Asociación incorrecta", "error");
    }
  };

  const stats = useMemo(() => ({
    learned: associations.filter(a => a.status === 'APRENDIDA' && !a.history).length,
    known: associations.filter(a => a.status === 'CONOCIDA' && !a.history).length,
    recognized: associations.filter(a => a.status === 'RECONOCIDA' && !a.history).length,
    discovered: associations.filter(a => a.status === 'DESCUBIERTA' && !a.history).length,
    unknown: associations.filter(a => a.status === 'DESCONOCIDA' && !a.history).length,
  }), [associations]);

  const stagesUI = [
    { label: 'Desconocidas', cycle: 1, count: stats.unknown },
    { label: 'Descubiertas', cycle: 2, count: stats.discovered },
    { label: 'Reconocidas', cycle: 3, count: stats.recognized },
    { label: 'Conocidas', cycle: 4, count: stats.known },
  ];

  return (
    <div className="min-h-screen relative flex flex-col bg-slate-50 overflow-x-hidden">
      {toast && <ToastNotification key={toast.id} toast={toast} onClose={() => setToast(null)} />}

      {showConfirmReset && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-sm z-[200] flex items-center justify-center p-6 animate-in fade-in duration-200">
          <div className="bg-white w-full max-w-sm rounded-[2.5rem] p-10 text-center shadow-2xl">
            <h3 className="text-xl font-black text-slate-900 mb-6 tracking-tight">¿Reiniciar todo?</h3>
            <p className="text-slate-500 text-sm mb-8">Se perderán todos los estados y volverán a Desconocidas.</p>
            <div className="flex flex-col gap-2">
              <button onClick={executeFullReset} className="w-full bg-rose-600 text-white py-4 rounded-2xl font-black shadow-lg active:scale-95 transition">Confirmar Reinicio</button>
              <button onClick={() => setShowConfirmReset(false)} className="w-full bg-slate-100 text-slate-600 py-4 rounded-2xl font-bold hover:bg-slate-200 transition">Cancelar</button>
            </div>
          </div>
        </div>
      )}

      {gameState.isFinished ? (
        <FinishedPanel 
          stats={stats} 
          onBack={onBack} 
          onResetAll={() => setShowConfirmReset(true)}
          onArchive={handleArchiveLearned}
          onContinue={handleContinue}
        />
      ) : (
        <div className="max-w-4xl mx-auto p-4 md:p-6 pb-32 w-full flex-1 flex flex-col">
          {/* SCORING / PROGRESS BAR LADDER */}
          <div className="w-full mb-10 mt-4 px-2">
            <div className="flex items-center justify-between relative max-w-2xl mx-auto">
              <div className="absolute top-5 left-0 w-full h-0.5 bg-slate-200 -z-10"></div>
              {stagesUI.map((stage, idx) => {
                const isActive = stage.cycle === gameState.currentCycle;
                const isDone = stage.cycle < gameState.currentCycle;
                return (
                  <div key={idx} className="flex flex-col items-center relative bg-slate-50 px-2">
                    <div className={`w-10 h-10 rounded-full flex items-center justify-center font-black text-[10px] border-4 transition-all duration-500 relative ${
                      isActive ? 'bg-indigo-600 border-white text-white scale-125 shadow-lg shadow-indigo-100' :
                      isDone ? 'bg-emerald-500 border-white text-white' : 'bg-white border-slate-100 text-slate-300'
                    }`}>
                      {isDone ? '✓' : stage.cycle}
                      <div className={`absolute -top-3 -right-3 min-w-[20px] h-[20px] px-1 rounded-full flex items-center justify-center text-[9px] font-black border-2 transition-all ${
                        isActive ? 'bg-indigo-500 text-white border-white' : 'bg-white text-slate-400 border-slate-50'
                      }`}>
                        {stage.count}
                      </div>
                    </div>
                    <span className={`text-[8px] font-black uppercase tracking-widest mt-4 whitespace-nowrap transition-colors ${isActive ? 'text-indigo-600' : 'text-slate-400'}`}>
                      {stage.label}
                    </span>
                  </div>
                );
              })}
              <div className="flex flex-col items-center relative bg-slate-50 px-2">
                <div className={`w-10 h-10 rounded-full flex items-center justify-center font-black text-xs border-4 relative ${
                  stats.learned > 0 ? 'bg-amber-400 border-white text-white' : 'bg-white border-slate-100 text-amber-200'
                }`}>
                  ★
                  <div className="absolute -top-3 -right-3 min-w-[20px] h-[20px] px-1 rounded-full bg-amber-500 text-white border-white border-2 flex items-center justify-center text-[9px] font-black">
                    {stats.learned}
                  </div>
                </div>
                <span className={`text-[8px] font-black uppercase tracking-widest mt-4 whitespace-nowrap ${stats.learned > 0 ? 'text-amber-500' : 'text-slate-300'}`}>
                  Aprendidas
                </span>
              </div>
            </div>
          </div>

          <button 
            onClick={() => setShowSettings(true)}
            className="fixed top-24 right-6 z-40 p-3 bg-white rounded-full shadow-lg border border-slate-100 text-slate-400 hover:text-indigo-600 transition active:scale-90"
          >
            <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" /></svg>
          </button>

          <div className="flex-1 flex flex-col items-center justify-center">
            {/* CARD */}
            <div className="w-full max-w-md bg-white rounded-[3.5rem] shadow-2xl border border-white p-10 text-center relative overflow-hidden group">
              <div className="absolute top-0 left-0 w-full h-1.5 bg-indigo-600 opacity-20" />

              <div className="mb-8">
                <span className="text-[10px] font-black text-indigo-400 uppercase tracking-[0.3em] block mb-2">{list.concept}</span>
                <h2 className="text-4xl font-black text-slate-900 mb-8 break-words leading-tight">{displayTerm || '---'}</h2>
                <div className="h-1 w-10 bg-slate-100 mx-auto rounded-full" />
              </div>

              <div className="min-h-[120px] flex flex-col justify-center">
                {list.settings.mode === 'real' ? (
                  <div className="w-full">
                    <input 
                      type="text" autoFocus
                      value={gameState.userInput}
                      onChange={(e) => setGameState(prev => ({ ...prev, userInput: e.target.value }))}
                      onKeyDown={(e) => e.key === 'Enter' && checkInput()}
                      placeholder="Respuesta..."
                      className="w-full text-center text-xl font-bold py-5 bg-slate-50 border-2 border-slate-100 rounded-3xl focus:border-indigo-600 focus:bg-white outline-none transition-all shadow-inner"
                    />
                  </div>
                ) : (
                  <div className="text-3xl font-black text-indigo-600 px-4">
                    {gameState.revealed ? (
                      <div className="animate-in slide-in-from-bottom-2 fade-in duration-300 break-words">{targetDefinition}</div>
                    ) : (
                      <div className="text-slate-100 tracking-[0.5em] select-none py-2 opacity-50">XXXXXX</div>
                    )}
                  </div>
                )}
              </div>
            </div>

            {/* PENDIENTES COUNTER BELOW CARD */}
            <div className="mt-8 flex items-center gap-2">
              <div className="bg-indigo-600 text-white px-5 py-2 rounded-full text-[10px] font-black uppercase tracking-widest shadow-lg shadow-indigo-100">
                Pendientes: {gameState.queue.length - gameState.currentIndex}
              </div>
              {gameState.currentIndex > 0 && (
                <button 
                  onClick={() => setGameState(prev => ({ ...prev, currentIndex: prev.currentIndex - 1, revealed: false }))}
                  className="bg-white text-slate-400 px-5 py-2 rounded-full text-[10px] font-black uppercase tracking-widest border border-slate-100 hover:text-indigo-600 transition"
                >
                  Atrás
                </button>
              )}
            </div>
          </div>

          {/* BOTTOM ACTIONS */}
          <div className="fixed bottom-0 left-0 right-0 p-8 bg-gradient-to-t from-slate-50 via-slate-50 to-transparent flex justify-center z-30">
            <div className="max-w-md w-full grid grid-cols-3 gap-3">
              <button onClick={handlePasar} className="h-16 bg-white border-2 border-slate-100 text-slate-400 rounded-2xl font-black hover:bg-slate-50 transition shadow-lg active:scale-95 text-[10px] uppercase tracking-widest">
                Siguiente
              </button>
              <button 
                onClick={() => setGameState(prev => ({ ...prev, revealed: !prev.revealed, wasRevealed: true }))}
                className={`h-16 rounded-2xl font-black transition shadow-lg active:scale-95 text-[10px] uppercase tracking-widest ${gameState.revealed ? 'bg-indigo-100 text-indigo-700' : 'bg-indigo-50 text-indigo-600'}`}
              >
                {gameState.revealed ? 'Ocultar' : 'Revelar'}
              </button>
              <button onClick={handleCorrect} className="h-16 bg-indigo-600 text-white rounded-2xl font-black hover:bg-indigo-700 transition shadow-xl shadow-indigo-100 active:scale-95 text-[10px] uppercase tracking-widest flex items-center justify-center gap-2">
                <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg>
                Correcta
              </button>
            </div>
          </div>
        </div>
      )}

      {/* MODAL CONFIGURACIÓN */}
      {showSettings && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-[100] flex items-center justify-center p-6 animate-in fade-in duration-200">
          <div className="bg-white w-full max-w-sm rounded-[3rem] p-10 shadow-2xl animate-in zoom-in-95 duration-200">
            <h3 className="text-2xl font-black text-slate-900 mb-8 tracking-tight">Opciones</h3>
            <div className="space-y-8">
              <div>
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">Método</label>
                <div className="flex bg-slate-50 p-1 rounded-2xl">
                  {(['training', 'real'] as GameMode[]).map(m => (
                    <button key={m} onClick={() => onUpdateList({ ...list, settings: { ...list.settings, mode: m } })} className={`flex-1 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${list.settings.mode === m ? 'bg-white text-indigo-600 shadow-md' : 'text-slate-400'}`}>{m === 'training' ? 'Práctica' : 'Escritura'}</button>
                  ))}
                </div>
              </div>
              <button 
                onClick={() => setShowConfirmReset(true)}
                className="w-full bg-rose-500 text-white py-4 rounded-2xl font-black shadow-lg active:scale-95 uppercase text-[10px] tracking-widest"
              >
                Borrar Progreso (Reset)
              </button>
            </div>
            <button onClick={() => setShowSettings(false)} className="w-full mt-10 bg-slate-900 text-white py-4 rounded-[2rem] font-black hover:bg-slate-800 transition text-[11px] uppercase tracking-widest">Cerrar</button>
          </div>
        </div>
      )}
    </div>
  );
};

const ToastNotification: React.FC<{ toast: Toast, onClose: () => void }> = ({ toast, onClose }) => (
  <div 
    onClick={onClose}
    className={`fixed top-12 left-1/2 -translate-x-1/2 z-[300] px-8 py-4 rounded-[2rem] shadow-2xl font-black text-[11px] uppercase tracking-widest cursor-pointer animate-in slide-in-from-top-12 fade-in duration-500 flex items-center gap-4 border-2 ${
      toast.type === 'success' ? 'bg-emerald-600 text-white border-emerald-400' : 
      toast.type === 'error' ? 'bg-rose-600 text-white border-rose-400' : 
      'bg-indigo-700 text-white border-indigo-500'
    }`}
  >
    {toast.message}
  </div>
);

const FinishedPanel: React.FC<{ stats: any, onBack: () => void, onResetAll: () => void, onArchive: () => void, onContinue: () => void }> = ({ stats, onBack, onResetAll, onArchive, onContinue }) => (
  <div className="max-w-xl mx-auto p-6 text-center animate-in zoom-in duration-500 flex-1 flex flex-col justify-center min-h-screen">
    <div className="bg-white rounded-[4rem] shadow-2xl p-12 border border-slate-100">
      <div className="w-20 h-20 bg-indigo-50 text-indigo-600 rounded-full flex items-center justify-center mx-auto mb-8 shadow-inner">
        <svg className="w-10 h-10" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg>
      </div>
      <h2 className="text-3xl font-black text-slate-900 mb-2 tracking-tight">Sesión Terminada</h2>
      <p className="text-slate-400 mb-10 text-sm font-medium">Revisa el estado de tus asociaciones:</p>

      <div className="grid grid-cols-2 gap-4 mb-10">
        <div className="bg-amber-50 p-6 rounded-[2.5rem] border border-amber-100">
          <div className="text-4xl font-black text-amber-500 mb-1">{stats.learned}</div>
          <div className="text-[10px] uppercase font-black text-amber-400 tracking-widest">★ Aprendidas</div>
        </div>
        <div className="bg-indigo-50 p-6 rounded-[2.5rem] border border-indigo-100">
          <div className="text-4xl font-black text-indigo-600 mb-1">{stats.unknown + stats.discovered + stats.recognized + stats.known}</div>
          <div className="text-[10px] uppercase font-black text-indigo-400 tracking-widest">En Proceso</div>
        </div>
      </div>

      <div className="flex flex-col gap-3">
        <button onClick={onContinue} className="w-full bg-indigo-600 text-white py-5 rounded-[2rem] font-black shadow-xl shadow-indigo-100 active:scale-95 text-xs uppercase tracking-[0.2em] transition-all">Continuar Juego</button>
        <div className="grid grid-cols-2 gap-3">
          <button onClick={onArchive} className="bg-slate-100 text-slate-600 py-4 rounded-[2rem] font-black text-[9px] uppercase tracking-widest active:scale-95 transition hover:bg-slate-200">Mover al Histórico</button>
          <button onClick={onResetAll} className="bg-rose-50 text-rose-600 py-4 rounded-[2rem] font-black text-[9px] uppercase tracking-widest active:scale-95 transition hover:bg-rose-100">Reiniciar a Cero</button>
        </div>
        <button onClick={onBack} className="w-full bg-white text-slate-300 py-4 rounded-2xl font-bold active:scale-95 text-[10px] uppercase tracking-widest mt-4">Cerrar</button>
      </div>
    </div>
  </div>
);

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { AssociationList, Association, AssociationStatus, GameCycle, GameState, FlipOrder, GameMode } from '../types';
import { calculateSimilarity } from '../utils/similarity';

interface GameViewProps {
  list: AssociationList;
  onUpdateList: (list: AssociationList) => void;
  onBack: () => void;
}

interface Toast {
  message: string;
  type: 'success' | 'error' | 'info';
  id: number;
}

export const GameView: React.FC<GameViewProps> = ({ list, onUpdateList, onBack }) => {
  const [associations, setAssociations] = useState<Association[]>(list.associations);
  const [gameState, setGameState] = useState<GameState>({
    listId: list.id,
    currentCycle: 1,
    currentIndex: 0,
    queue: [],
    history: [],
    isFinished: false,
    revealed: false,
    userInput: '',
    lastMatchScore: null,
    wasRevealed: false
  });

  const [showSettings, setShowSettings] = useState(false);
  const [showConfirmReset, setShowConfirmReset] = useState(false);
  const [toast, setToast] = useState<Toast | null>(null);

  const showNotification = useCallback((message: string, type: 'success' | 'error' | 'info' = 'success') => {
    setToast({ message, type, id: Date.now() });
  }, []);

  useEffect(() => {
    if (toast) {
      const timer = setTimeout(() => setToast(null), 3000);
      return () => clearTimeout(timer);
    }
  }, [toast]);

  /**
   * Lógica de Ciclos según Requerimiento:
   * 
   * Ciclo 1 (Desconocidas): Solo muestra las Desconocidas.
   *   - Correcta: Pasa a APRENDIDA (Aprendida a la primera).
   *   - Siguiente: Pasa a DESCUBIERTA.
   * 
   * Ciclo 2 (Descubiertas): Solo muestra las Descubiertas.
   *   - Correcta: Se queda en DESCUBIERTA.
   *   - Siguiente: Pasa a RECONOCIDA.
   * 
   * Ciclo 3 (Reconocidas): Solo muestra las Reconocidas.
   *   - Correcta: Se queda en RECONOCIDA.
   *   - Siguiente: Pasa a CONOCIDA.
   * 
   * Ciclo 4 (Conocidas): Solo muestra las Conocidas.
   *   - Correcta: Se queda en CONOCIDA.
   *   - Siguiente: Se queda en CONOCIDA.
   */
  const startCycle = useCallback((cycle: GameCycle, currentAssocs: Association[]) => {
    let targetStatus: AssociationStatus;
    switch (cycle) {
      case 1: targetStatus = AssociationStatus.DESCONOCIDA; break;
      case 2: targetStatus = AssociationStatus.DESCUBIERTA; break;
      case 3: targetStatus = AssociationStatus.RECONOCIDA; break;
      case 4: targetStatus = AssociationStatus.CONOCIDA; break;
      default: targetStatus = AssociationStatus.DESCONOCIDA;
    }

    const availableIds = currentAssocs
      .filter(a => a.status === targetStatus && !a.history)
      .map(a => a.id);

    const shuffled = [...availableIds].sort(() => Math.random() - 0.5);

    if (shuffled.length === 0 && cycle < 4) {
      startCycle((cycle + 1) as GameCycle, currentAssocs);
      return;
    }

    const allLearned = currentAssocs.every(a => a.status === AssociationStatus.APRENDIDA || a.history);

    setGameState({
      listId: list.id,
      currentCycle: cycle,
      currentIndex: 0,
      queue: shuffled,
      history: [],
      isFinished: allLearned || (shuffled.length === 0 && cycle === 4),
      revealed: false,
      userInput: '',
      wasRevealed: false,
      lastMatchScore: null
    });
  }, [list.id]);

  useEffect(() => { 
    startCycle(1, associations); 
  }, []);

  const executeFullReset = () => {
    const resetData = associations.map(a => ({ 
      ...a, 
      status: AssociationStatus.DESCONOCIDA, 
      history: false 
    }));
    setAssociations(resetData);
    setShowConfirmReset(false);
    setShowSettings(false);
    onUpdateList({ ...list, associations: resetData });
    startCycle(1, resetData);
    showNotification("Progreso reiniciado", "info");
  };

  const handleArchiveLearned = () => {
    const learnedCount = associations.filter(a => a.status === AssociationStatus.APRENDIDA && !a.history).length;
    if (learnedCount === 0) {
      showNotification("Nada que archivar aún", "error");
      return;
    }
    const archived = associations.map(a => a.status === AssociationStatus.APRENDIDA ? { ...a, history: true } : a);
    setAssociations(archived);
    onUpdateList({ ...list, associations: archived });
    showNotification("Aprendidas archivadas", "success");

    const nextRoundAssocs = archived.map(a => !a.history ? { ...a, status: AssociationStatus.DESCONOCIDA } : a);
    setAssociations(nextRoundAssocs);
    startCycle(1, nextRoundAssocs);
  };

  const handleContinue = () => {
    const reset = associations.map(a => !a.history ? { ...a, status: AssociationStatus.DESCONOCIDA } : a);
    setAssociations(reset);
    onUpdateList({ ...list, associations: reset });
    startCycle(1, reset);
    showNotification("Iniciando nueva ronda", "info");
  };

  const currentAssocId = gameState.queue[gameState.currentIndex];
  const currentAssoc = associations.find(a => a.id === currentAssocId);

  const displayTerm = useMemo(() => {
    if (!currentAssoc) return '';
    return list.settings.flipOrder === 'reversed' ? currentAssoc.definition : currentAssoc.term;
  }, [currentAssoc, list.settings.flipOrder]);

  const targetDefinition = useMemo(() => {
    if (!currentAssoc) return '';
    return list.settings.flipOrder === 'reversed' ? currentAssoc.term : currentAssoc.definition;
  }, [currentAssoc, list.settings.flipOrder]);

  const handlePasar = () => {
    if (!currentAssoc) return;
    let nextStatus = currentAssoc.status;

    if (gameState.currentCycle === 1) nextStatus = AssociationStatus.DESCUBIERTA;
    else if (gameState.currentCycle === 2) nextStatus = AssociationStatus.RECONOCIDA;
    else if (gameState.currentCycle === 3) nextStatus = AssociationStatus.CONOCIDA;

    advance(nextStatus);
  };

  const handleCorrect = () => {
    if (!currentAssoc) return;
    let nextStatus = currentAssoc.status;

    if (gameState.currentCycle === 1) {
      nextStatus = AssociationStatus.APRENDIDA;
    }

    advance(nextStatus);
  };

  const advance = (nextStatus: AssociationStatus) => {
    const updatedAssociations = associations.map(a => a.id === currentAssocId ? { ...a, status: nextStatus } : a);
    setAssociations(updatedAssociations);

    if (gameState.currentIndex < gameState.queue.length - 1) {
      setGameState(prev => ({
        ...prev,
        currentIndex: prev.currentIndex + 1,
        revealed: false,
        userInput: '',
        wasRevealed: false,
        lastMatchScore: null
      }));
    } else {
      onUpdateList({ ...list, associations: updatedAssociations });
      if (gameState.currentCycle < 4) {
        startCycle((gameState.currentCycle + 1) as GameCycle, updatedAssociations);
      } else {
        setGameState(prev => ({ ...prev, isFinished: true }));
      }
    }
  };

  const checkInput = () => {
    const score = calculateSimilarity(gameState.userInput, targetDefinition);
    setGameState(prev => ({ ...prev, lastMatchScore: score }));
    if (score >= list.settings.threshold) {
      handleCorrect();
    } else {
      showNotification("Asociación incorrecta", "error");
    }
  };

  const stats = useMemo(() => ({
    learned: associations.filter(a => a.status === 'APRENDIDA' && !a.history).length,
    known: associations.filter(a => a.status === 'CONOCIDA' && !a.history).length,
    recognized: associations.filter(a => a.status === 'RECONOCIDA' && !a.history).length,
    discovered: associations.filter(a => a.status === 'DESCUBIERTA' && !a.history).length,
    unknown: associations.filter(a => a.status === 'DESCONOCIDA' && !a.history).length,
  }), [associations]);

  const stagesUI = [
    { label: 'Desconocidas', cycle: 1, count: stats.unknown },
    { label: 'Descubiertas', cycle: 2, count: stats.discovered },
    { label: 'Reconocidas', cycle: 3, count: stats.recognized },
    { label: 'Conocidas', cycle: 4, count: stats.known },
  ];

  return (
    <div className="min-h-screen relative flex flex-col bg-slate-50 overflow-x-hidden">
      {toast && <ToastNotification key={toast.id} toast={toast} onClose={() => setToast(null)} />}

      {showConfirmReset && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-sm z-[200] flex items-center justify-center p-6 animate-in fade-in duration-200">
          <div className="bg-white w-full max-w-sm rounded-[2.5rem] p-10 text-center shadow-2xl">
            <h3 className="text-xl font-black text-slate-900 mb-6 tracking-tight">¿Confirmar reinicio?</h3>
            <div className="flex flex-col gap-2">
              <button onClick={executeFullReset} className="w-full bg-rose-600 text-white py-4 rounded-2xl font-black shadow-lg hover:bg-rose-700 active:scale-95 transition">Borrar Progreso</button>
              <button onClick={() => setShowConfirmReset(false)} className="w-full bg-slate-100 text-slate-600 py-4 rounded-2xl font-bold hover:bg-slate-200 transition">Cancelar</button>
            </div>
          </div>
        </div>
      )}

      {gameState.isFinished ? (
        <FinishedPanel 
          stats={stats} 
          onBack={onBack} 
          onResetAll={() => setShowConfirmReset(true)}
          onArchive={handleArchiveLearned}
          onContinue={handleContinue}
        />
      ) : (
        <div className="max-w-4xl mx-auto p-4 md:p-6 pb-32 w-full flex-1 flex flex-col">
          {/* LADDER INDICATOR */}
          <div className="w-full mb-6 mt-4 px-2">
            <div className="flex items-center justify-between relative max-w-3xl mx-auto">
              <div className="absolute top-5 left-0 w-full h-0.5 bg-slate-200 -z-10"></div>
              {stagesUI.map((stage, idx) => {
                const isActive = stage.cycle === gameState.currentCycle;
                const isDone = stage.cycle < gameState.currentCycle;
                return (
                  <div key={idx} className="flex flex-col items-center relative bg-slate-50 px-3">
                    <div className={`w-10 h-10 rounded-full flex items-center justify-center font-black text-[10px] border-4 transition-all duration-500 relative ${
                      isActive ? 'bg-indigo-600 border-white text-white scale-125 shadow-xl shadow-indigo-100' :
                      isDone ? 'bg-emerald-500 border-white text-white' : 'bg-white border-slate-100 text-slate-300'
                    }`}>
                      {isDone ? '✓' : stage.cycle}
                      <div className={`absolute -top-3 -right-3 min-w-[20px] h-[20px] px-1 rounded-full flex items-center justify-center text-[9px] font-black border-2 transition-all ${
                        isActive ? 'bg-indigo-50 text-white border-white' : 'bg-white text-slate-400 border-slate-50'
                      }`}>
                        {stage.count}
                      </div>
                    </div>
                    <span className={`text-[8px] font-black uppercase tracking-widest mt-4 whitespace-nowrap transition-colors ${isActive ? 'text-indigo-600' : 'text-slate-400'}`}>
                      {stage.label}
                    </span>
                  </div>
                );
              })}
              <div className="flex flex-col items-center relative bg-slate-50 px-3">
                <div className={`w-10 h-10 rounded-full flex items-center justify-center font-black text-xs border-4 relative ${
                  stats.learned > 0 ? 'bg-amber-400 border-white text-white' : 'bg-white border-slate-100 text-amber-200'
                }`}>
                  ★
                  <div className="absolute -top-3 -right-3 min-w-[20px] h-[20px] px-1 rounded-full bg-amber-500 text-white border-white border-2 flex items-center justify-center text-[9px] font-black">
                    {stats.learned}
                  </div>
                </div>
                <span className={`text-[8px] font-black uppercase tracking-widest mt-4 whitespace-nowrap ${stats.learned > 0 ? 'text-amber-500' : 'text-slate-300'}`}>
                  Aprendidas
                </span>
              </div>
            </div>
          </div>

          <button 
            onClick={() => setShowSettings(true)}
            className="fixed top-24 right-6 z-40 p-3 bg-white rounded-full shadow-lg border border-slate-100 text-slate-400 hover:text-indigo-600 transition active:scale-90"
          >
            <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" /></svg>
          </button>

          {/* PENDIENTES COUNTER IN THE GAP */}
          <div className="flex justify-center mb-6">
            <div className="bg-white border border-slate-200 px-6 py-2.5 rounded-full flex items-center gap-3 shadow-sm group">
              <span className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">Pendientes de procesar:</span>
              <span className="text-indigo-600 font-black text-sm">{gameState.queue.length - gameState.currentIndex}</span>
            </div>
          </div>

          <div className="flex-1 flex flex-col items-center justify-start mt-2">
            {/* CARD */}
            <div className="w-full max-w-md bg-white rounded-[3.5rem] shadow-2xl border border-white p-10 text-center relative overflow-hidden group">
              <div className="absolute top-0 left-0 w-full h-1.5 bg-indigo-600 opacity-20" />

              <div className="mb-8">
                <span className="text-[10px] font-black text-indigo-400 uppercase tracking-[0.3em] block mb-2">{list.concept}</span>
                <h2 className="text-4xl font-black text-slate-900 mb-8 break-words leading-tight">{displayTerm || '---'}</h2>
                <div className="h-1 w-10 bg-slate-100 mx-auto rounded-full" />
              </div>

              <div className="min-h-[120px] flex flex-col justify-center">
                {list.settings.mode === 'real' ? (
                  <div className="w-full">
                    <input 
                      type="text" autoFocus
                      value={gameState.userInput}
                      onChange={(e) => setGameState(prev => ({ ...prev, userInput: e.target.value }))}
                      onKeyDown={(e) => e.key === 'Enter' && checkInput()}
                      placeholder="Respuesta..."
                      className="w-full text-center text-xl font-bold py-5 bg-slate-50 border-2 border-slate-100 rounded-3xl focus:border-indigo-600 focus:bg-white outline-none transition-all shadow-inner"
                    />
                  </div>
                ) : (
                  <div className="text-3xl font-black text-indigo-600 px-4">
                    {gameState.revealed ? (
                      <div className="animate-in slide-in-from-bottom-2 fade-in duration-300 break-words">{targetDefinition}</div>
                    ) : (
                      <div className="text-slate-100 tracking-[0.5em] select-none py-2 opacity-50">XXXXXX</div>
                    )}
                  </div>
                )}
              </div>
            </div>

            {/* ATRÁS BUTTON */}
            {gameState.currentIndex > 0 && (
              <button 
                onClick={() => setGameState(prev => ({ ...prev, currentIndex: prev.currentIndex - 1, revealed: false }))}
                className="mt-6 bg-white text-slate-400 px-6 py-2 rounded-full text-[10px] font-black uppercase tracking-widest border border-slate-100 hover:text-indigo-600 transition shadow-sm active:scale-95"
              >
                ← Atras
              </button>
            )}
          </div>

          {/* ACTIONS */}
          <div className="fixed bottom-0 left-0 right-0 p-8 bg-gradient-to-t from-slate-50 via-slate-50 to-transparent flex justify-center z-30">
            <div className="max-w-md w-full grid grid-cols-3 gap-3">
              <button onClick={handlePasar} className="h-16 bg-white border-2 border-slate-100 text-slate-400 rounded-2xl font-black hover:bg-slate-50 transition shadow-lg active:scale-95 text-[10px] uppercase tracking-widest">
                Siguiente
              </button>
              <button 
                onClick={() => setGameState(prev => ({ ...prev, revealed: !prev.revealed, wasRevealed: true }))}
                className={`h-16 rounded-2xl font-black transition shadow-lg active:scale-95 text-[10px] uppercase tracking-widest ${gameState.revealed ? 'bg-indigo-100 text-indigo-700' : 'bg-indigo-50 text-indigo-600'}`}
              >
                {gameState.revealed ? 'Revelar' : 'Revelar'}
              </button>
              <button onClick={handleCorrect} className="h-16 bg-indigo-600 text-white rounded-2xl font-black hover:bg-indigo-700 transition shadow-xl shadow-indigo-100 active:scale-95 text-[10px] uppercase tracking-widest flex items-center justify-center gap-2">
                <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg>
                Correcta
              </button>
            </div>
          </div>
        </div>
      )}

      {/* SETTINGS MODAL */}
      {showSettings && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-[100] flex items-center justify-center p-6 animate-in fade-in duration-200">
          <div className="bg-white w-full max-w-sm rounded-[3rem] p-10 shadow-2xl animate-in zoom-in-95 duration-200">
            <h3 className="text-2xl font-black text-slate-900 mb-8 tracking-tight">Opciones</h3>
            <div className="space-y-8">
              <div>
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">Método</label>
                <div className="flex bg-slate-50 p-1 rounded-2xl">
                  {(['training', 'real'] as GameMode[]).map(m => (
                    <button key={m} onClick={() => onUpdateList({ ...list, settings: { ...list.settings, mode: m } })} className={`flex-1 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${list.settings.mode === m ? 'bg-white text-indigo-600 shadow-md' : 'text-slate-400'}`}>{m === 'training' ? 'Práctica' : 'Escritura'}</button>
                  ))}
                </div>
              </div>
              <button 
                onClick={() => setShowConfirmReset(true)}
                className="w-full bg-rose-500 text-white py-4 rounded-2xl font-black shadow-lg active:scale-95 uppercase text-[10px] tracking-widest"
              >
                Borrar Progreso (Reset)
              </button>
            </div>
            <button onClick={() => setShowSettings(false)} className="w-full mt-10 bg-slate-900 text-white py-4 rounded-[2rem] font-black hover:bg-slate-800 transition text-[11px] uppercase tracking-widest">Cerrar</button>
          </div>
        </div>
      )}
    </div>
  );
};

