"use client";

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { AssociationList, Association, AssociationStatus, GameCycle, GameState } from '@/lib/types';
import { calculateSimilarity } from '@/lib/similarity';

interface GameViewProps {
  list: AssociationList;
  onUpdateList: (list: AssociationList) => void;
  onBack: () => void;
  showSettings: boolean;
  setShowSettings: (val: boolean) => void;
}

export const GameView: React.FC<GameViewProps> = ({ list, onUpdateList, onBack, showSettings, setShowSettings }) => {
  const [gameState, setGameState] = useState<GameState>({
    listId: list.id,
    currentCycle: 1,
    currentIndex: 0,
    queue: [],
    isFinished: false,
    revealed: false,
    userInput: '',
    wasRevealed: false
  });

  const [associations, setAssociations] = useState<Association[]>(list.associations);

  const startCycle = useCallback((cycle: GameCycle, currentAssocs: Association[]) => {
    let filter: AssociationStatus;
    switch(cycle) {
      case 1: filter = AssociationStatus.DESCONOCIDA; break;
      case 2: filter = AssociationStatus.DESCUBIERTA; break;
      case 3: filter = AssociationStatus.RECONOCIDA; break;
      case 4: filter = AssociationStatus.CONOCIDA; break;
      default: filter = AssociationStatus.DESCONOCIDA;
    }

    const queue = currentAssocs
      .filter(a => a.status === filter && !a.history)
      .map(a => a.id)
      .sort(() => Math.random() - 0.5);

    if (queue.length === 0 && cycle < 4) {
      startCycle((cycle + 1) as GameCycle, currentAssocs);
      return;
    }

    setGameState(prev => ({
      ...prev,
      currentCycle: cycle,
      currentIndex: 0,
      queue,
      isFinished: queue.length === 0 && cycle === 4,
      revealed: false,
      userInput: '',
      wasRevealed: false
    }));
  }, []);

  useEffect(() => {
    startCycle(1, associations);
  }, [startCycle, associations]);

  const currentAssoc = useMemo(() => 
    associations.find(a => a.id === gameState.queue[gameState.currentIndex]),
    [associations, gameState.queue, gameState.currentIndex]
  );

  const handleNext = () => {
    if (!currentAssoc) return;
    let nextStatus = currentAssoc.status;

    if (gameState.currentCycle === 1) nextStatus = AssociationStatus.DESCUBIERTA;
    else if (gameState.currentCycle === 2) nextStatus = AssociationStatus.RECONOCIDA;
    else if (gameState.currentCycle === 3) nextStatus = AssociationStatus.CONOCIDA;

    advance(nextStatus);
  };

  const handleCorrect = () => {
    if (!currentAssoc || gameState.wasRevealed) return;
    // Solo en ciclo 1 el botón correcto marca como APRENDIDA
    if (gameState.currentCycle === 1) {
      advance(AssociationStatus.APRENDIDA);
    } else {
      // En otros ciclos, "Correcta" no cambia el estado según tus reglas
      advance(currentAssoc.status);
    }
  };

  const advance = (nextStatus: AssociationStatus) => {
    const updated = associations.map(a => a.id === currentAssoc?.id ? { ...a, status: nextStatus } : a);
    setAssociations(updated);

    if (gameState.currentIndex < gameState.queue.length - 1) {
      setGameState(prev => ({ ...prev, currentIndex: prev.currentIndex + 1, revealed: false, wasRevealed: false }));
    } else {
      onUpdateList({ ...list, associations: updated });
      if (gameState.currentCycle < 4) {
        startCycle((gameState.currentCycle + 1) as GameCycle, updated);
      } else {
        setGameState(prev => ({ ...prev, isFinished: true }));
      }
    }
  };

  if (gameState.isFinished) return (
    <div className="max-w-md mx-auto mt-20 p-8 bg-white rounded-3xl shadow-xl text-center">
      <h2 className="text-3xl font-black mb-4">¡Ronda Completada!</h2>
      <div className="flex flex-col gap-3 mt-8">
        <button onClick={() => {
           const reset = associations.map(a => ({ ...a, status: AssociationStatus.DESCONOCIDA }));
           setAssociations(reset);
           startCycle(1, reset);
        }} className="bg-indigo-600 text-white py-4 rounded-2xl font-bold">Reiniciar todo</button>
        <button onClick={onBack} className="text-slate-500 font-bold py-2">Volver</button>
      </div>
    </div>
  );

  return (
    <div className="max-w-4xl mx-auto px-6 py-10 flex flex-col items-center">
      <div className="w-full flex justify-between mb-8">
        <div className="flex gap-2">
          {[1,2,3,4].map(c => (
            <div key={c} className={`w-3 h-3 rounded-full ${gameState.currentCycle >= c ? 'bg-indigo-600' : 'bg-slate-200'}`}></div>
          ))}
        </div>
        <span className="text-xs font-bold text-slate-400 uppercase tracking-widest">
          {gameState.currentIndex + 1} / {gameState.queue.length}
        </span>
      </div>

      <div className="w-full bg-white rounded-[2.5rem] shadow-2xl border-4 border-white p-12 text-center relative overflow-hidden">
        <div className="absolute top-0 left-0 w-full h-2 bg-indigo-600/10"></div>
        <h2 className="text-5xl font-black text-slate-900 mb-8">{currentAssoc?.term}</h2>

        <div className="h-24 flex items-center justify-center">
          {gameState.revealed ? (
            <p className="text-3xl font-bold text-indigo-600 animate-in fade-in zoom-in duration-300">
              {currentAssoc?.definition}
            </p>
          ) : (
            <div className="flex gap-2">
              {[1, 2, 3, 4, 5].map(i => (
                <div key={i} className="w-6 h-8 bg-slate-100 rounded-md animate-shimmer"></div>
              ))}
            </div>
          )}
        </div>
      </div>

      <div className="fixed bottom-10 left-0 right-0 px-6">
        <div className="max-w-2xl mx-auto grid grid-cols-3 gap-4">
          <button onClick={handleNext} className="bg-white border-2 border-slate-200 text-slate-600 h-16 rounded-2xl font-black uppercase text-xs tracking-widest shadow-lg active:scale-95 transition">Siguiente</button>
          <button onClick={() => setGameState(p => ({...p, revealed: !p.revealed, wasRevealed: true}))} className="bg-indigo-50 text-indigo-700 h-16 rounded-2xl font-black uppercase text-xs tracking-widest shadow-lg active:scale-95 transition">Revelar</button>
          <button onClick={handleCorrect} disabled={gameState.wasRevealed} className={`h-16 rounded-2xl font-black uppercase text-xs tracking-widest shadow-lg active:scale-95 transition flex items-center justify-center gap-2 ${gameState.wasRevealed ? 'bg-slate-100 text-slate-300' : 'bg-indigo-600 text-white'}`}>
            <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7"/></svg>
            Correcta
          </button>
        </div>
      </div>
    </div>
  );
};

export const calculateSimilarity = (str1: string, str2: string): number => {
  const s1 = normalize(str1);
  const s2 = normalize(str2);

  if (s1 === s2) return 1.0;
  if (s1.length === 0 || s2.length === 0) return 0.0;

  const editDistance = levenshteinDistance(s1, s2);
  const maxLength = Math.max(s1.length, s2.length);

  return (maxLength - editDistance) / maxLength;
};

const normalize = (str: string): string => {
  return str
    .toLowerCase()
    .trim()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[^\w\s]/gi, '');
};

const levenshteinDistance = (a: string, b: string): number => {
  const matrix = Array.from({ length: a.length + 1 }, () =>
    Array.from({ length: b.length + 1 }, (_, i) => i)
  );

  for (let i = 1; i <= a.length; i++) {
    matrix[i][0] = i;
    for (let j = 1; j <= b.length; j++) {
      const cost = a[i - 1] === b[j - 1] ? 0 : 1;
      matrix[i][j] = Math.min(
        matrix[i - 1][j] + 1,
        matrix[i][j - 1] + 1,
        matrix[i - 1][j - 1] + cost
      );
    }
  }
  return matrix[a.length][b.length];
};

