      setUser(JSON.parse(guestUser));
      setLoading(false);
      return;
    }

    if (isConfigured && auth) {
      return onAuthStateChanged(auth, (u: any) => {
        setUser(u);
        setLoading(false);
      });
    } else {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    if (!user) {
      setLists([]);
      return;
    }

    if (user.uid.startsWith('guest-')) {
      const savedLists = localStorage.getItem(`glimmind_lists_${user.uid}`);
      if (savedLists) setLists(JSON.parse(savedLists));
      return;
    }

    if (isConfigured && db) {
      const q = query(collection(db, "lists"), where("userId", "==", user.uid));
      const unsubscribe = onSnapshot(q, (snapshot: any) => {
        setLists(snapshot.docs.map((d: any) => d.data() as AssociationList));
      });
      return () => unsubscribe();
    }
