      setLists(updatedLists);
      localStorage.setItem(`glimmind_lists_${user.uid}`, JSON.stringify(updatedLists));
    } else if (isConfigured && db) {
      await setDoc(doc(db, "lists", updatedList.id), updatedList);
    }
